//console.log('clearWinWait:  RETURN   for  dObj.aiObj.doneF= ' + (dObj && dObj.aiObj ? dObj.aiObj.doneF : 'na') + '  and  $(#dEmail).is(:visible)= ' + $('#dEmail').is(':visible') + '  $(#aiDOSpop).is(:hidden)= ' + $('#aiDOSpop').is(':hidden'));
			return;		// <<<<<<<<<<<<<<<<<<<<<
