function pmp( h, o )	// popMagnificPopup		https://dimsemenov.com/plugins/magnific-popup/documentation.html
{
//console.log('pmp:  h= ' + h);

	clearWinWait('pmp');

	if( !h ) { return; }

// NO!!!	h = h.replace(/\./g, '<b>.</b>');

	var popClass = 'mpop ', txtClass = 'mpopTxt ', ftrClass = 'mpopFtr ';	// KEEP trailing spaces!!!!!!!!!!!!!!!

	var mainClass = 'my-mfp-zoom-in';

	var popStyle, txtStyle;


	if(!o) { o = {}; }
//console.log('pmp:  starting o= ' + JSON.stringify(o));

	if( o.popClass ) { popClass += o.popClass; }

	if( o.txtClass ) { txtClass += o.txtClass; }

	if( o.ftrClass ) { ftrClass += o.ftrClass; }

	if( o.mainClass ) { mainClass = o.mainClass; }	// NOT +=...


	if( o.popStyle ) { popStyle = o.popStyle; }		// NOT +=...
	if( o.txtStyle ) { txtStyle = o.txtStyle; }		// NOT +=...

	if( !o.shwClsBtn ) { o.shwClsBtn = false; }
	if( !o.clsBgClk  ) { o.clsBgClk  = false; }

	if( !o.onOpnFn    ) { o.onOpnFn 	= ''; }
	if( !o.onClsFn    ) { o.onClsFn 	= ''; }
//	if( !o.afterClsFn ) { o.afterClsFn 	= ''; }

//console.log('pmp:  AAA o= ' + JSON.stringify(o));
//console.log('pmp:  AAA txtClass= ' + txtClass);


if( o.mdlFlag )
{
	o.clsBgClk  = false;

	o.shwClsBtn = false;

	o.hideFttr  = true;
}
else if( o.hideFttr )
{
	o.shwClsBtn = false;

	o.clsBgClk  = true;
}
else
{
	if( o.clsTO ) { o.shwClsBtn = false; } else if( !o.onClsFn || o.onClsFn == 'std' ) { o.onClsFn = 'pmpCls()'; }

	if( o.onClsFn ) { txtClass += ' txtFtr'; }
}

//if( !o.shwClsBtn && ( !o.onClsFn && !o.clsTO ) ) { o.shwClsBtn = true; }	<-- o.shwClsBtn currently NOT supported...

//console.log('pmp:  ending o= ' + JSON.stringify(o));
//console.log('pmp:  ending txtClass= ' + txtClass);


	h 	= '<div class="' + popClass.trim() + '"' + ( popStyle ? ' "' + popStyle + '"' : '' ) + '>'

		+ '<div class="' + txtClass.trim() + '"' + ( txtStyle ? ' "' + txtStyle + '"' : '' ) + '>' + h + '</div>';



	if( o.hideFttr )
	{
	}
	else if( o.onClsFn.trim().length > 0 )
	{
		h 	+= '<div class="modal-footer mdl-ftr-ctr ' + ftrClass.trim() + '"><button type="button" class="btn btn-primary btn-sm" onclick="' + o.onClsFn + ';"><i class="glyphicon glyphicon-ok"></i></button></div>';
	}

		h 	+= '</div>';


	$.magnificPopup.open({
							items: {
								    src: h, 	// can be a HTML string, jQuery object, or CSS selector
								    type: 'inline'
							  	},

							fixedContentPos: false,
							fixedBgPos: true,
							preloader: false,

//							midClick: true,
// default					closeBtnInside: true,
// default					closeOnBgClick: true,
// default					overflowY: 'auto',

							enableEscapeKey: ( o.mdlFlag ? false : true),	// <<<<<<<<<<<<<<<<<<<<

							showCloseBtn: o.shwClsBtn,
							closeOnBgClick: o.clsBgClk,

							removalDelay: 300,
							mainClass: mainClass,	// 'my-mfp-zoom-in',

							callbacks: {
										open:  function() { return o.onOpnFn; } 	// this = Popup instance --> this.close()		$(this.contentContainer) --> jQry access to popup content h
// see modal-footer htm above!!!		close: function() { return o.onClsFn; }
// never fires...						afterClose: function() { return o.afterClsFn; },	// <<<<<<<<<<<<<<<<<<<
								}
					});

	if( o.clsTO ) { setTimeout(function() { $.magnificPopup.close(); }, o.clsTO ); }
}



