function oae(fn, jx, ts, er, sf, sgef)	// OnAjaxError...		er.message		// silentFlag, sendGregEmailFlag...
{
//console.log('oae:  jx= ' + JSON.stringify(jx) + '  ts= ' + ts + '  er= ' + er);

	var e = '', sc = '', s = '';
	try
	{
		clearWinWait('oae');

		pmpCls();

		if( !fn ) { fn = 'na'; }

		if( !sf ) { sf = false; }

		if( !sgef ) { sgef = false; }


		fn = 'grav5.js.' + fn;


		if( jx )
		{ 
			try{ sc = jx.status; }catch(err){ sc = 'na';  if( devF ) { console.log('oae.sc:  err= ' + err); }  }	

			jx = JSON.stringify(jx);
		}
		else
		{
			jx = 'na';
		}


		try { s += '   <br><br>aID= ' + aID;  } catch(err) { }

		try { s += '   <br><br>uID= ' + uID;  } catch(err) { }

		try { s += '   <br><br>aN= '  + aN;  } catch(err) { }

		try { s += '   <br><br>uN= '  + uN;  } catch(err) { }

		try { s += '   <br><br>uE= '  + uE;  } catch(err) { }

		try { s += '   <br><br>sf= '  + sf;  } catch(err) { }


		if( !ts ) { ts = 'na'; }

		if( !er ) { er = 'na'; }

		e = s + '  <br><br> jx= ' + jx + '  <br><br> ts=' + ts + ' <br><br> er= ' + er;

		$.ajax({
					type: "POST",
					url: "js_er",
					datatype: "json",
					data: { uID:uID, uE:uE, rF:sf, 	f:fn, e:e, sc:sc, sgef:sgef },
					error: function () {}		// do NOT trigger another ajax error...
				});
	}
	catch(err)
	{
		console.log('oae:  err= ' + err + '  for sc= ' + sc + '  and e= ' + e);
	}
	finally
	{
		console.log('oae:  fn= ' + fn + '  e= ' + e + '  and sc= ' + sc);
	}
}	// oae





