function waRatingThanks( calledBy, obj )
{
	if( !obj ) { obj = {}; }

//console.log('waRatingThanks:   calledBy= ' + calledBy);
//console.log('waRatingThanks:   obj= ' + JSON.stringify(obj));
//console.log('waRatingThanks:   starting review= ' + JSON.stringify(review));

	if( !calledBy ) { calledBy = 'na'; }

	let SkipOfferFlag = false, SkipReason = '';

	// Also see dispRating below...			
	if( !purF && ( EXTREVUWF || BOblkF || mfaF ) )
	{
		SkipOfferFlag = true;

		SkipReason = 'EXTREVUWF || BOblkF || mfaF';
	}
// ---
	else if( !purF && ( glc == 0 && !inidF && !inLnkF ) )	// free and we don't have an inID or inLnk...
	{
		SkipOfferFlag = true;

		SkipReason = 'glc == 0 && !inidF && !inLnkF';
	}
// ---

// -----
	// record that we made the CWS request and what we offered...
	review.lastCWSaskMS = Date.now();
	review.lastAskMS 	= Date.now();
//console.log('waRatingThanks:   review= ' + JSON.stringify(review));

// --- KEEP!!!
	let blkCredits = '';

	if( glc == 0 )	// default to double and not 1000 block credits...
	{
		review.msgCode = 'dbl_monthly';		// review.msgCode = 'trpl_monthly';
	}

	if( !review.msgCode || review.msgCode == 'NonExpBlkCredits' )	// KEEP !review.msgCode!!!!
	{
		blkCredits = '1000';

		review.blkCredits = blkCredits;
	}
// ---


	$.ajax({ url: 'AJAX_Review', type: 'POST', data: { calledBy: calledBy + '.waRatingThanks', lastCWSaskF:true, SkipOfferFlag:SkipOfferFlag, SkipReason:SkipReason, aID:aID, uID:uID, glc:glc, REVBOTF:REVBOTF, id:obj.id, msgCode:review.msgCode, blkCredits:review.blkCredits, stars:review.stars, review:JSON.stringify(review), obj:JSON.stringify(obj) } })

		.done( function(j, ts, jx) { 

						if( SkipOfferFlag )
						{
							if( obj.popFlag )
							{
								$('#mdlRating').modal('hide');

								setTimeout(function() { pmp('Thanks for the feedback!'); }, 600);
							}
							else
							{
								pmp('Thanks for the feedback!');
							}

							return;
						}

// ---
				let $m, w = 500, Ttl, Intro, plTxt;

				obj.allStarsFlag = false;	// initialize...

				if( obj.id )
				{
					if( obj.id == 'allStars' )
					{
						obj.allStarsFlag = true;

						$m = $('#allStarsMdl');

						Ttl = 'Thanks for the 5-Star Rating!';


						if( glc == 0 )	// default to double/triple and not 1000 block credits...
						{
							review.msgCode = 'dbl_monthly';		// review.msgCode = 'trpl_monthly';
						}


						if( !review.msgCode || review.msgCode == 'NonExpBlkCredits' )	// KEEP !review.msgCode!!!!
						{
							w = 480;

							blkCredits = '1000';	// KEEP as failsafe!!!!

							review.blkCredits = blkCredits;

							if( glc > 0 || !REVBOTF )
							{
								Intro = 'Take a moment to post a review in the Google Chrome Store and receive <b>' + blkCredits + ' non-expiring email discovery credits!</b>';
							}
							else	// MUST be free AND REVBOTF...
							{
								Intro = 'Take a moment to post a review in the Google Chrome Store and receive <b>' + blkCredits + ' non-expiring email discovery credits</b> plus access to the LeadLeaper <b>Leads-Gen Assistant</b>';
							}

							Intro += '<p style="margin-top: 15px;">Unlike monthly email credits<b>,</b> non-expiring block credits do not expire at the end of each month so you can use them anytime</p>';
						}

						else if( glc == 0 )
						{
							w = 515;

							if( review.msgCode == 'dbl_monthly' )
							{
								Intro = 'Take a moment to post a quick review in the Google Chrome Store<b>,</b> <br>and we will <b>double your monthly free discovery credits to 400!</b>';
							}
							else if( review.msgCode == 'trpl_monthly' )
							{
								Intro = 'Take a moment to post a quick review in the Google Chrome Store<b>,</b> <br>and we will <b>triple your monthly free discovery credits to 600!</b>';
							}
						}

					}	// if( obj.id == 'allStars' )

					else
					{
						$m = $('#starsMdl');

						Ttl = 'Thanks for the Feedback';

						Intro = 'We will strive to do better!';

						plTxt = 'What would you like to see improved?';
					}

				}	// if( obj.id )


				if( !Intro )
				{
					if( obj.popFlag ) { $('#mdlRating').modal('hide'); }

					return;
				}



				$m.find('.modal-header').show(0).find('.modal-title').text( Ttl );

				if( obj.allStarsFlag )
				{
					$m.find('.modal-body').find('.mdl-intro').removeClass('mdl-better').html( Intro );
				}
				else
				{
					$m.find('.modal-body').find('.mdl-intro').addClass('mdl-better').html( Intro ).end().find('.postRev').removeClass('HL').val( '' ).attr('placeholder', plTxt).css('height', '150px');	//.off('click').on('click', function(evt) { $(this).removeClass('HL'); } ).end().find('#revFrom').val( uN ).end().find('#revReply').val( uE );
				}


// SAVE!!		$m.find('.modal-footer').show(0).find('button.btn-confirm').off('click').on('click', function(evt) { postHowTo(evt, $m, obj.id, allStarsFlag); } );
				$m.find('.modal-footer').show(0).find('button.btn-confirm').off('click').on('click', function(evt) { postRevBtn( evt, $m, obj ); } );

// ---
				if( obj.popFlag )
				{
					$('#mdlRating').modal('hide');

			//		setTimeout(function() { $m.modal( { width: w, keyboard: true, backdrop: 'static', show: true } ).on('hidden.bs.modal', function () { $(this).data('bs.modal', null); }); }, 600);
					setTimeout(function() { $m.modal( { width: w, keyboard: true, show: true } ).on('hidden.bs.modal', function () { $(this).data('bs.modal', null); }); }, 600);

					return;
				}
// ---
//				$m.modal( { width: w, keyboard: true, backdrop: 'static', show: true } ).on('hidden.bs.modal', function () { $(this).data('bs.modal', null); });
				$m.modal( { width: w, keyboard: true, show: true } ).on('hidden.bs.modal', function () { $(this).data('bs.modal', null); });

// ---
		})	// done

		.fail( function(jx, ts, er) { 
										try { oae('waRatingThanks.AJAX_Review', jx, ts, er); }catch(er){} 

										if( obj.popFlag )
										{
											$('#mdlRating').modal('hide');

											setTimeout(function() { pmp('Thanks for the feedback!'); }, 600);
										}
										else
										{
											pmp('Thanks for the feedback!');
										}
		});	// fail
// -----
}
