function dispRating()
{
//console.log('dispRating:  review= ' + JSON.stringify(review));
//console.log("dispRating:  $('#emStatus').is(':visible')= " + $('#emStatus').is(':visible') );

	// If EXTREVUWF, block so users can web-app rate once EXTREVUWF complete!!!   If free, ONLY display AFTER captured 10+ leads so can then CWS ask if 5-star rating...
//	if( EXTREVUWF || mfaF || hsLoginF )
	if( EXTREVUWF         || hsLoginF )
	{
		return;
	}
// ---
	if( $('#emStatus').is(':visible') ) { return; }
// ---




	$('#usr-review').html('<span class="usr-rev-lbl">How are we doing?</span><span id="usr-rev-stars" class="usr-rev-stars"><i id="star1" class="far fa-star"></i><i id="star2" class="far fa-star"></i><i id="star3" class="far fa-star"></i><i id="star4" class="far fa-star"></i><i id="star5" class="far fa-star"></i></span>');

// ---
	$('#usr-rev-stars').each(function() { for( var i = 0; i < review.stars; i++ ) { $('#star' + (i+1)).removeClass('far fa-star').addClass('fas fa-star star-sel'); } });
// ---


	$('#usr-rev-stars')

		.off('mouseleave')

		.on('mouseleave', function(){ $(this).find('> i').each(function(idx){ var $t = $(this);	if( $t.hasClass('star-sel') ) {} else { $t.removeClass('fas fa-star').addClass('far fa-star'); }  });  })

	.find('> i')		// $('#usr-rev-stars > i')

		.off('mouseenter')

		.on('mouseenter', function(){	var $t = $(this), id = $t.attr('id').substring(4);

										$t.parent().find('> i').each(function(idx){ 	var $t = $(this);	if( $t.hasClass('star-sel') ) {} else { $t.removeClass('fas fa-star').addClass('far fa-star'); }  });

										for( var i = 0; i < id; i++ ) { 	$('#star' + (i+1)).removeClass('far fa-star').addClass('fas fa-star'); }
							})

		.off('click')

		.on('click', function(){var $t = $(this), selStars = $t.attr('id').substring(4);

								$t.parent().find('> i').removeClass('fas fa-star star-sel').addClass('far fa-star');

								for( var i = 0; i < selStars; i++ ) { $('#star' + (i+1)).addClass('fas fa-star star-sel'); }

								postRating( selStars );
							});


	setTimeout(function() {
							let $e = $('#usr-review');

// NO!!!						$e.addClass('show-usr-review');

								$e.fadeIn();
				}, 3000);
}






function postRevBtn( evt, $m, obj )
{
//console.log('postRevBtn:   obj= ' + JSON.stringify(obj));
//console.log('postRevBtn:   review= ' + JSON.stringify(review));

	evtStop( evt );

	$(evt.target).blur();

	var $b = $(evt.target);

	if( $b.hasClass('btn-confirm') )
	{
		if( !review.msgCode )    { review.msgCode 	 = ''; }
		if( !review.blkCredits ) { review.blkCredits = ''; }

		review.lastAskMS = Date.now();


		var q = '';
		if( !obj.allStarsFlag )	// NOT
		{
			q = $m.find('.modal-body').find('#postRev').val().trim();

			if( !q || q.length == 0 ) { $m.find('.modal-body').find('#postRev').addClass('HL');	return; }

			// simply record < 5 review...
			$.ajax({ url: 'AJAX_Review', type: 'POST', data: { calledBy:'postRevBtn (btn-confirm)', aID:aID, uID:uID, q:q, id:obj.id, msgCode:review.msgCode, blkCredits:review.blkCredits, stars:review.stars, review:JSON.stringify(review), obj:JSON.stringify(obj) } })

						.done( function(j, ts, jx) { })

						.fail( function(jx, ts, er) { try { oae('postRevBtn.AJAX_Review', jx, ts, er); }catch(er){} });

			$m.modal('hide');
		}

		else
		{
			var win = window.open('https://chromewebstore.google.com/detail/email-finder-leadleaper/iojojcfflmfcejodomoafimdiianbgfe/reviews', '_blank');  win.focus();

			review.sub++;

			$.ajax({ url: 'AJAX_Review', type: 'POST', data: { calledBy:'postRevBtn (allStarsFlag)', aID:aID, uID:uID, q:q, REVBOTF:REVBOTF, id:obj.id, msgCode:review.msgCode, blkCredits:review.blkCredits, stars:review.stars, review:JSON.stringify(review), obj:JSON.stringify(obj) } })

						.done( function(j, ts, jx) { })

						.fail( function(jx, ts, er) { try { oae('postRevBtn.AJAX_Review', jx, ts, er); }catch(er){} });


			setTimeout(function(){ 
									$m.modal('hide');

//									pmp('Thanks for posting a review!');
						}, 1000);

/* SAVE!!
			setTimeout(function(){
									var h 	= '<table class="waRatingThanks-status"><tbody><tr>'
											+ '<td class="wav-frog-logo"><span class="mdl-ttl-logo">&nbsp;</span></td>'	// waving frog...
											+ '<td class="rev-txt">';
										h += 'Thanks! &nbsp;&nbsp;Once Google notifies us of your<br>review<b>,</b> your bonus credits will be available';	// <b>.</b>
										h += '<p style="margin-top:15px">Note that you must include a review with <br>your rating for Google to notify us';
										h	+= '</td></tr></tbody></table>';
									$m.modal('hide');
									setTimeout(function() {pmp( h ); }, 600);
					}, 8000);	// allow 8 seconds since we are not displaying instructions AND we now always require confirmation before awarding credits...
*/
		}	// else obj.allStarsFlag

	}	// if( $b.hasClass('btn-confirm') )
}










