function remindOC( evt )
{
//console.log('remindOC:  ');

	var $a = $(evt.target), cnt = 0, id, ds, d, htm;
//console.log('remindOC:  $a.length= ' + $a.length);		cRemind

	while( cnt < 3 && $a.get(0).tagName.toLowerCase() != 'a' ) { cnt++;		$a = $a.parent(); }

	id = $a.attr('id');
	ds = $a.attr('data');
//console.log('remindOC:  id= ' + id);
//console.log('remindOC:  ds= ' + ds);

	if( ds )
	{
		ds = decodeURIComponent( ds );
//console.log('remindOC:  ds= ' + ds);

		d = JSON.parse( ds );
//console.log('remindOC:  d= ' + JSON.stringify(d));

		d.DDremF = true;

		reminderPop( evt, d );
	}
}




