function tsDiff( d1, d2, rf )
{
//console.log('d1.getTime() = ' + d1.getTime());
//console.log('d2.getTime() = ' + d2.getTime());

	var diff = d1.getTime() - d2.getTime();
//console.log('diff = ' + diff);

	var daysDiff = Math.floor(diff/1000/60/60/24);
        diff -= daysDiff*1000*60*60*24;
//console.log('daysDiff = ' + daysDiff);

	var hoursDiff = Math.floor(diff/1000/60/60);
        diff -= hoursDiff*1000*60*60;

	var minutesDiff = Math.floor(diff/1000/60);
        diff -= minutesDiff*1000*60;

//	var secondsDiff = Math.floor(diff/1000);

//console.log('diff = ' + daysDiff + ' day/s ' + hoursDiff + ' hour/s ' + minutesDiff + ' minute/s ');	//  + secondsDiff + ' second/s ');

	return [daysDiff, hoursDiff, minutesDiff];	//, secondsDifference];
}










