function UpdateSignatureCB( j )
{
	clearWinWait('UpdateSignatureCB');

	if( typeof j == 'string' ) { j = JSON.parse( j ); }
//console.log("UpdateSignatureCB:  j= " + JSON.stringify(j) );


	var $b = $('#panel_signature').find(' #emSigUpdtBtn'), cls='success', txt = 'Updated!';

	if( j.rC != 1 )	// a problem was encountered...
	{
		oe('UpdateSignatureCB', 'j.rC= ' + j.rC);

		cls = 'failed';

		txt = 'Failed!';

		if( $b.outerWidth() > 200 ) { txt = 'Update failed!'; }
	}
	else
	{
		if( $b.outerWidth() > 200 ) { txt = 'Update complete!'; }
	}



	try
	{
		$.getJSON( sigURL + '?n=' + Date.now(), 

					function( j )
					{
						sigObj = j;
 //console.log("UpdateSignatureCB:  sigObj= " + JSON.stringify(sigObj) );
// ---
						comDNC( 'UpdateSignatureCB', sigObj.SigHtml );
// ---
					}).fail(function(jx, ts, er) { oae('UpdateSignatureCB  sigURL=' + sigURL, jx, ts, er); });
	}
	catch(er)
	{
// console.log("UpdateSignatureCB:  er= " + er.message + ' for sigURL= ' + sigURL );
		rpt('UpdateSignatureCB', er.message + ' for sigURL= ' + sigURL);
	}



	$b.removeClass('savHL').addClass(cls).html(txt).blur();

	setTimeout(function() { $b.removeClass(cls).html('Save <i class="fa fa-arrow-circle-right"></i>'); }, 2000);
}






