function procFontFam( cBy, fN )
{
//console.log('procFontFam:  cBy= ' + cBy);
//console.log('procFontFam:  starting fN= ' + fN);

	fN = fN.replace(/&quot;/g, "\'").trim();	// <<<<<<<<<<<<<<<<<<<<<<
//console.log('procFontFam:  AAA fN= ' + fN);

	fN = fN.replace(/"/g, "\'").trim();			// <<<<<<<<<<<<<<<<<<<<<<
//console.log('procFontFam:  BBB fN= ' + fN);



	var fNsA = fN.split(','), fN2, s;		// <span style="font-family: 'times new roman', times;">asfasdf asdfasfasfsdasdf</span>		<span style="font-family: tahoma, arial, helvetica, sans-serif;">asfasdf asdfasfasfsdasdf</span>
//console.log('procFontFam:  fNsA.length= ' + fNsA.length);

	if( fNsA.length > 1 )
	{
		for(var i=0; i < fNsA.length; i++)
		{
			s = fNsA[i].trim();		// times new roman  or  'times new roman'

			var fNa = s.split(/\s+/g);
//console.log('procFontFam:  s= ' + s + '  --> fNa.length= ' +  fNa.length);

			if( fNa.length > 1 && !s.startsWith("'") )
				s = "'" + s + "'";	// 'times new roman'

			if( fN2 )
				fN2 = fN2 + ', ' + s;
			else
				fN2 = s;
		}
	}
	else
	{
		// <span style="font-family: &quot;Times New Roman&quot;;">		SummerNote...
	}

//console.log('procFontFam:  ending fN2= ' + fN2);
//console.log('procFontFam:  returned ' + (fN2 ? fN2 : fN));

	return (fN2 ? fN2 : fN);	// <<<<<<<<<<<<<<<<<<<<<<
}






