function eSalCustSelFn( evt, $e )
{
//console.log('eSalCustSelFn:  '); 

	let $li = $(evt.target), cntr = 0;

	while( cntr < 4 && $li.get(0).tagName.toLowerCase() != 'li' ) { cntr++; 	$li = $li.parent(); }

	let $a    = $li.find('a'), 
		$b    = $li.parent().parent().find('button'),	// select drop-dwn btn within custom sal popup!!
		v     = $a.attr('data-value'), 
		t     = $a.text().trim();

// console.log('eSalCustSelFn:  $li.length= ' + $li.length + '  $b.length= ' + $b.length + '  $a.length= ' + $a.length + '  v= ' + v + '  t= ' + t); 


		$li.parent().find('> li').find('a.checked').removeClass('checked');	// remove current selection

		$a.addClass('checked');


		if( t.startsWith('[') )	// "[Lead_First_Name]"
		{
			$b.find('span.sal-sel').attr('data-value', v).text( t );
		}
		else	// if( t.startsWith('No ') )	// "No Lead Name"
		{
			$b.find('span.sal-sel').attr('data-value', v).html( '<span style="color:#aaa;">' + t + '</span>' );
		}
}




function eSalCustFn( evt, $m, $e, curSel )		// $m = popup eSalCustMdl,  $e = modal containing Summernote
{
//console.log('eSalCustFn:  $m= ' + $m + '  $e= ' + $e + '  curSel= ' + curSel);	// + '  custF= ' + custF); 

	let $btn = $(evt.target);

	if( $btn.hasClass('btn-save') )
	{
//console.log('eSalCustFn:  btn-save');

// ----------
let $fc = $m.find('.note-editor').find('.note-toolbar'),	// fontControls
	fN	= $fc.find('span.note-current-fontname').text(),
	fS	= $fc.find('span.note-current-fontsize').text();

//console.log('eSalCustFn:  $fc.length= ' + $fc.length);
//console.log('eSalCustFn:  starting fN= ' + fN);
//console.log('eSalCustFn:  fS= ' + fS);


	if( fN && fN.length && fN != 'Font Family' && fN != 'default' )
	{
// NO!!!	if( fN.split(/\s+/g).length > 1 ) { fN = '&quot;' + fN + '&quot;'; }	// { fN = '\"' + fN + '\"'; }
// ----
//console.log('eSalCustFn:  starting fN= ' + fN);
				fN = procFontFam( 'eSalCustFn', fN );
//console.log('eSalCustFn:  post-procFontFam fN= ' + fN);
// ----
	}
	else
	{
		fN = '';
	}
//console.log('eSalCustFn:  ending fN= ' + fN);
		

	if( fS && fS.length && fS != 'Size' && fS != 'default' )
	{
	}
	else
	{
		fS = '';
	}
// ---------


		let cWord = $m.find('.eSalCust').find('.eSalCustTxt > input').val();	//	"Ciao"
//console.log('eSalCustFn:  cWord= ' + cWord);

		let $bs = $m.find('.eSalCustSel').find('button > span.sal-sel'),
			v   = $bs.attr('data-value'), 	// "-fname-"  or  ""
			t   = $bs.text().trim();		// "[Lead_First_Name]" or "No Lead Name"

//console.log('eSalCustSelFn:  $bs.length= ' + $bs.length + '  v= ' + v + '  starting t= ' + t); 

		if( !t.startsWith('[') )	// NOT "[Lead_First_Name]"	--> "No Lead Name"
		{
			t = '';
		}
//console.log('eSalCustSelFn:  ending t= ' + t); 


		let eData = (cWord + ' ' + v).trim(),	// "Ciao -fname-"  or  "Ciao"
			eTxt  = (cWord + ' ' + t).trim();	// "Ciao [Lead_First_Name]"  or  "Ciao"
//console.log('eSalCustFn:  pre-style:  eData= ' + eData + '  eTxt= ' + eTxt + '  sty.length= ' + sty.length);

// ----
	eData = eData + '|' + eTxt + '|' + fN + '|' + fS;
//console.log('eSalCustFn:  post-style:  eData= ' + eData + '  eTxt= ' + eTxt);
// ----


		$e.find('.eSal').find('button.dropdown-toggle')

			.find('span.sal-sel').attr('data-value', eData).text( eTxt );


		$e.find('.eSal').find('ul.dropdown-sal-btn > li.cust-sal')

			.find('> a').attr('data-value', eData).addClass('checked')

			.parent().find('> span').text( eTxt );

	}	// if btn-save


	else 	// MUST be a cancel, so restore any prev val...
	{
////console.log('eSalCustFn:  btn-cancel');
		if( curSel )
		{
			let t, custF;

			switch( curSel )
			{
				case "-fname-"		: 	t = '[Lead_First_Name]';		break;

				case "Hi -fname-"	: 	t = 'Hi [Lead_First_Name]';		break;

				default				:	t = curSel.replace('-fname-', '[Lead_First_Name]');		custF = true;
			}
//console.log('eSalCustFn.btn-cancel:  curSel= ' + curSel + ' -->  t= ' + t + '  custF= ' + custF);
// ---

			if( !custF )	// NOT
			{
				$e.find('.eSal').find('ul.dropdown-sal-btn > li').find('a.checked').removeClass('checked');		// remove current selection


				$e.find('.eSal').find('button.dropdown-toggle')

					.find('span.sal-sel').attr('data-value', curSel).text( t );


				$e.find('.eSal').find('ul.dropdown-sal-btn > li')

					.find('> a[data-value="' + curSel + '"]').addClass('checked');	// data-value
			}
		}
	}

	clsMdl( $m );
}



