function eSalPreSav( cb, eSal, o )		// { fontFam:fontFam, fontSz:fontSz, fontColor:fontColor }
{
	if( !o ) { o = {}; }

//console.log('eSalPreSav:  cb= ' + cb + '  starting eSal= ' + eSal);
//console.log('eSalPreSav:  o= ' + (o ? JSON.stringify(o) : o));

	try
	{
		let fN, fS, fC;
// ----------------
		if( eSal.startsWith('<span') )
		{
			return eSal;	// failsafe...
		}
// ----------------


// =============
			if( o.fontFam 	 ) { fN = o.fontFam; }

			if( o.fontSz  	 ) { fS = o.fontSz; }

			if( o.fontColor  ) { fC = o.fontColor; }

//console.log('eSalPreSav:  starting fN= ' + fN + '  starting fS= ' + fS + '  starting fC= ' + fC);
// =============



		let eData, sty = '';

		let sA = eSal.split('|');	// eSal= Hallo -fname-|Hallo [Lead_First_Name]|Verdana|18
//console.log('eSalPreSav:  sA.length= ' + sA.length);

		if( sA.length )	// KEEP
		{
			eSal = sA[0].trim();	// Hallo -fname-	ALWAYS to start and then modified if we have custom data...
//console.log('eSalPreSav:  sA.length starting eSal= ' + eSal);

			if( sA.length == 4 )		// KEEP		// if we have custom data -->  eSal= Hallo -fname-|Hallo [Lead_First_Name]|Verdana|18
			{
				eData = sA[0].trim();	// Hallo -fname-

// 				t = sA[1].trim();		// Hallo [Lead_First_Name]

				if( !fN ) { fN = sA[2].trim(); }		// Verdana	/	Times New Roman
//console.log('eSalPreSav:  AAA fN= ' + fN);

				if( fN && fN.length && fN != 'Font Family' && fN != 'default' )
				{
// <span style="font-family: &quot;Arial Black&quot;; font-size: 18px;"> First paragraph.</span>	<-- works!!!  (eBody)...
// <span style="font-family: &quot;"Arial Black"&quot;; font-size:18px;">Hi Greg</span>,<br><br>	<-- fails due to too many "

// see procFontFam...	fN = fN.replace(/&quot;/g, '').trim();
//console.log('eSalPreSav:  AAA fN= ' + fN);
// ---
					fN = fN.replace(/"/g, '').trim();
//console.log('eSalPreSav:  BBB fN= ' + fN);

//					if( fN.split(/\s+/g).length > 1 ) { fN = '\'' + fN + '\''; }			// { fN = '\"' + fN + '\"'; }
// NO!!!			if( fN.split(/\s+/g).length > 1 ) { fN = '&quot;' + fN + '&quot;'; }	// { fN = '\"' + fN + '\"'; }
// ----
//console.log('eSalPreSav:  starting fN= ' + fN);
					fN = procFontFam( 'eSalPreSav', fN );
//console.log('eSalPreSav:  post-procFontFam fN= ' + fN);
// ----

					sty = sty + 'font-family:' + fN + ";";
//console.log('eSalPreSav:  fN  sty= ' + sty);
				}


				if( !fS ) { fS = sA[3].trim(); }	// 18
//console.log('eSalPreSav:  fS= ' + fS);

				fS = fS.replace('px', '').trim();

				if( fS && fS.length && fS != 'Size' && fS != 'default' )
				{
					if( tmceF )
					{
						sty = sty + 'font-size:' + fS.replace('px', '').trim() + ';';	// + 'px;';  <--  NO since translated into a keyword (small, large, ect.)
					}
				}


//console.log('eSalPreSav:  fC= ' + fC);
				if( fC && fC.length && fC != 'Color' && fC != 'default' )
				{
					sty = sty + 'color:' + fC + ";";
				}

//console.log('eSalPreSav:  sty= ' + sty);

				if( sty.length )
				{
					eSal = '<span style="' + sty + '">' + eData + ',</span>';		// Include , (comma) within span to apply style size & color, if exists...
//					eSal = '<span style="' + sty + '">' + eData + '</span>';		// Exclude , (comma) since not supporting font color...
				}

			}	// if( sA.length == 4 )

		}	// if( sA.length )

//console.log('eSalPreSav:  post-style:  eData= ' + eData + ' -->  eSal= ' + eSal);

	}
	catch( err )
	{
//console.log('eSalPreSav:   eSal= ' + eSal + ' --> err= ' + err.message);
		rpt('eSalPreSav', 'eSal= ' + eSal + ' --> err= ' + err.message);
	}

//console.log('eSalPreSav:  ending eSal= ' + eSal);

	return eSal;
}
