function tPopHdrBtns( evt )
{
	var $btn = $(evt.target);	// var $e = $(evt.target);

	if( $btn.get(0).tagName.toLowerCase() == 'i' ) { $btn = $btn.parent(); }

	$('#tModal').find('.tttip').tooltip('hide');

	$btn.blur();

//console.log("tPopHdrBtns:  $btn.attr('id')= " + $btn.attr('id'));

	switch( $btn.attr('id') )
	{
		case 'tPopSavSavAs'	:	temSav( 'tPopHdrBtns.tPopSavSavAs', evt, $btn, { cpyF:true } );		break;


		case 'tPopDel'		:	temObj.delF = true;


								var h 	= '<div style="color: red;  font-size: 16px;  margin:5px 0;  font-weight: normal;  letter-spacing: normal; ">DELETE email template</div></div>'
										+ '<div id="temDelPO-footer" class="modal-footer">'
										+ 	'<button class="btn btn-sm btn-default btn-cancel">Cancel</button>'
										+ 	'<button class="btn btn-sm btn-danger  btn-confirm">Confirm</button>'
										+ '</div>';

								$btn.popover({
												placement: 'left',		// 'bottom',

												container: 'body',		// #tModal

												html: true,

												content: h,		// function() { return $m.html(); },

										}).on('show.bs.popover', function(){ $(this).data('bs.popover').tip().css('max-width', '600px'); })

											.on('shown.bs.popover',

													function() { 
																	$('#temDelPO-footer').find('> button').off('click').on( 'click', function(evt){ evtStop(evt);  DelTem( evt, $btn); } ); 
											})

											.on('hidden.bs.popover', function(){ temObj.delF = false;	$(this).popover('destroy'); }).popover('show');

								break;
	}	// switch

}	// tPopHdrBtns



