function eSendB( evt, o )	// ONLY applies to campaigns, not email templates...
{
//if( !pF ) { console.log('eSendB:  o= ' + (o ? JSON.stringify( o ) : o)); }

	var $tc, ctObj, eObj, pID, cID, piID, ciID;

	var camSavF;

	if( o )
	{
		camSavF = o.camSavF;

		ctObj   = o.ctObj;	// may be undefined...
	}
//console.log('eSendB:  camSavF= ' + camSavF);


	if( ctObj )
	{
		eObj = ctObj.eObj;

		$tc = $('#camModal .modal-body > .tabbable > .tab-content').find( '#ct' + ctObj.id );
	}

	else if( $('#gDOS').is(':visible') )
	{
		return eSendCHB( 'eSendB', evt, o );
	}

	else
	{
		$tc = $('#camModal .modal-body > .tabbable > .tab-content > div.active');
		
		var fuckJS = $tc.attr('id');

		ctObj = camObj[ fuckJS ];

		eObj = ctObj.eObj;
	}


	pID  = camObj.pID;	if( !pID ) { pID = 0;  clF = true;	}	// campaignLibraryFlag...

	cID  = camObj.cID;	if( !cID ) { cID = 0; }

	ciID = eObj.ciID;	if( !ciID )	{ ciID = 0; }	// campaign(email)InstanceID --> if 0, then no campaign email instance (and therefore, no campaign) associated with email...

	piID = eObj.piID;	if( !piID )	{ piID = 0; }	// project(email)InstanceID...


//console.log('eSendB:  pID= ' + pID + '  piID= ' + piID + '  cID= ' + cID + '  ciID= ' + ciID);
//console.log('eSendB:  eObj= ' + JSON.stringify( eObj ) );
//return;



	if( ( !pID && !cID ) || ( pID && !piID ) || ( cID && !ciID) )
	{
//console.log('eSendB:  if');

		winWait( 'eSendB' );

 		$.getJSON( 'AJAX_InstIDs', 
									{ aID:aID, uID:uID, pID:pID, cID:cID, piID:piID, ciID:ciID },

									function(j) { 
													if( j.rC != 1 )
													{
														oe('eSendB.AJAX_InstIDs', 'j.rC= ' + j.rC);

														return;
													}

													if( j.nlcF )	// newLibraryCampaignFlag...  so capture newly-generated campaignID...
													{
														camObj.cID = j.cID;	// do NOT reset nF...
													}

													if( j.nceiF )	// NewCampEmailInstanceFlag
													{
														ncei( j.nID, null, o );	// ctObj
													}

													if( !j.nceiF || ( j.nceiF && !camSavF ) )	// if j.nceiF && camSavF, then ncei() calls eSendC ...
													{
//console.log('eSendB.AJAX_InstIDs:   if --> eSendCHB');
														eSendCHB( 'eSendB', evt, o );
													}

							}).fail(function(jx, ts, er) { oae('eSendB.AJAX_InstIDs', jx, ts, er); });
	}
	else
	{
//console.log('eSendB:  eSendCHB else');
		return eSendCHB( 'eSendB', evt, o );
	}
}






