function camSavSM()
{
	try
	{
//console.log('camSavSM:  camObj.actSent= ' + camObj.actSent + '  camObj.nf= ' + camObj.nf + '  camObj.actF= ' + camObj.actF + '  camObj.pID= ' + camObj.pID + '  camObj.cID= ' + camObj.cID);

		var $m = $('#camModal .modal-body > .tabbable'), 

			$tAa = $m.find('#cam-tabs-list').find('> li > a').not('.addTab');	//, $tDa = $m.find('> .tab-content > div');

		var ctID, ctObj;
	
		var df = true,	// doneFlag...
			pf = false;	// processFlag...

		var cntr = 0;

		$tAa.each( function(i, o) {
									cntr++;
	
									var hrf  = $(this).attr('href'), 
										tTtl = $(this).text();

									ctID = hrf.substring(1);

									ctObj = camObj[ctID];

									var $tc = $('#camModal .modal-body > .tabbable > .tab-content').find( hrf ),
										eS  = $tc.find('.eSubject').val();

									var eB;
									if( tmceF )
									{
//											  eB = tinymce.get('camMCE' + ctID).getContent();	// tinymce.get('camMCE' + 'ct' + ctObj.id).getContent();	// tinymce.activeEditor.getContent();
//										try { eB = tinymce.get('camMCE' + ctID).getContent(); } catch(err) { eB = null; }	// ctID = 'ct3863'
//										if( !eB )
//										{
											var $ta  = $tc.find('.cContent').find('> textarea.camMCE'),
												taID = $ta.attr('id');
//console.log('camSavSM:  $ta.length= ' + $ta.length + '  taID= ' + taID);

											try { eB = tinymce.get( taID ).getContent(); } catch(err) { eB = null; }	// <<<<<<<<<<<<<<<<<<<<
//										}
									}
//console.log('camSavSM:  cntr= ' + cntr + '  hrf= ' + hrf + '  tTtl= ' + tTtl + '  ctID= ' + ctID + '  eS.trim().length= ' + eS.trim().length + ' $( eB ).text().trim().length= ' + ( eB ? $( eB ).text().trim().length : eB) );


										if( tTtl.startsWith('Optional second email...') || tTtl.startsWith('Another email...') || eB == null || $( eB ).text().trim().length == 0 )
										{
											ctObj.ss = 2;	// done...
										}

									if( !ctObj.ss ) { ctObj.ss = 0; }
//console.log('camSavSM:  ctObj.ss= ' + ctObj.ss + '  parseInt(ctObj.ss, 10)= ' + parseInt(ctObj.ss, 10) + '  for ctID= ' + ctID);

									switch( parseInt(ctObj.ss, 10) )
									{
										case	0	:	df = false;		pf = true;		break;
	
										case	1	:	df = false;						break;		// do NOT exit...
	
// default is true...					case	2	:	df = true;		break
									}
//console.log('camSavSM:  df= ' + df + '  pf= ' + pf + '  ctID= ' + ctID);

									if( pf ) { return false; }	// return false exits .each loop...

						});	// each

//console.log('camSavSM:  cntr= ' + cntr + '  df= ' + df + '  pf= ' + pf);	// +  '  camSavIntervCntr= ' + camSavIntervCntr

		if( pf )
		{
			eSendB( null, { savF:true, camSavF:true, ctObj:ctObj } );
		}

		else if( !df )	// nothing left to process, but processing not yet complete...
		{
//console.log('camSavSM:  else if( !df ) ');	// +  '  camSavIntervCntr= ' + camSavIntervCntr
//			if( !camSavIntervId ) { camSavIntervId = window.setInterval( camSavSM, 500 ); }	// wait 1/2 second and try again...
//			camSavIntervCntr++;
		}

		else
		{
			var iIDs;

			var $tAa = $('#camModal .modal-body > .tabbable').find('#cam-tabs-list').find('> li > a').not('.addTab');


			$tAa.each( function(i, o) {
										var hrf = $(this).attr('href'), 
											id  = hrf.substring(3);	// #ct1234

										if( !iIDs ) { iIDs = id; } else { iIDs = iIDs + ',' + id; }
									});
//console.log('camSavSM:  camObj.pID= ' + camObj.pID + '  iIDs= ' + iIDs);


			if( camObj.pID )
			{
				var camActF = false;		if( $('#camModal').find('#camAct').is(':checked') ) { camActF = true; }	
//console.log('camSavSM:  camActF= ' + camActF + '  camObj.xweF= ' + camObj.xweF + '  camObj.camRulesBtnFlag= ' + camObj.camRulesBtnFlag + '  camObj.opnFUpID= ' + camObj.opnFUpID + '  camObj.lnkFUpID= ' + camObj.lnkFUpID + '  camObj.repFUpID= ' + camObj.repFUpID + '  camObj.pID= ' + camObj.pID + '  camObj.cID= ' + camObj.cID);

				if( !camActF ) { HideDripIndicators( ); }
// ---
				if( !camActF ) { $('#camRulesBtn').show(0); }	// <<<<<<<<<<<<<<<<<<<<<<<<
// ---
				$.getJSON( 'AJAX_ProjectDef', { tmceF:tmceF, aID:aID, uID:uID, pID:camObj.pID, cID:camObj.cID, 	xweF:camObj.xweF, 	opnFUpID:camObj.opnFUpID, lnkFUpID:camObj.lnkFUpID,	repFUpID:camObj.repFUpID, iIDs:iIDs, actF:camActF,  psavf:true }, function( j ) { j.camActF = camActF;   camSavSMcb( j ); }).fail(function(jx, ts, er) { oae('camSavSM.AJAX_ProjectDef', jx, ts, er); });
			}
			else
			{
//console.log('camSavSM:  else call AJAX_LibCampaignDef');

				$.getJSON( 'AJAX_LibCampaignDef', { tmceF:tmceF, aID:aID, uID:uID, cID:camObj.cID, iIDs:iIDs, psavf:true }, function( j ) { camSavSMcb( j ); }).fail(function(jx, ts, er) { oae('camSavSM.AJAX_LibCampaignDef', jx, ts, er); });
			}
		}
	}
	catch(er)
	{
		oe('camSavSM:', 'er= ' + er);
	}
}



function camSavSMcb( j )
{
//console.log('camSavSMcb:  j.rC= ' + j.rC + '  j.camActF= ' + j.camActF + '  j.neCnt= ' + j.neCnt + '  camObj.pID= ' + camObj.pID + '  camObj.camTtl= ' + camObj.camTtl + '  camObj.cID= ' + camObj.cID);

	if( j.rC != 1 )
	{
		oe('camSavSMcb', 'j.rC= ' + j.rc);

		return;
	}


	if( camObj.pID )
	{
		$('.outSB' + camObj.pID).attr('aef', (j.camActF ? 1 : 0) );		// outpID
	}


	camObj.nf = false;

	if( !camObj.pID && camObj.camTtl )	// a libCamSave...
	{
		$('#camModal').find('.modal-header').find('h4.modal-title').html('<span class="pt">' + camObj.camTtl + '</span><i class="ttip fa fa-pencil hover-edit" title="Edit campaign title"></i>').show(0).end()

			.find('.fa-pencil').off('click').on('click', camSavTtlCatPop).tooltip( { placement: 'bottom', delay: 200 } );
	}

	$('#camModal').find('button.btn-sav').tooltip('hide');

//console.log('camSavSMcb:  j.camActF= ' + j.camActF + '  camObj.pID= ' + camObj.pID + '  camObj.cID= ' + camObj.cID + '  camObj.clsEmpF= ' + camObj.clsEmpF + '  camObj.ocO= ' + camObj.ocO);


		if( camObj.pID && j.camActF )
		{
// ---
	camObj.savF = false;
// ---
			projCamAct( j );
		}
		else
		{
			clearWinWait('camSavSMcb');

			camObj.savF = false;

			panelRefresh( 'camSavSMcb', null, null, 'Campaigns', true, true );		// panelRefresh( cBy, evt, e, id, brf, savF )

			if( camObj.ocO )	// onCloseObj...
			{
//console.log('camSavSMcb.camObj.ocO:  camObj.clsEmpF= ' + camObj.clsEmpF);

				setTimeout( function() { camCls( 'camSavSMcb', null, camObj.j, camObj.clsEmpF ); }, 400);		// allow winwait to clear...
			}
			else
			{
				setTimeout( function() { pmp( 'Save complete', { clsTO:2000 } ); }, 400);		// allow winwait to clear...
			}
		}
}






