function emailSendStatus()
{
//if( !pF ) { console.log('emailSendStatus:  emailStatusObj= ' + (emailStatusObj ? JSON.stringify(emailStatusObj) : emailStatusObj) ); }

	$.ajax({
			url: "AJAX_SendEmailStatus",

			data: { aID:aID, uID:uID, pID:0, dsF:true },	// KEEP pID:0,  dripStatusFlag		

			timeout: 0,

			type: "GET",		// type: "POST",	// <-- switch to a "GET" due to chrome FU...

			dataType: "json"
	})

	.done( function(jsn, ts, jx) { 
//if( !pF ) { console.log('emailSendStatus.AJAX_SendEmailStatus:  jsn= ' + (jsn ? JSON.stringify(jsn) : jsn) ); }

									if( !jsn ) { return false; }

									if( jsn && typeof jsn == 'string' ) { jsn = JSON.parse(jsn); }	

									if( !jsn.rC || jsn.rC == 9 || !jsn.pID ) { return; }


									if( emailStatusObj && emailStatusObj.pID && jsn.pID == emailStatusObj.pID )
									{
										if( jsn.DripF && emailStatusObj.piID && jsn.piID && jsn.piID != emailStatusObj.piID )	// piID ONLY exists if DripF...
										{
											// Same list/campaign, but different email within campaign so restart progBar...
										}
										else
										{
											return;
										}
									}

									emailStatusObj = { pID:jsn.pID, piID:jsn.piID, DripF:jsn.DripF, list:jsn.list, eSub:jsn.eSub };

									initFtrProgBar( 'emailSendStatus' );
	})

	.fail(function(jx, ts, er) { if( er ) { oae('emailSendStatus.AJAX_SendEmailStatus', jx, ts, er); }	try { if( dripStatusIntervalID ) { clearInterval(dripStatusIntervalID);  dripStatusIntervalID = null; } } catch(er) { dripStatusIntervalID = null; } });
}






function emailStatusProgBar()
{
//if( !pF ) { console.log('emailStatusProgBar:  emailStatusObj= ' + (emailStatusObj ? JSON.stringify(emailStatusObj) : emailStatusObj) ); }

	$.ajax({
			url: "AJAX_SendEmailStatus",

			data: { uID:uID, pID:emailStatusObj.pID },	// pID:outpID

			timeout: 0,

			type: "GET",		// type: "POST",	// <-- switch to a "GET" due to chrome FU...

			dataType: "json"
	})

	.done( function(jsn, ts, jx) { 
									if( !jsn ) { return false; }

									if( jsn && typeof jsn == 'string' ) { jsn = JSON.parse(jsn); }	

//if( !pF ) { console.log('emailStatusProgBar.AJAX_SendEmailStatus  jsn= ' + JSON.stringify(jsn)); }
//if( !pF ) { console.log('emailStatusProgBar.AJAX_SendEmailStatus  jsn.rC= ' + jsn.rC + '  jsn.DripF= ' + jsn.DripF + '  jsn.rCntr= ' + jsn.rCntr + '  jsn.eCntr= ' + jsn.eCntr + '  jsn.fCntr= ' + jsn.fCntr); }
/*
      JsonObj.put("rCntr", 	RecipientsCnt);
      JsonObj.put("eCntr", 	EmailedCnt);
      JsonObj.put("fCntr", 	ErrorCnt);		// failed...
      JsonObj.put("rC", 	StatusInt);		// 0 (exception), 1 (underway), 2 (complete), 9 (problem)	<<<<<<<<<<<<<<<<<<<<<<<<<<<<<
*/
// ---
									if( jsn.rC && jsn.rC > 0 ) { emailSendStatusFailedCntr = 0; }	// reset...
// ---

									if( jsn.rC == 9 )
									{
										if( dripF )
										{
											closeFtrProgBar();
										}

										oe('emailStatusProgBar.AJAX_SendEmailStatus', 'jsn.rC= ' + jsn.rC + '  for jsn.pID= ' + jsn.pID + '  and dripF= ' + dripF);

										try { if( emailStatusIntervalID ) { clearInterval(emailStatusIntervalID);  emailStatusIntervalID = null; } } catch(er) { emailStatusIntervalID = null; }
// ---
		try { if( emailStatusHmDashIntervalID ) { clearInterval(emailStatusHmDashIntervalID);  emailStatusHmDashIntervalID = null; } } catch(er) { emailStatusHmDashIntervalID = null; }

		emailStatusRefHmDash( true );	// final refresh...		doneF
// ---
									}

									else if( jsn.rC == 2 || (jsn.eCntr + jsn.fCntr + jsn.sCntr) >= jsn.rCntr )
									{
										if( dripF )
										{
											let $e = $('#ftrProgBar');

												$e.find('.progStatus').text('Emailing complete').end().find('.front').css( { 'clip-path': 'inset(0 0 0 100%)' } );
												$e.find('.gears').fadeOut();

												setTimeout(function() { 
																		$e.find('.PBclose').fadeIn();

																		$e.find('.PBclose').off('click').on('click', closeFtrProgBar);
															}, 400);


											if( !emailStatusObj || !emailStatusObj.DripF )	// NOT
											{
												updateSentDate();
											}
										}
										else
										{
											$('#emStatusProgBar').attr('aria-valuenow', jsn.rCntr).css('width', '100%');

											setTimeout(function() { 
																	let m = 'Emailing complete';

																	updateSentDate( m );

																}, 2000);
										}

										try { if( emailStatusIntervalID ) { clearInterval(emailStatusIntervalID);  emailStatusIntervalID = null; } } catch(er) { emailStatusIntervalID = null; }
// ---
		try { if( emailStatusHmDashIntervalID ) { clearInterval(emailStatusHmDashIntervalID);  emailStatusHmDashIntervalID = null; } } catch(er) { emailStatusHmDashIntervalID = null; }

		emailStatusRefHmDash( true );	// final refresh...		doneF
// ---
									}

									else if( jsn.rC > 0 )
									{
/*
if( !pF ) { console.log('emailStatusProgBar.AJAX_SendEmailStatus  starting jsn.rCntr= ' + jsn.rCntr + '  emailStatusObj.maxSend= ' + (emailStatusObj && emailStatusObj.maxSend ? emailStatusObj.maxSend : emailStatusObj) ); }
	if(emailStatusObj && emailStatusObj.maxSend && emailStatusObj.maxSend < jsn.rCntr ) { jsn.rCntr = emailStatusObj.maxSend; }
if( !pF ) { console.log('emailStatusProgBar.AJAX_SendEmailStatus  ending jsn.rCntr= ' + jsn.rCntr); }
*/
										var w = Math.round( ( (jsn.eCntr + jsn.fCntr)/jsn.rCntr )*100 ) + '%';

										if( dripF )
										{
											if( jsn.eCntr && jsn.rCntr )	// ONLY update if we have emailed leads...
											{
	$('#ftrProgBar').find('.progStatus').text( jsn.eCntr + ' of ' + jsn.rCntr + ' leads emailed').end().find('.front').css( { 'clip-path': 'inset(0 0 0 ' + w + ')' } );
											}
										}
										else
										{
											$('#emStatusProgBar').attr('aria-valuenow', (jsn.eCntr + jsn.fCntr)).css('width', w);
										}
									}

									else
									{
										if( dripF )
										{
											closeFtrProgBar();
										}

										emailSendStatusFailedCntr++;

										if( emailSendStatusFailedCntr > 10 )
										{
											oe('emailStatusProgBar.AJAX_SendEmailStatus', 'jsn.rC= ' + jsn.rC + '  for jsn.pID= ' + jsn.pID + '  and dripF= ' + dripF);

											try { if( emailStatusIntervalID ) { clearInterval(emailStatusIntervalID);  emailStatusIntervalID = null; } } catch(er) { emailStatusIntervalID = null; }
// ---
		try { if( emailStatusHmDashIntervalID ) { clearInterval(emailStatusHmDashIntervalID);  emailStatusHmDashIntervalID = null; } } catch(er) { emailStatusHmDashIntervalID = null; }

		emailStatusRefHmDash( true );	// final refresh...		doneF
// ---
										}
									}
	})

	.fail(function(jx, ts, er) { 
								if( er ) { oae('emailStatusProgBar.AJAX_SendEmailStatus.oae', jx, ts, er); }	

								try { if( emailStatusIntervalID ) { clearInterval(emailStatusIntervalID);  emailStatusIntervalID = null; } } catch(er) { emailStatusIntervalID = null; } 
// ---
		try { if( emailStatusHmDashIntervalID ) { clearInterval(emailStatusHmDashIntervalID);  emailStatusHmDashIntervalID = null; } } catch(er) { emailStatusHmDashIntervalID = null; }

		emailStatusRefHmDash( true );	// final refresh...		doneF
// ---
	});
}



function closeFtrProgBar()
{
	emailStatusObj = null;	// reset...

	let $e = $('#ftrProgBar');

		$e.fadeOut();

	setTimeout(function() { 
							$e.find('.progStatus').text('emailing underway').css( { 'clip-path': 'inset(0 0 0 0%)' } );

							$('#usr-review').fadeIn();

							if( $('body').outerWidth() < 1400 )
							{
								$('#outProspects_wrapper').find('.dt-info').find('.legend').fadeIn();
							}
			}, 400);
}




function updateSentDate( m )	// m may be undefined/null...
{
//console.log('updateSentDate:  m= ' + m );
// ---
	if( !emailStatusObj ) { emailStatusObj = {}; }	// KEEP!!!!		 eSendCB called by BOTH eSendCHB AND eSendC (if not a testAcct)...
//console.log('updateSentDate:  emailStatusObj= ' + (emailStatusObj ? JSON.stringify(emailStatusObj) : emailStatusObj) );
//console.log('updateSentDate:  emailStatusObj.DripF= ' + emailStatusObj.DripF );
//console.log('updateSentDate:  emailStatusObj.dtIDa= ' + emailStatusObj.dtIDa );
// ---

	if( emailStatusObj.dtIDa )
	{
		var dt = new Date(), row, rd;

		emailStatusObj.dtIDa.forEach(function (dtID, idx) {		// emailStatusObj.cIDa.forEach(function (cID, idx) {
//console.log('updateSentDate:  dtID= ' + dtID);
															row = opdt.row( dtID );
//console.log('updateSentDate:  row= ' + row);
															rd = row.data();
//console.log('updateSentDate:  rd= ' + rd);
//if( rd ) { console.log('updateSentDate:  rd= ' + JSON.stringify(rd) ); }
															rd.emailed 	  = dt;
// ---
															rd.anyEmailed = dt;
// ---
															row.data( rd ).draw(false);	// do NOT reset pagination!!
									});	// forEach
	}

// ----
		if( m ) { setTimeout(function() { pmp( m, { } ); }, 500); }

		if( eCntrsObj.id == 'opeapnpeDD' )	// do NOT clear if selected prospects!!!!
		{
			eCntrsObj[eCntrsObj.id] = [];

// NO!!		eCntrsObj.id = null;
		}
// ----

/*
emailStatusObj.eDosFlag  = eDosFlag;
emailStatusObj.aiDosFlag = aiDosFlag;
*/

//	if( emailStatusObj && !emailStatusObj.DripF && !emailStatusObj.dtIDa ) { opref(); }		// if executing eSendC, rather than eSendCHB, then no emailStatusObj so refresh entire list...
	if( emailStatusObj && !emailStatusObj.DripF && !emailStatusObj.dtIDa && !emailStatusObj.eDosFlag ) { opref(); }		// if executing eSendC, rather than eSendCHB, then no emailStatusObj so refresh entire list...
}






