function camSavTtlCatPop()
{
//console.log('camSavTtlCatPop:  camObj.delF= ' + camObj.delF + '  camObj.nf= ' + camObj.nf + '  camObj.pID= ' + camObj.pID + '  camObj.cID= ' + camObj.cID);

	var mTtl = 'Save Campaign', ttl, n = 0, li='';	//, cCID, camcTxt;


	if( camObj && camObj.delF ) { $('#camModal').find('#camDel').popover('hide');  camObj.delF = false;	n = 500; } 


	setTimeout(function() {
							ttl = camObj.camTtl;

							if( !ttl || ttl.trim().length == 0 )
							{
								if( camObj.nf && !camObj.pID )
								{
									ttl = '';
								}
								else
								{
									ttl = $('#camModal').find('.modal-header > h4.out-title > span.pt').text();
								}
						
								if( !ttl || ttl.trim().length == 0 ) { ttl = ''; }
							}

							ttl = ttl.replace(/&#39;/g, "'");   
							ttl = ttl.replace(/&#34;/g, '"');


							if( !camObj.nf ) { mTtl = 'Edit Campaign Title'; }


							$savCamPopMdl.find('.modal-header').show(0).find('.modal-title').text( mTtl );

							$savCamPopMdl.find('input#camTitle').val( ttl ).off('click').on('click', function() { $(this).removeClass('HL'); });

							$savCamPopMdl.find('.modal-footer').find('button.btn-save').show(0).end().show(0).find('button').off('click').on('click', function(evt) { camSavTtlCatPopBtn( evt ); });

//							$savCamPopMdl.modal( { width: 400, keyboard: true, backdrop: 'static', show: true } );	//.on( 'hidden.bs.modal', function() { });
							$savCamPopMdl.modal( { width: 400, keyboard: true, show: true } );	//.on( 'hidden.bs.modal', function() { });

							cMdl( $savCamPopMdl );

							if( camObj.nf && !camObj.pID ) { { setTimeout(function() { $savCamPopMdl.find('input#camTitle').focus(); }, 400); } }
			}, n);
}



function camSavTtlCatPopBtn( evt )
{
	evtStop(evt);

	var $e = $(evt.target);

		$e.blur();


	$savCamPopMdl.find('input').removeClass('HL');

	var camTtl=$savCamPopMdl.find('#camTitle').val(), catID=0;	// SAVE  catID=$savCamPopMdl.find('#outLibCampSC button').attr('data').substring(6);

//console.log('camSavTtlCatPopBtn:  camObj.cID= ' + camObj.cID + '  camObj.pID= ' + camObj.pID + '  camTtl= ' + camTtl + '  catID= ' + catID);

	if(camTtl.trim().length == 0)
	{
		$savCamPopMdl.find('#camTitle').addClass('HL');

		return;
	}

	camObj.camTtl = camTtl;

	camObj.catID = catID;

	$savCamPopMdl.modal('hide');


	if( !camObj.pID )	// a libCam...
	{
		camSavSav();
	}
	else
	{
		winWait( 'camSavTtlCatPopBtn' );

		camTtl = camObj.camTtl;		//, catID = camObj.catID;
//console.log('camSavTtlCatPopBtn:  camTtl= ' + camTtl + '  camObj.camSubs= ' + camObj.camSubs);

		$.post(	'AJAX_LibCampaignDef',

				{ tmceF:tmceF, aID:aID, uID:uID, cID:camObj.cID, catID:catID, camTtl:camTtl, camSubs:camObj.camSubs, savf:true },

				function( j ) { if( j.rC != 1 ) { oe('camSavTtlCatPopBtn.AJAX_LibCampaignDef', 'j.rC= ' + j.rC);  	return; }		camObj.nf=false;	camObj.camSubs=null;	camObj.cID=j.cID;	setTimeout(function() { clearWinWait('camSavTtlCatPopBtn');		setTimeout(function() { pmp('Template saved', { clsTO:2000 });		panelRefresh( 'camSavTtlCatPopBtn.AJAX_LibCampaignDef', null, null, 'Campaigns', true, false ); }, 400); }, 2000);	},		// panelRefresh( cBy, evt, e, id, brf, savF )

				'json'

			).fail(function(jx, ts, er) { oae('camSavTtlCatPopBtn.AJAX_LibCampaignDef', jx, ts, er); });
	}
}
