// ---

		$outLibCamsMdl.find('.modal-header').show(0).find('.modal-title').html( '&nbsp;' );		// Sequence Templates

//			.end().find('button.tstClose').off('click').on('click', outLibCamsMdlCls);


	$outLibCamsMdl.modal( { width: w, height: mht, keyboard: true, backdrop: 'static', show: true } )

