function dgLnkBtn( evt )
{
//console.log('dgLnkBtn:  ');

	if( evt ) { evtStop(evt); }

	try { $dgLnkBtn.tooltip('hide'); } catch(er){}


// -----
		if( $dgLnkBtn.parent().find('.popover').is(':visible') )
		{
//console.log('dgLnkBtn:  visible return');

			$dgLnkBtn.popover('hide');

			return;
		}
// -----



	var rng, $e = $('#gDOS').find('.note-editable');

	try
	{
		var $gWP = $e.find('#gravWP'), gWPf, plf;
//console.log('dgLnkBtn:  $gWP.length= ' + $gWP.length);

		if( $gWP.length > 0 )
		{
			gWPf = true;

			plf = $gWP.hasClass('pstLnk');
//console.log('dgLnkBtn:  gWPf = ' + gWPf + '  plf= ' + plf);

			if( !plf )
			{
				var t = $e.find('#gravWP').text();
//console.log('dgLnkBtn:  t= ' + t);
					t = t.replace(/\u00a0/g, "");	// replace &nbsp;...
//console.log('dgLnkBtn:  t= ' + t + '  t.trim().length= ' + t.trim().length);

					if( t.trim().length > 0 )
					{
						eEditLink();
	
						return;
					}
			}
		}

		rng = window.getSelection().getRangeAt(0);
//console.log('dgLnkBtn:  rng.collapsed= ' + rng.collapsed + '  rng.toString().trim().length= ' + rng.toString().trim().length);

		if(rng.collapsed || rng.toString().trim().length == 0)
		{
			rng = null;
		}
		else
		{
			try
			{
				rng = window.getSelection();
//console.log('dgLnkBtn:  rng.anchorNode= ' + rng.anchorNode);
//console.log('dgLnkBtn:  rng.anchorNode.nodeValue= ' + rng.anchorNode.nodeValue);
//console.log('dgLnkBtn:  starting rng.focusOffset= ' + rng.focusOffset);

				var sTxt = rng.anchorNode.nodeValue.substring(rng.anchorOffset, rng.focusOffset);
//console.log('dgLnkBtn:  starting sTxt= ' + sTxt);
//console.log('dgLnkBtn:  starting sTxt.length= ' + sTxt.length);

				while( sTxt.endsWith(' ') )
				{
					sTxt = sTxt.substring(0, (sTxt.length-1));
	
					rng.modify("extend", "backward", "character");
				}
//sTxt = rng.anchorNode.nodeValue.substring(rng.anchorOffset, rng.focusOffset);
//console.log('dgLnkBtn:  ending rng.focusOffset= ' + rng.focusOffset);
//console.log('dgLnkBtn:  ending sTxt= ' + sTxt);
//console.log('dgLnkBtn:  ending sTxt.length= ' + sTxt.length);

				eEditLink( null, { rng:rng.getRangeAt(0) } );
			}
			catch(er)
			{
				rng = window.getSelection().getRangeAt(0);

				eEditLink( null, { rng:rng } );
			}
		}
	}
	catch(er)	// OK...
	{
		if( er.message.indexOf('partially selected a non-Text') != -1 )
		{
			rpt('dgLnkBtn:', er.message);

			pmp('Links cannot contain preceding or following spaces or punctuation');
		}
	}


	if( !rng )
	{
		eLinkHlp( evt );
	}
}




