function sigLinkHlp( evt )
{
//console.log('sigLinkHlp:  evt= ' + evt);

	let h = 'First select the email text that you <br>would like to associate with a link';

// -----
	let $b = $(evt.target);

//console.log("sigLinkHlp:  $b.find('.popover').is(':visible')= " + $b.find('.popover').is(':visible'));

	if( $b.parent().find('.popover').is(':visible') )
	{
//console.log('sigLinkHlp:  visible return');

		$b.removeClass('active');

		$b.popover('hide');

		return;
	}

	$sigLnkBtn.popover({ html: true, placement: 'bottom', content: '<div style="float:left;  overflow:visible;  white-space:nowrap;  color:#08c;  width:210px; padding:0 0 7px 0;">' + h + '</div>' }).on('show.bs.popover', function(){ $(this).data('bs.popover').tip().css('max-width', '600px'); }).on('hidden.bs.popover', function(){ $(this).popover('destroy'); }).popover('show');
// -----
}


function sigEditLink ( evt )
{
	evtStop(evt);
//console.log('sigEditLink:  ');	// id = evt.target.id, 

	var $e = $(evt.target), cntr = 0, href;	// href = $e.attr('href');

	while( cntr < 4 && $e.get(0).tagName.toLowerCase() != 'a' ) { cntr++; 	$e = $e.parent(); }

		if( $e.get(0).tagName.toLowerCase() == 'a' ) { href = $e.attr('href'); }
//console.log('sigEditLink:  href= ' + href);


	if( !href || href.trim().length < 5 ) { href = ''; }


	var $m = $('#sigLinkModal');

		$m.find('.modal-header').show(0).find('.modal-title').text('Edit Email Signature Link');

		$m.find('.modal-body').find('#siglUrl').val( href ).removeClass('HL').off('click').on('click', function(){ $(this).removeClass('HL'); });

//		$m.find('.modal-footer').show(0).find('button').off('click').on('click', function(evnt) { sigLinkBtns(evnt, id); } );
		$m.find('.modal-footer').show(0).find('button').off('click').on('click', function(evnt) { sigLinkBtns(evnt, $e); } );

		$m.modal( { width: 450, keyboard: true, backdrop: 'static' } ).on( 'hidden.bs.modal', function() { });
		$m.show();
		$m.find('.modal-body').find('#siglUrl').focus().blur();

	return false;	// ensures that any assigned href URL is NOT executed...
}



function sigLinkBtns( evt, $e )		// sigLinkID
{
//console.log('sigLinkBtns:  $e= ' + $e);
//console.log('sigLinkBtns:  $e.attr("id")= ' + $e.attr("id"));
//console.log('sigLinkBtns:  $e.attr("href")= ' + $e.attr("href"));

	evtStop(evt);

	var $b = $(evt.target), $m = $('#sigLinkModal');

	if( $b.hasClass('btn-rem') )
	{
 		$e.each(function() { $(this).off('click').replaceWith(this.childNodes); });

		$m.modal('hide');
	}
	else
	{
		var u = $m.find('#siglUrl').val();
//console.log('sigLinkBtns:  u= ' + u);
			if(u.trim().length < 5)
			{
				$m.find('#siglUrl').addClass('HL');

				pmm('Please first enter an internet address (URL)', null, 2);

				return;
			}

		if( u.indexOf('@') > 0 )	// an email address...
		{
			if( !u.toLowerCase().startsWith('mailto') ) { u = 'mailto:' + u.toLowerCase(); }
		}

		else if( u.toLowerCase().startsWith('tel:') )
		{
		}

		else if( !u.toLowerCase().startsWith('http') )
		{
			u = 'https://' + u;
		}
//console.log('sigLinkBtns:  u= ' + u);


		if( $b.hasClass('btn-prev') )
		{
			if( u.indexOf('@') > 0 )	// an email address...
			{
				pmm('Cannot preview mailto links', null, 2);
			}

			else if( u.toLowerCase().startsWith('tel:') )
			{
				pmm('Cannot preview telephone links', null, 2);
			}

			else
			{
				var win = window.open(u, '_blank');  

				win.focus();
			}
		}


		else if( $b.hasClass('btn-save') )
		{
//console.log('sigLinkBtns:  btn-save  u= ' + u);

			$e.attr('href', u);

/*
			if( $e.attr('href') )	// editing an existing link...
			{
				$e.attr('href', u);
			}
			else	// creating a new link
			{
				let id = $e.attr('id');		// id ONLY exists when creating NEW link...
console.log('sigLinkBtns:  btn-save  else  id= ' + id);
				$('#panel_signature').find('.note-editable').find('#' + id).attr('href', u);
			}
*/

			$m.modal('hide');

			$('#emSigUpdtBtn').addClass('savHL');

		}	// else if save...

	}	// else NOT remove...

}	// sigLinkBtns








