function eLinkHlpIgnore( btnEvt, evt, $m, $tc, o )
{
//console.log("eLinkHlpIgnore:  ");

	evtStop( btnEvt );

	$(btnEvt.target).blur();


	var eDosFlag;  if( o && o.eDosFlag ) { eDosFlag = o.eDosFlag; }

	var $b = $(btnEvt.target);
//console.log("eLinkHlpIgnore:  $b.hasClass('btn-confirm')= " + $b.hasClass('btn-confirm'));

	if( $b.hasClass('btn-confirm') )
	{
		winWait( 'eLinkHlpIgnore' );

		if( eDosFlag )
		{
			dObj.ignoreF = true;

			$dgLnkBtn.popover('hide');
		}
		else
		{
			$tc.find('.eContent .note-editor .note-toolbar .note-gLnk').popover('hide');

			camObj.ignoreF = true;
		}

//console.log('eLinkHlpIgnore:  eSendCHB');

		eSendCHB( 'eLinkHlpIgnore', evt, o );
	}

	$m.modal('hide');
}




