		{
			let $tc = $('#camModal .modal-body > .tabbable > .tab-content > div.active'), ctID = $tc.attr('id'), ctObj = camObj[ctID], eObj = ctObj.eObj; 

			lpUrl = eObj.lpUrl;
			lpOFN = eObj.lpOFN;
		}

