function RestoreLeads( evt, $m, allF )
{
//console.log('RestoreLeads:  allF= ' + allF);

	evtStop( evt );

	$(evt.target).blur();

	if( !allF ) { allF = false; }

	var $b = $(evt.target);
//console.log("ArchiveCam:  $b.hasClass('btn-confirm')= " + $b.hasClass('btn-confirm'));

	if( $b.hasClass('btn-confirm') )
	{
		$m.modal('hide');

		winWait( 'RestoreLeads' );

		$.post(	'AJAX_CMR', 

				{ aID:aID, uID:uID, glc:glc, from:outpID, to:outpID, ec:'r', allF:allF }, 	// keep both from and to...

				function( j ) {
								if( j.rC != 1 )
								{
									oe('RestoreLeads.AJAX_CMR', 'j.rC != 1');

									return;
								}

								if( !j.resCnt )
								{
									clearWinWait('ArchiveCam');

									setTimeout( function() { 
																let m = 'No recently-removed leads found';

																if( allF )
																	m = 'No removed leads found';

																pmp( m ); 
													}, 500 );

									return;
								}

//								if( engF )
//									$('#engSB' + outpID).trigger( 'click', { pID:outpID, cmdF:true, resCnt:j.resCnt } );
//								else
									$('#outSB' + outpID).trigger( 'click', { pID:outpID, cmdF:true, resCnt:j.resCnt } );
							},	
				'json'

 				).fail(function(jx, ts, er) { if(!jx || !jx.status || jx.status != 200) { oae('RestoreLeads.AJAX_CMR  a= ' + a, jx, ts, er); } });
	}
}




function ArchiveCam( evt, $m )
{
//console.log("ArchiveCam:  ");

	evtStop( evt );

	$(evt.target).blur();

	var $b = $(evt.target);
//console.log("ArchiveCam:  $b.hasClass('btn-confirm')= " + $b.hasClass('btn-confirm'));

	if( $b.hasClass('btn-confirm') )
	{
		winWait( 'ArchiveCam' );

		$.getJSON( 'AJAX_ArchiveCam', { aID:aID, uID:uID, pID:outpID }, function(j) { ArchiveCamCB(j, $m); } ).fail(function(jx, ts, er) { oae('ArchiveCam.AJAX_ArchiveCam', jx, ts, er); });
	}
}


function ArchiveCamCB( j, $m )
{
//console.log('ArchiveCamCB:  j.rC= ' + j.rC + '  j.pID= ' + pID);

	if(j.rC != 1) { oe('ArchiveCamCB', 'j.rC= ' + j.rC);		return; }

	if( j.pID )
	{
		$m.modal('hide');

		outpID = 0;

		actpID = 0;

		$('#OutProjectProspects').hide();

		j.delf = true;

		aedpCB( JSON.stringify(j) );

		camArchF = true;
	}
}




