function repMgmBtn( evt, tstOnlyFlag )
{
//console.log('repMgmBtn:  tstOnlyFlag= ' + tstOnlyFlag + '  apaF= ' + apaF);

// ---
	if ( glc < 2 ) { reqUpGrd( 'repMgmBtn' );	return; }
// ---

	var esp = $('#panel_em_acct').find('input.eESP').val();	
//console.log('repMgmBtn:  esp= ' + esp);

		if( !esp || esp.length < 10 )
		{
			emAcctBtn( evt );

			return false;
		}

// ---
	var gglF = false, msF = false;		if( esp.indexOf('Google') != -1 ) { gglF = true; } else { msF = true; }
//console.log('repMgmBtn:  gglF= ' + gglF + '  msF= ' + msF);
// ---

// ---
	repUIconfig();
// ---


	pmpCls();	// KEEP!!!!

	winWait( 'repMgmBtn' );

	$.getJSON( 'emAcctBtnStatus', { cBy:'repMgmBtn', aID:aID, uID:uID }, 

		function( jsn )
		{
// console.log('repMgmBtn:  jsn= ' + (jsn ? JSON.stringify(jsn) : jsn) );		// {"sF":true,"msncaF":false,"gtaF":true,"gtatF":true,"fE":"greg@renostaffing.org","ESP":"Google Workspace","ctd":""}
			if( !jsn || !jsn.sF )
			{
				oe('repMgmBtn', '!jsn || !jsn.sF');

				return;
			}

			if( !jsn.fE || !jsn.ESP )	//  jsn= {"sF":true, "fE":"frank.tolve2@outlook.com", "ESP":"Microsoft Office 365"}
			{
				clearWinWait('repMgmBtn');

				setTimeout(function() { pmp( 'Please first specify your email Sender Account', { onClsFn: 'displaySenderUI()' } ); }, 400);

				return;
			}

			$('#panel_em_acct').find('input.eFrom').val( jsn.fE ).end().find('input.eESP').val( jsn.ESP );


			var feDom = jsn.fE.substring(jsn.fE.indexOf('@') + 1).toLowerCase();


			if( jsn.ctd ) { ctdF = true;	ctdJsn = jsn; }	// <<<<<<<<<<<<<<<<<


// ---
			if( tstOnlyFlag )
			{
				clearWinWait('repMgmBtn');

				return;
			}
// ---

			var cF = true, d = 'uID=' + uID + '&gglF=' + gglF + '&msF=' + msF + '&feDom=' + feDom;


			$('#panel_em_acct').find('.repMgmt').find('input').removeClass('red');	// clear...

			$('#panel_em_acct').find('.repMgmt').find('input')

					.each( function() { 

								var $t = $(this), id = $t.attr('id'), v = $t.val().trim();
//console.log('repMgmBtn:  id= ' + id + '  -->  v= ' + v + '  --> $.isNumeric(v)= ' + $.isNumeric(v));

								if( id != 'eDNC' && id != 'eGglUnSubCbox' )		// eDNC is the only non-numeric field...
								{
									if( !v ) { v = 0; }		// OK, all fields are optional...

									if( !$.isNumeric(v) )
									{
										clearWinWait('repMgmBtn');

										cF = false;

										$t.addClass('red');

										pmp('Please enter a valid number');

										return false;
									}
								}


								if( id != 'eGglUnSubCbox' )
								{
									d += '&' + id + '=' + v;
								}
							});


					d += '&eGglUnSubCbox=' + $('#eGglUnSubCbox').is(':checked');
//console.log('repMgmBtn:  cF= ' + cF + '  -->  d= ' + d);



					var gglMaxSend;		try { gglMaxSend = parseInt($('#eMaxGglSend').val(), 10); } catch(err) { gglMaxSend = 0; }
//console.log('repMgmBtn:  gglMaxSend= ' + gglMaxSend); 

					if( gglMaxSend >= 5000 )
					{
						if( gglF )
						{
							if( !$('#eGglUnSubCbox').is(':checked') )	// NOT checked...
							{
								$('#eGglUnSubCbox').prop('checked', true);

								var h 	= 'Google policy requires companies to include an unsubscribe email header when sending 5000+ daily emails'

										+ '<p style="margin-top:10px; text-align:center;"><a class="gglWhy" href="javascript:gglWhy()">View Google Policy</a></p>';

								pmp( h );

								cF = false;		// failsafe...

								return;
							}
						}

						else if( InitMsMaxGglSend < 5000 && !msUnsubEmHdrMsgFlag )	// NOT
						{
							msUnsubEmHdrMsgFlag  = true;

							var h 	= 'Google policy requires companies to include an unsubscribe email <br>header when sending 5000+ daily emails to Google recipients'

									+ '<p style="margin-top:10px; text-align:center;"><a class="gglWhy" href="javascript:gglWhy()">View Google Policy</a></p>'

									+ '<p style="margin-top:10px; text-align:center;">Contact your Office 365 admin or <a class="contactLL" href="mailto:team@leadleaper.net?Subject=Microsoft unsubscribe email headers: ' + jsn.fE.toLowerCase() + '">LeadLeaper</a> for assistance</p>';

							pmp( h );

							cF = false;		// failsafe...

							return;
						}
					}


			if( cF && d )
			{
				$.post( 'repMgmt', d, 

					function( j )
					{ 
//console.log('repMgmBtn.repMgmt:  j= ' + (j ? JSON.stringify(j) : j));
						if( !j || !j.sF ) { oe('repMgmBtn.repMgmt', '!j || !j.sF');  return; } 

						clearWinWait('repMgmBtn');

						pmp('Update complete');
					}, 

					'json' ).fail(function(jx, ts, er) { oae('repMgmBtn.repMgmt', jx, ts, er); });
			}

		}).fail(function(jx, ts, er) { if( er ) { oae('opemctd', jx, ts, er); } });
}



