			+	'<li>Your future <b>monthly</b> discovery credits will remain <b>' + numberWithCommas( emc ) + '</b></li>'

			+	'<li>Block credits do <b>not expire</b> or <b>auto-replenish</b> each month</li>'

			+	'<li>You will be billed <b>$' + cents/100 + ' once</b> for the additional credits</li>'

			+ 	'</ul>'

			+	'<p>Would you like to continue?</p>';
/* SAVE!!
	}
	else
	{
		h 	+=	'<ul class="subTabPDC">'
			+	'<li>Your total <b>remaining</b> credits for this month will be <b>' + numberWithCommas( trc ) + '</b></li>'
			+	'<li>Your future <b>monthly</b> discovery credits will now be <b>' + numberWithCommas( nmc ) + '</b></li>'
			+	'<li>Monthly credits are auto-replenished on the 1st of each month</li>'
			+	'<li>You will be billed an <b>additional $' + cents/100 + ' each month</b></li>'
			+	'<li>You may cancel this additional monthly billing anytime</li>'
			+ 	'</ul>'
			+	'<p>Would you like to continue?</p>';
	}
*/

	h 	+=	'</div>';


	var $m = $('#pdcModalYN');

		$m.find('.modal-header').hide(0);

		$m.find('.modal-body').html( h );

		$m.find('.modal-footer').show(0).find('button').show(0).off('click').on( 'click', function(evnt) { subTabPDCcon( evnt, bpF, id, cnt, cents ); } );	// DupDosEmailCByn( evt, j.dcID, newValue );

