function onUpdateUserProfile( evt )
{
// console.log('onUpdateUserProfile:  ');

	if( evt ) { evt.preventDefault(); }


	var $f = $('#panel_profile > form'), $e, v, meN, meE, meMgrCbox = 0;

	$e = $f.find('#eName'); v = $e.val().trim();

		if( v.length == 0 )
		{
			$e.parent().addClass('has-error').append('<span class="help-block">Please first enter your name</span>');

			return;
		}


		var a = v.split(/\s+/g);

		if( a.length < 2 )
		{
			$e.parent().addClass('has-error').append('<span class="help-block">Please first enter your first and last name</span>');

			return;
		}

/*
	$e = $f.find('#eTitle'); v = $e.val().trim();
		if( v.length == 0 )
		{
			$e.parent().addClass('has-error').append('<span class="help-block">Please first enter your title</span>');
			return;
		}
*/

	$e = $f.find('#eEmail'); v = $e.val().toLowerCase().trim();

		if( v.length == 0 )
		{
			$e.parent().addClass('has-error').append('<span class="help-block">Please first enter a business email address</span>');

			return;
		}

// ---
		var x = v.indexOf('@'), x2 = v.lastIndexOf('.'), dom = v.substring(x+1), dom2 = v.substring(x+1, x2);

		if( x == -1 || x2 < x )
		{
			$e.parent().addClass('has-error').append('<span class="help-block">Please first enter a valid business email address</span>');

			return;
		}


		if( fe.indexOf( dom ) != -1 || bl.indexOf( dom2 ) != -1 )
		{
			if( ( v.indexOf('@gmail.com') != -1 || v.indexOf('@googlemail.com') != -1 || v.indexOf('@outlook.com') != -1 ) )
			{
				$e = $('#gModal1');

				$e.find('.modal-header').hide(0);

				$e.find('.modal-body').html( '<div style="margin:10px 0;">Please first enter a business email address or contact <a href="javascript:gMdlHelp();">LeadLeaper</a> for assistance</div>' );

				$e.find('.modal-footer').show(0).find('button.btn-default').hide(0).end().find('button.btn-confirm').text('OK').show(0);

				$e.modal( { show: true } );

				cMdl( $e );

				return;
			}

			if( v.indexOf('@gmail') == -1 && v.indexOf('@googlemail') == -1 && v.indexOf('@outlook') == -1 )
			{
				$e.parent().addClass('has-error').append('<span class="help-block">Please first enter a business email address</span>');

				return;
			}
		}
// ---

/*
	$e = $f.find('#ePhone'); v = $e.val().trim();
		if( v.length == 0 )
		{
			$e.parent().addClass('has-error').append('<span class="help-block">Please first enter your phone number</span>');
			evt.preventDefault();
			return;
		}
*/


	$e = $f.find('#ePwd'); v = $e.val().trim();
//console.log('onUpdateUserProfile:   ePwd= ' + v);

		if( v.length == 0 )
		{
			$e.parent().addClass('has-error').append('<span class="help-block">Please first enter a password</span>');

			evt.preventDefault();

			return;
		}

	var pwd = v;

	$e = $f.find('#cePwd'); v = $e.val().trim();

		if( v.length == 0 )
		{
			$e.parent().addClass('has-error').append('<span class="help-block">Please first confirm your password</span>');

			return;
		}

		if( v.toUpperCase() != pwd.toUpperCase() )
		{
			$e.parent().addClass('has-error').append('<span class="help-block">Confirmation password does not match entered password</span>');

			return;
		}


	winWait( 'onUpdateUserProfile' );

	var d = $f.serialize() + '&aID=' + aID + '&uID=' + uID + '&uepF=true';

	$.post(	'AJAX_EditProfile', d, onUpdateUserProfileCB, 'json' ).fail(function(jx, ts, er) { oae('onUpdateUserProfile.AJAX_EditProfile', jx, ts, er); });
}



function onUpdateUserProfileCB( j )
{
//console.log('onUpdateUserProfileCB:  j.rC= ' + j.rC);

	clearWinWait('onUpdateUserProfileCB');

	var $b = $('#panel_profile > form').find(':submit'), cls='success', txt = 'Updated!';


	if( j.rC != 1 )	// a problem was encountered...
	{
		var $e;

		if( j.dupF || j.iedF || j.gglESP || j.msESP )
		{
			$e = $('#gModal1');

			$e.find('.modal-header').hide(0);

			$e.find('.modal-footer').show(0).find('button.btn-default').hide(0).end().find('button.btn-confirm').text('OK').show(0);
		}


		if( j.dupF )		// email already exists for another user...
		{
				$e.find('.modal-body').html( '<div style="margin:10px 0;">Sorry, but the entered email address is employed by another account<b>.</b><p>Please enter a different email address or contact <a href="javascript:gMdlHelp();">LeadLeaper</a> for assistance<b>.</b></div>' );

				$e.modal( { show: true } );

				cMdl( $e );
		}

		else if( j.iedF )	// invalidEmailDomain...
		{
				$e.find('.modal-body').html( '<div style="margin:10px 0;">Please first enter a valid email address or contact <a href="javascript:gMdlHelp();">LeadLeaper</a> for assistance</div>' );

				$e.modal( { show: true } );

				cMdl( $e );
		}

		else if( j.gglESP || j.msESP )
		{
			let ESP = 'Google';		if( j.msESP ) { ESP = 'Microsoft'; }

				$e.find('.modal-body').html( '<div style="margin:10px 0;"><b>' + ESP + '</b> is the email service provider for the entered email address<b>.</b><p>Please contact <a href="javascript:gMdlHelp();">LeadLeaper</a> regarding your options<b>.</b> &nbsp;Thanks<b>.</b></div>' );

				$e.modal( { show: true } );

				cMdl( $e );
		}

		else
		{
			oe('onUpdateUserProfileCB', 'j.rC= ' + j.rC);
		}


		cls = 'failed';

		txt = 'Failed!';

		if($b.outerWidth() > 200) { txt = 'Update failed!'; }
	}
	else
	{
		if($b.outerWidth() > 200) { txt = 'Update complete!'; }

		uN  = j.uN;

		ufN = j.ufN;

		ulN = j.ulN;

		uE	= j.uEm;

//		$('#usernameDD').text( uN );

		$('#ePwd, #cePwd').val('');	// clear both...

		rA[1] = j.uN;  rA[2] = j.uTtl;  rA[3] = j.uPh;  rA[4] = j.uEm;		// ["374915", "Greg Henson", "Tester", "222-333-4444", "g@hh.com"]
	}

	$b.addClass(cls).html(txt);

	setTimeout(function() { $b.removeClass(cls).html('Save <i class="fa fa-arrow-circle-right"></i>'); }, 2000);
}




