function uHelpBtn( evt, $m, gbcc )
{
	evtStop( evt );

	$(evt.target).blur();

	if( !gbcc ) { gbcc = ''; }

	var $b = $(evt.target);
//console.log("uHelpBtn:  $b.hasClass('btn-confirm')= " + $b.hasClass('btn-confirm'));

	if( $b.hasClass('btn-confirm') )
	{
		var n, e, q;

		n = $m.find('.modal-body').find('#postFrom').val().trim();

		e = $m.find('.modal-body').find('#postReply').val().trim();

		q = $m.find('.modal-body').find('#postQuest').val().trim();


		if( !n || n.length == 0 ) { $m.find('.modal-body').find('#postFrom').addClass('HL');	return; }

		if( !e || e.indexOf('@') == -1 ) { $m.find('.modal-body').find('#postReply').addClass('HL');	return; }

		if( !q || q.length == 0 ) { $m.find('.modal-body').find('#postQuest').addClass('HL');	return; }

//console.log('uHelpBtn:  n= ' + n + '  e= ' + e + '  q= ' + q);
// return;

		winWait( 'uHelpBtn' );

// ---
	chrome.runtime.sendMessage( ceID, { capStatus:true },  // , uID:uID

			function( resp ) { 
								if( chrome.runtime.lastError ) { }

								let capStatus = {};

								if( !resp )
								{
									rpt('uHelpBtn.sendMessage.capStatus', '!resp');
								}
								else
								{
//console.log('uHelpBtn.sendMessage.capStatus: resp= ' + JSON.stringify(resp));
									capStatus = resp;
								}

								$.post(	'AJAX_Help', { aID:aID, uID:uID, n:n, e:e, q:q, gbcc:gbcc, capStatus:JSON.stringify(capStatus) }, function(j) { uHelpBtn_CB(j, $m, gbcc); }, 'json' ).fail(function(jx, ts, er) { oae('uHelpBtn.AJAX_Help', jx, ts, er); });
		});
// ---
// SAVE		$.post(	'AJAX_Help', { aID:aID, uID:uID, n:n, e:e, q:q, gbcc:gbcc }, function(j) { uHelpBtn_CB(j, $m, gbcc); }, 'json' ).fail(function(jx, ts, er) { oae('uHelpBtn.AJAX_Help', jx, ts, er); });

	}
}


