function pTOS()		// popTermsOfService...
{
	var w = 800, h = 600, t = 0, l = 0;

	if(screen.availWidth < w)
		w = screen.availWidth;
	else
		l = (screen.availWidth - w) / 2;

	if(screen.availHeight < h)
		h = screen.availHeight;
	else
		t = (screen.availHeight - h) / 2;

	window.open('http://' + llName.toLowerCase() + '.com/terms-of-service', '', 'toolbar=no, menubar=no, resizable, width=' + w + ' ,height=' + h + ', top=' + t + ', left=' + l);

   	return false;	// keep to avoid toggling cBox...
}









