function hmDashTippyME( evt )
{
//console.log('hmDashTippyME:  ');

// NO!!!	if( hmDashTippy ) { return; }

	if( glc < 1 && !freeOutF ) { return; }

	var $e = $(evt.target), n = 0;	//  id = evt.target.id;

	while( !$e.hasClass('tippy') && n < 5 )		// boxOC
	{
		n++;

		$e = $e.parent();
	}

	if( n < 5 )
	{
//		id = $e.attr('id');
//console.log('hmDashTippyME:  n= ' + n + '  id= ' + id);

		hmDashTippy = tippy( $e.get(0), {

						content: 'Click to view',

						placement: 'top', 

						followCursor: true,		// 'initial',

						distance: 10,

						delay: [600, 0],		// show, hide

		//				duration: [400, 200],	// show, hide

						hideOnClick: true,

						theme: 'llGrn',

//hideOnClick: false, trigger: 'click', interactive: true,	// <<<<<< FOR DEV ONLY <<<<<<<<<<<<	

		onShow(instance) { hmDashTippyTO = setTimeout(function() { instance.hide(); }, 1400);  },	// 2000

		onHide(instance) { try{ window.clearTimeout( hmDashTippyTO );	hmDashTippyTO = null; }catch(er){ hmDashTippyTO = null; }  },

						onHidden(instance) { instance.destroy(); }
		});

	}	// if( n < 5 )
}



function hmDashOC( evt )
{
//console.log('hmDashOC:  glc= ' + glc + '  freeOutF= ' + freeOutF);

	if( glc < 1 && !freeOutF ) { pricing();		return; }


	var $e = $(evt.target), id, n = 0;	//  = evt.target.id;

	while( !$e.hasClass('boxOC') && n < 5 )
	{
		n++;

		$e = $e.parent();
	}

	if( n < 5 )
	{
		id = $e.attr('id');
	}
//console.log('hmDashOC:  n= ' + n + '  id= ' + id);


	if( id )
	{
		winWait( 'hmDashOC' );

		var chartF, engF=false, opnF=false, lnkF=false, rplyF=false, webF=false, sF=true; 

		switch( id )
		{
			case	'HomeDashEngOC'				:	engF = true;		break;
			case	'HomeDashBannerBoxDlvd'		:	engF = true;		break;

			case	'HomeDashBannerBoxOpns'		:	opnF = true;		break;
			case	'HomeDashOpnsOC'			:	opnF = true;		break;

			case	'HomeDashBannerBoxLnks'		:	lnkF = true;		break;
			case	'HomeDashLnksOC'			:	lnkF = true;		break;

			case	'HomeDashBannerBoxRply'		:	rplyF = true;		break;
			case	'HomeDashRplyOC'			:	rplyF = true;		break;

			case	'hmDashChartOC'				:	chartF = true;		break;

			default								:	sF = false;
		}
//console.log('hmDashOC:  sF= ' + sF + '  freeOutF= ' + freeOutF + '  chartF= ' + chartF + '  engF= ' + engF + '  opnF= ' + opnF + '  lnkF= ' + lnkF + '  rplyF= ' + rplyF + '  webF= ' + webF);

		if( sF )
		{
// ---
			if( glc < 1 && !engF && !opnF && !chartF ) { clearWinWait('hmDashOC');	reqSub( 'hmDashOC' );		return; }

			if( glc < 2 && rplyF ) { clearWinWait('hmDashOC');	reqUpgd();		return; }	// <<<<<<<<<<<<<<<<<<<<<<<<<
// ---


// ---
	$('#HomeDash').fadeOut();
// ---

			$('body').removeClass('hmDash').css('overflow-y', 'hidden');	// <<<<<<<<<<<<		overflow: hidden;


			if( chartF )
			{
				$('#hmDashChart').css('opacity','0');

				$.getJSON( 'AJAX_Dash', { aID:aID, uID:uID, glc:glc, freeOutF:freeOutF, tzOs:tzOs }, dashSBcb ).fail(function(jx, ts, er) { oae('dashSB.AJAX_Dash', jx, ts, er); });
			}

			else if( engF )
				engAdt.ajax.url( 'AJAX_Activity?aID=' + aID + '&uID=' + uID + '&glc=' + glc + '&freeOutF=' + freeOutF + '&opnF=' + opnF + '&lnkF=' + lnkF  + '&rplyF=' + rplyF + '&webF=' + webF + '&engF=' + engF + '&pID=0').load( function( d ) { engAct_CB( d ); } );

			else
				adt.ajax.url( 'AJAX_Activity?aID=' + aID + '&uID=' + uID + '&glc=' + glc + '&freeOutF=' + freeOutF + '&opnF=' + opnF + '&lnkF=' + lnkF  + '&rplyF=' + rplyF + '&webF=' + webF + '&engF=' + engF + '&pID=0').load( function( d ) { act_CB( d, { opnF:opnF, lnkF:lnkF, rplyF:rplyF, webF:webF, engF:engF } ); } );
		}
		else
		{
			clearWinWait('hmDashOC');

			$('#HomeDash').fadeIn();
		}
	}
}






function ctdMsg( evt )
{
//console.log('ctdMsg:  evt.data= ' + evt.data);
//console.log('ctdMsg:  ctdJsn= '   + (ctdJsn ? JSON.stringify(ctdJsn) : ctdJsn) );
	try
	{
		if( evt.data == 'loaded' )
		{
			var feDom = ctdJsn.fE.substring(ctdJsn.fE.indexOf('@') + 1), ctd = ctdJsn.ctd;
//console.log('ctdMsg:  feDom= ' + feDom + '  ctd= ' + ctd);

			var iframe = document.getElementById("ctdIF");

				iframe.contentWindow.postMessage( document.location.hostname + '|' + uID + '|' + feDom + '|' + ctd, "*" );

			setTimeout( clearWinWait, 1000);
		}

		else if( evt.data == 'escape' )
		{
//console.log('ctdMsg: evt.data == escape');

			pmpCls();	// ctdCls();
		}

		else if( evt.data == 'done' )
		{
//console.log('ctdMsg: evt.data == done');
// ---
			SndrAcctsPopCls();	// includes sndrAcctsTbl refresh...
// ---
			pmpCls();	// ctdCls();

//			setTimeout( function() { $('#engMenu').addClass('open'); }, 800);
		}

		else if( evt.data && evt.data.startsWith('update') )
		{
			var ctDom = evt.data.substring(evt.data.indexOf('|')+1);
//console.log('ctdMsg:  update ctDom= ' + ctDom);
// ---
			SndrAcctsPopCls();	// includes sndrAcctsTbl refresh...
// ---

//			$('#opemctdTxt').html('Tracking domain <span id="ctDom" class="hlCTD" style="font-weight:bold;">' + ctDom + '</span> is <span class="hlGrnTxt">enabled</span>');

			$('#opemctdTxt').html('<span style="font-size:16px;">Tracking domain <span id="ctDom" class="hlCTD" style="font-weight:bold;">' + ctDom + '</span> is <span class="hlGrnTxt">enabled</span></span>');
		}
	}
	catch(err)
	{
//console.log('ctdMsg:  err= ' + err.message);
		oe('ctdMsg', err, true);
	}
}



