function medt_ping( cntr, mgrID )	
{
	if( !cntr ) { cntr = 0; }

	cntr++;
//console.log('medt_ping:  cntr= ' + cntr + '  mgrID= ' + mgrID);

	if( cntr > 30 )		// 80 Increase for production!!!!	<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<
	{
//console.log('medt_ping:  cntr= ' + cntr + ' EXIT');
		clearWinWait('medt_ping');

		oe('medt_ping', 'cntr= ' + cntr + 'mgrID= ' + mgrID + ' EXIT', true);	// silentFlag...

		return;
	}


	$.getJSON('ProcResults', { mgrID:mgrID, code:'MR' }, 

				function( jsn )
				{
//console.log('medt_ping:  jsn= ' + (jsn ? JSON.stringify(jsn) : jsn));

					if( !jsn || !jsn.rC )
					{
//console.log('medt_ping.ProcResults:  !jsn || !jsn.rC || jsn.rC < 0 EXIT');

						clearWinWait('medt_ping');

						oe('medt_ping.ProcResults', 'jsn= ' + (jsn ? JSON.stringify(jsn) : jsn), true);		// silentFlag...

						return;
					}

//console.log('medt_ping:  jsn.rC= '    + jsn.rC + '  jsn.mgrID= ' + jsn.mgrID + '  jsn.pingF= ' + jsn.pingF);
//console.log('medt_ping:  jsn.data= '  + jsn.data);

					if( jsn.rC == 2 )	// we're done, so display any results...
					{
						medt.clear();
						medt.rows.add( jsn.data );	// a json array...

						medt.order( [ 1, 'asc' ] ).draw();	// 'desc'

						$memp.show();

						clearWinWait('medt_ping');

						return;
					}

					if( jsn.pingF && jsn.mgrID )
					{
						medt_pingRetry( cntr, jsn.mgrID );
					}

					else
					{
						clearWinWait('medt_ping');

						oe('medt_ping.ProcResults', 'else  jsn= ' + (jsn ? JSON.stringify(jsn) : jsn), true);	// silentFlag...

						return;
					}
				}
	)
	.fail(function(jx, ts, er) { oae('medt_ping.ProcResults', jx, ts, er); });
}


function medt_pingRetry( cntr, mgrID )
{
//console.log('medt_pingRetry:  cntr= ' + cntr + '  mgrID= ' + mgrID);
	setTimeout( function() { medt_ping( cntr, mgrID ) }, 3000);	// <<<<<<<<<<<<<<<<<<<<<<<<<<<
}



