function mgmtUIa( dc, subF )	// Subscription(UI)Flag...
{
//console.log('mgmtUIa:  dc= ' + dc + '  graF= ' + graF + '  subF= ' + subF);

	if( !subF ) { subF = false; }

	var $m, ttl;

	switch( dc )			
	{
		case '1'	:		$m = $('#meuModal');	ttl = 'Add to Team';

								if( subF ) { ttl = 'Add a User'; }

// ---
							$m.find('form').find('#meEmailDom').val( uE.substring( uE.indexOf('@') ) );
// ---

							$m.find('.form-group-opt').hide(0).end().find('.form-group-cBx > input').prop('checked', false);

							$m.find('form').find('#merEIcb').parent().hide(0);

							$m.find('form').find('#meuSubBtn').html('Add <i class=\"fa fa-arrow-circle-right\"></i>').off('click').on('click', function(evt) { $('#meuModal form').find('.has-error').removeClass('has-error').find('span.help-block').remove();	meAddUpdateUserProfile('BBB', evt, null, subF); } );

							$m.find('.modal-header').show(0).find('.modal-title').text( ttl );

							$m.modal( { width: 600, keyboard: true, backdrop: 'static', show: true } ).on( 'hidden.bs.modal', function() { });

							cMdl( $m );

							break;


		case '2'	:		$m = $('#merModal');	ttl = 'Add a Reseller';

							if( affaF ) { ttl = 'Add a Client'; } else if( graF ) { ttl = 'Add a Managed Trial'; }

							$m.find('form input').removeAttr('disabled').removeAttr('readonly');	// canNOT emply .removeProp since it ONLY removes attribs set with .prop!!!

							$m.find('form').find('#mruLic').parent().hide(0);

							if( graF ) { $m.find('.form-group-cBx > input').prop('checked', false);		$m.find('#mrExpF').parent().hide(0);	$m.find('#mrIP').parent().hide(0);	}

// ---
							$m.find('form').find('textarea').val('').removeClass('onfocus hl').off('focus').on('focus', function() { $m.find('.merEI').addClass('onfocus'); }).off('blur').on('blur', function() { $m.find('.merEI').removeClass('onfocus'); });

	$m.find('.meurEIb').val( '\r\n' + ufN + ',\r\n' );	// KEEP!!!

	autosize.update( $m.find('.meurEIa') );
	autosize.update( $m.find('.meurEIb') );


	$m.find('.meurName').off('blur').on('blur', function() {
//console.log('mgmtUIa:  mETo= ' + JSON.stringify(mETo));
//console.log("mgmtUIa:  $m.find('.meurEIa').val()= " + $m.find('.meurEIa').val());
//console.log("mgmtUIa:  $m.find('.meurEIa').val().trim().length= " + $m.find('.meurEIa').val().trim().length);

															if( $m.find('.meurEIa').val().trim().length == 0 )
															{
																var eS = '', EIa = '', EIb = '\r\n' + ufN + ',\r\n', o;

																switch( dc )
																{
																	case '1'	:	o = mETo.meu;	break;

																	case '2'	:	if( graF ) { o = mETo.meu; } else { o = mETo.mer; }	break;
																}
//console.log('mgmtUIa:  o= ' + JSON.stringify(o));
																if( o )
																{
																	if( o.eS  ) { eS = o.eS;   }
																	if( o.EIa ) { EIa = o.EIa; }
																	if( o.EIb ) { EIb = o.EIb + EIb; }
																}
//console.log('mgmtUIa:  eS= ' + eS + '  EIa= ' + EIa + '  EIb= ' + EIb);


																var v = $(this).val().trim(), a = v.split(/\s+/g), n;
//console.log('mgmtUIa:  v= ' + v + '   a.length= ' +  a.length);
																if( a.length > 1 )
																{
																	n = a[0];																
//console.log('mgmtUIa:  n= ' + n);
																	if( n && n.trim().length > 0 )
																	{
																		EIa = n.trim() + ',\r\n\r\n' + EIa + '\r\n';
																	}
																}


																$m.find('.meurEIa').val( EIa );

																	autosize.update( $m.find('.meurEIa') );

																$m.find('.meurEIb').val( EIb );		// KEEP!!!

																	autosize.update( $m.find('.meurEIb') );

															}	// if

												 	});	// on blur...


								winWait( 'mgmtUIa' );

								try { $.getJSON( sigURL + '?n=' + Date.now(), function( j ) { meurSigUrlCB(j, $m); }).fail( function(jx, ts, er) { meurSigUrlCB(null, $m); });  } catch(er){ meurSigUrlCB(null, $m); }

	if( !mETo )	// NOT
	{
		$.getJSON( 'AJAX_mETo', { aID:aID, uID:uID }, mEToCB ).fail(function(jx, ts, er) { oae('mgmtUIa.AJAX_mETo', jx, ts, er); });
	}
// ---

							$m.find('form').find('#merSubBtn').html('<span>Add</span> <i class=\"fa fa-arrow-circle-right\"></i>').off('click').on('click', function(evt) { $('#merModal form').find('.has-error').removeClass('has-error').find('span.help-block').remove();		meAddUpdateReseller(evt, null); } );

							$m.find('form').find('#merEIcb').prop('checked', false).off('click').on('click', function(evt) { merEIcBox( $(this), $m  );  } ).parent().show(0);

							break;
	}	// switch



	if( !$m ) { return; }


	$m.find('form').find('.has-error').removeClass('has-error').find('span.help-block').remove();

	$m.find('input.login-cntrl').removeAttr('readonly').removeClass('ulF').parent().show(0);

	$m.find('form').find('input.clrInput').val('');

	$m.find('.modal-header').show(0).find('.modal-title').text( ttl );

	$m.find('.modal-body').removeClass('merAdd').find('.merEIfg').hide(0);
}




function merEIcBox( $t, $m )
{
//console.log('merEIcBox:  ');

	if( $t.is(':checked') )
	{
		var mt = parseInt($m.css('margin-top'), 10);
//console.log('merEIcBox:  mt= ' + mt );

			mt = mt - ( $m.offset().top - $('body').scrollTop() - 20 );
//console.log('merEIcBox:  mt= ' + mt );
												
		$m.animate( { 'margin-top': mt+'px' }, 400, 

					function() {
								var tos = $m.offset().top;

								if( tos < 0 ) { $m.animate( { 'margin-top': ( mt - tos + 20 ) + 'px' }, 400 ); }
	
								$m.find('.modal-body').addClass('merAdd').find('.merEIfg').slideDown( 400, function() { autosize.update( $m.find('.meurEIa') );		autosize.update( $m.find('.meurEIb') );		$m.find('form').find('#merSubBtn > span').text('Add & Send Email');	} );
						 });
	}
	else
	{
		$m.find('.modal-body').removeClass('merAdd').find('.merEIfg').slideUp( 400, function() { $m.find('form').find('#merSubBtn > span').text('Add'); } );
	}
}





function mEToCB( j )
{
//console.log('mEToCB:  j= ' + JSON.stringify(j));

	if( j && j.mETo )
	{
		j.mETo = j.mETo.replace(/&#34;/g, '\\"');
		j.mETo = j.mETo.replace(/&#39;/g, "'");

		mETo = JSON.parse( j.mETo );
	}
}




