function hmCreditsCB( j )
{
//console.log('hmCreditsCB:  j= ' + JSON.stringify(j));
//console.log('hmCreditsCB:  j.rC= ' + j.rC + '  j.edc= ' + j.edc);

	if( j.rC != 1 )
	{
		oe('hmCreditsCB', 'j.rC= ' + j.rC);
		return;
	}


	if( j.edc < 0 ) { j.edc = 0; }

	$('#hmDashCredits').html( 

		(j.edc && j.edc > 0 ? '<span' + (glc < 1 ? ' class="free"' : '') + '>' + numberWithCommas(j.edc) + ' credits' + 

									(glc > 0 ? '<span class="actAtBR purchase">purchase</span>' : '<span class="actAtBR purchase">Upgrade</span>') + '</span>' 

							: '<span class="NOedc">No credits' + (glc > 0 ? '<span class="actAtBR purchase">purchase</span>' : '<span class="actAtBR purchase">Upgrade</span>') 

			+ '</span>') );

	$('#hmDashCredits').find('.purchase').off('click').on('click', hmCreditsOC);
}


function hmCreditsOC( evt )
{
//console.log('hmCreditsOC:  ');

	var $e = $(evt.target);

	if( glc < 1 )
	{
		pricing();
	}
	else
	{
		$('#uSub').trigger('click');

		setTimeout(function() { $('#subPDC').find('.pbdcBtnGrp > button').trigger('click'); }, 1000);
	}
}





// ------------------------------
function hmGrphCB( j )
{
//console.log('hmGrphCB:  j= ' + JSON.stringify(j));
//console.log('hmGrphCB:  j.misc.hmDashOnlyF= ' + (j.misc ? j.misc.hmDashOnlyF : j.misc));	// + '  j.disc= ' + j.disc + '  j.delivered= ' + j.delivered + '  j.opened= ' + j.opened + '  j.clicked= ' + j.clicked + '  j.replied= ' + j.replied);
//console.log("hmGrphCB:  $('#hmDashLastDelivered').find('> span.gears').length= " + $('#hmDashLastDelivered').find('> span.gears').length);


	try { $tipPO.popover('destroy'); } catch(er) {}

	if( j.rC != 1 )
	{
		oe('hmGrphCB', 'j.rC= ' + j.rC);

		return;
	}


	try
	{
// ---
//		if( !glc || ( !j.misc.hmDashOnlyF && !j.delivered && $('#hmDashLastDelivered').html().length ) )
		if( !glc || ( ( !j.misc || !j.misc.hmDashOnlyF ) && !j.delivered && $('#hmDashLastDelivered').find('> span.gears').length == 0 && $('#hmDashLastDelivered').html().length ) )	// hmDashLastDelivered
		{
			$('#hmDashLastDelivered').html('')
		}


		var dt, fdt, cCnt = 0;

		if( glc && j && j.misc && j.misc.lstOpnTS && j.misc.opened )
		{
			dt = new Date( j.misc.lstOpnTS - zero );

			fdt = Intl.DateTimeFormat( 'en-US', { weekday: 'short', month: 'short', day: 'numeric' } ).format( dt ) + '<span class="actAtBR"></span>' + Intl.DateTimeFormat( 'en-US', { hour: 'numeric', minute: 'numeric', second: 'numeric' } ).format( dt );

// ---
			try { cCnt = parseInt( $('#hmDashOpened').text().replaceAll(',', ''), 10 ); } catch(er) { cCnt = -1;	console.log('hmGrphCB.opened.cCnt:  er= ' + er); }

				if( cCnt && cCnt > 0 && j.opened > cCnt ) { $('#hmDashOpened').text( numberWithCommas( j.opened ) ); }
// ---
		}

//console.log('hmGrphCB:  j.misc.opened= ' + j.misc.opened + '  j.misc.lstOpnTS= ' + (j.misc ? j.misc.lstOpnTS : j.misc) + '  fdt= ' + fdt);

		$('#hmDashLastOpened').html( (fdt ? '<span class="lbl">' + fdt + '</span>' : '') );


		fdt  = null;
		cCnt = 0;

		if( glc && j && j.misc && j.misc.lstLnkTS && j.misc.clicked )
		{
			dt = new Date( j.misc.lstLnkTS - zero );

			fdt = Intl.DateTimeFormat( 'en-US', { weekday: 'short', month: 'short', day: 'numeric' } ).format( dt ) + '<span class="actAtBR"></span>' + Intl.DateTimeFormat( 'en-US', { hour: 'numeric', minute: 'numeric', second: 'numeric' } ).format( dt );

// ---
			try { cCnt = parseInt( $('#hmDashClicked').text().replaceAll(',', ''), 10 ); } catch(er) { cCnt = -1;		console.log('hmGrphCB.clicked.cCnt:  er= ' + er); }

				if( cCnt && cCnt > 0 && j.clicked > cCnt ) { $('#hmDashClicked').text( numberWithCommas( j.clicked ) ); }
// ---
		}

//console.log('hmGrphCB:  j.misc.clicked= ' + j.misc.clicked + '  j.misc.lstLnkTS= ' + (j.misc ? j.misc.lstLnkTS : j.misc) + '  fdt= ' + fdt);

		$('#hmDashLastClicked').html( (fdt ? '<span class="lbl">' + fdt + '</span>' : '') );


		fdt  = null;
		cCnt = 0;

//console.log('hmGrphCB:  typeof j.replied == "string" --> ' + typeof j.replied == "string");
//console.log('hmGrphCB:  typeof j.replied == "number" --> ' + typeof j.replied == "number");

		if( glc > 1 && j && j.misc && j.misc.replied && j.misc.lstRplyTS && j.misc.replied > 0 )
		{
//console.log('hmGrphCB:  j.replied= ' + j.replied);

			dt = new Date( j.misc.lstRplyTS - zero );

			fdt = Intl.DateTimeFormat( 'en-US', { weekday: 'short', month: 'short', day: 'numeric' } ).format( dt ) + '<span class="actAtBR"></span>' + Intl.DateTimeFormat( 'en-US', { hour: 'numeric', minute: 'numeric', second: 'numeric' } ).format( dt );

// ---
			try { cCnt = parseInt( $('#hmDashRepied').text().replaceAll(',', ''), 10 ); } catch(er) { cCnt = -1;		console.log('hmGrphCB.replied.cCnt:  er= ' + er); }

				if( cCnt && cCnt > 0 && j.replied > cCnt ) { $('#hmDashRepied').text( numberWithCommas( j.replied ) ); }
// ---
		}

//console.log('hmGrphCB:  j.misc.replied= ' + j.misc.replied + '  j.misc.lstRplyTS= ' + (j.misc ? j.misc.lstRplyTS : j.misc) + '  fdt= ' + fdt);

		$('#hmDashLastRepied').html( (fdt ? '<span class="lbl">' + fdt + '</span>' : '') );
// ---


// see finally...		hmLoadCntr++;


		if( !j.misc.hmDashOnlyF )	// NOT hmDashOnlyF...
		{
			var hmDashChartOpen, hmDashChartEm;

// ----
			var $e = $('#HomeDashEngChart');	// <<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<
// ----

			var n = 2;	// if( j.discF ) { n = 1; }

			var dht = ( $('#HomeDashEngChart').height() - 10 ) / n;
//console.log('hmGrphCB:  n= ' + n + '   dht= ' + dht);

			$e.find('div.chart').css( 'height', dht + 'px');

			$e.find('.charts .chartOut').show(0);


			$('#hmDashDisc').text( numberWithCommas(j.disc) );

			if( glc || freeOutF ) { $('#hmDashDelivered').text( numberWithCommas( j.delivered ) ); } else { $('#hmDashDelivered').html( '<span class="upgrade">Upgrade</span>' ); }

			if( glc || freeOutF ) { $('#hmDashOpened').text( numberWithCommas( j.opened ) ); } else { $('#hmDashOpened').html( '<span class="upgrade">Upgrade</span>' ); }

			if( glc ) { $('#hmDashClicked').text( numberWithCommas( j.clicked ) ); } else { $('#hmDashClicked').html( '<span class="upgrade">Upgrade</span>' ); }
// ---
			if( glc > 1 ) { $('#hmDashRepied').text( numberWithCommas( j.replied ) ); } else { $('#hmDashRepied').html( '<span class="upgrade">Upgrade</span>' ); }
// ---



	$e.show();	// MUST show BEFORE plotting...		<<<<<<<<<<<<<<<<<<<<


			hmDashChartOpen = $.plot($('#hmDashChartOpen'), 

										[
											{ data: j.OPEN,  label: '<span style="color:#1e90ff;"><span class="chrtHideTxt">Email </span>Opens</span>' },	// Email Opens
											{ data: j.CLICK, label: '<span style="color:#0000ff;">Links<span class="chrtHideTxt"> Viewed</span></span>'},	// Links Viewed
											{ data: j.REPLY, label: '<span style="color:#1cb048;">Replies</span>' }											// Email Replies
										],
	
										{
											series: {
														lines:  { show: true },
														points: { show: true }
													},
	
											colors: [ '#1e90ff', '#0000ff', '#1cb048' ],
	
											legend: {
														margin: [0, 0]	// 20, 15
													},
	
											xaxis: 	{
														ticks: j.Xaxis
													},
	
											yaxis: 	{
														min: 0,
														minTickSize: 1,
														tickDecimals: 0
													},
	
											grid: 	{
														color: '#AAA',
														labelMargin: 10,
														hoverable: true,
														clickable: true,
														autoHighlight: false
													}
										}
								);



			hmDashChartEm = $.plot($('#hmDashChartEm'), 

									[
										{ data: j.SENT, label: '<span style="color:#00ff00;"><span class="chrtHideTxt">Emails </span>Sent</span>' },	// Emails Sent
//										{ data: j.DLVD, label: '<span style="color:#8a2be2;">Delivered<span class="chrtFtr"> **</span></span>' }										// Emails Delivered
										{ data: j.DLVD, label: '<span style="color:#8a2be2;">Delivered' + (freeOutF ? '<span class="chrtFtr"> **</span>' : '') + '</span>' }										// Emails Delivered
									],

									{

									colors: ['#00ff00', '#8a2be2'],

										series: {
													lines:  { show: true },
													points: { show: true }
												},

										legend: {
													margin: [0, 0]	// 20, 15
												},

										xaxis: 	{
													ticks: j.Xaxis
												},

										yaxis: 	{
													min: 0,
													minTickSize: 1,
													tickDecimals: 0
												},

										grid: 	{
													color: '#AAA',
													labelMargin: 10,
													hoverable: true,
													clickable: true,
													autoHighlight: false
												}
									}
								);


			var emLOlbl = hmDashChartEm.getAxes().yaxis.ticks[hmDashChartEm.getAxes().yaxis.ticks.length - 1].label, 
				opLOlbl = hmDashChartOpen.getAxes().yaxis.ticks[hmDashChartOpen.getAxes().yaxis.ticks.length - 1].label;
//console.log('hmGrphCB:  emLOlbl= ' + emLOlbl + '  opLOlbl= ' + opLOlbl);
//console.log('hmGrphCB:  emLOlbl.length= ' + emLOlbl.length + '  opLOlbl.length= ' + opLOlbl.length);

			if( emLOlbl.length > opLOlbl.length ) { $e.find('.col-md-12B').addClass('shiftL'); } else { $e.find('.col-md-12B').removeClass('shiftL'); }


			$e.find(".charts #hmDashChartOpen").bind(	"plothover",

												function(event, pos, item)
												{
													hmDashChartOpen.unhighlight();

													if( item && item.series && item.series.label && item.datapoint )
													{
														hmDashChartOpen.highlight( item.series, item.datapoint );

														$("#chartTT").html(item.datapoint[1].toFixed(0) + ' ' + item.series.label.toLowerCase()).css( { top: item.pageY-35, left: item.pageX-15 } ).fadeIn(200);
													}
													else
													{
														$("#chartTT").hide();
													}
												});


			$e.find(".charts #hmDashChartEm").bind(	"plothover",

												function(event, pos, item)
												{
													hmDashChartEm.unhighlight();

//													if( item && item.series && item.series.label && item.datapoint )
													if( !freeOutF && item && item.series && item.series.label && item.datapoint )
													{
														hmDashChartEm.highlight( item.series, item.datapoint );

														$("#chartTT").html(item.datapoint[1].toFixed(0) + ' ' + item.series.label.toLowerCase() ).css( { top: item.pageY-35, left: item.pageX-15 } ).fadeIn(200);
													}
													else
													{
														$("#chartTT").hide();
													}
												});

		}	// if NOT j.hmDashOnlyF

	}
	catch(err)
	{
//console.log('hmGrphCB:  err= ' + err.message);
		clearWinWait('hmGrphCB');

		$('#hmDashChart').css('opacity','1');
	}
	finally
	{
		setTimeout(function() { 
								hmLoadCntr++;

								$('#hmDashChart').css('opacity','1');

								if( hmLoadCntr > 3 ) { clearWinWait('hmGrphCB');		try{ window.clearTimeout(hmLoadTOid);	hmLoadTOid = null; }catch(er){ hmLoadTOid = null; } }
					}, 300);
	}

}	// hmGrphCB
