function aeImgBtnCB( j, elF )
{
//console.log('aeImgBtnCB:   elF= '  + elF);
//console.log('aeImgBtnCB:   j= '  + JSON.stringify(j));

	if(j.rC != 1)
	{
		oe( 'aeImgBtnCB', 'j.rC= ' + j.rC);  

		return; 
	}


	if( j.aF && !elF && j.cID != lanCID ) 
	{
		panelRefresh( 'aeImgBtnCB.AAA', null, null, 'Images', false, false );	// panelRefresh( cBy, evt, e, id, brf, savF )
	}
	else if( !elF )
	{
 		panelRefresh( 'aeImgBtnCB.BBB', null, null, 'Images', false, false );	// panelRefresh( cBy, evt, e, id, brf, savF )
	}
	else
	{
		clearWinWait('aeImgBtnCB');
	}


	$aeImgMdl.find('.modal-header button').click();

	var m;

	if( j.aF ) { m = 'Addition complete';		imgsCnt++;		imgLibObj = null; }

	else if ( !j.dF ) { m = 'Save complete'; }

	if( m ) { setTimeout(function() { pmp( m, { clsTO:2000 } ); }, 600); }

}	// aeImgBtnCB

