function aedpCB(resp, newVal)
{
//console.log('aedpCB:   resp=' + resp + '  newVal= ' + newVal + '  roleCode= ' + rc);
//return;

	var j = JSON.parse(resp);

	if( j.rC != 1 )
	{
		oe('aedpCB', 'j.rC= ' + j.rC);

		return;
	}

	if( j.nf )			// new flag
	{
		adcF = true;

		outpID = j.pID;

		$.getJSON( 'AJAX_MenuBar', { aID:aID, uID:uID, glc:glc, rc:rc, graF:graF }, aedpCBrefNB ).fail(function(jx, ts, er) { oae('aedpCB.AJAX_MenuBar', jx, ts, er); });
	}

	else if ( j.delf )	// delete
	{
		adcF = true;

		outpID = $('#outDrop li:eq(0) > a').attr('id').substring(5);	// outSB26951
//console.log('aedpCB:   outpID= ' + outpID);

		$.getJSON( 'AJAX_MenuBar', { aID:aID, uID:uID, glc:glc, rc:rc, graF:graF }, function(jsn) { jsn.delF=true;	aedpCBrefNB(jsn); } ).fail(function(jx, ts, er) { oae('aedpCB.AJAX_MenuBar', jx, ts, er); });
	}

	else if ( j.reactf )	// reactivate
	{
		$.getJSON( 'AJAX_MenuBar', { aID:aID, uID:uID, glc:glc, rc:rc, graF:graF }, aedpCBrefNB ).fail(function(jx, ts, er) { oae('aedpCB.AJAX_MenuBar', jx, ts, er); });
	}

	else	// must be an edit
	{
//???		$('#outProspects_wrapper').find('#pg-hdr > h1 > span.prjTtl').text();

		$.getJSON( 'AJAX_MenuBar', { aID:aID, uID:uID, glc:glc, rc:rc, graF:graF }, aedpCBrefNB ).fail(function(jx, ts, er) { oae('aedpCB.AJAX_MenuBar', jx, ts, er); });
	}
}



