function ldStats( evt, tde )
{
//console.log('ldStats:  ');
	try
	{
		evtStop(evt);

		let $e = $(evt.target);

		let rd = opdt.row( tde ).data(), g = rd.gData;
//console.log('ldStats:  rd= ' + JSON.stringify(rd) );
//console.log('ldStats:  g.opensCntr= ' + g.opensCntr + '  g.linksCntr= ' + g.linksCntr + '  g.repliesCntr= ' + g.repliesCntr + '  g.ldScore= ' + g.ldScore );

		let h =	'<div style="overflow:visible; padding:2px 4px; font-size:14px;"><table><tbody>';	// <b>:</b>

			h += '<tr><td style="text-align:right;  padding:5px;">Email Opens</td><td   style="padding:5px;">' + (g.opensCntr > 2 ? (g.opensCntr + '+') : g.opensCntr) + '</td></tr>';

			h += '<tr><td style="text-align:right;  padding:5px;">Link Views</td><td    style="padding:5px;">' + (g.linksCntr > 2 ? (g.linksCntr + '+') : g.linksCntr) + '</td></tr>';

			h += '<tr><td style="text-align:right;  padding:5px;">Email Replies</td><td style="padding:5px;">' + g.repliesCntr + '</td></tr>';

			h += '</tbody></table>';


		tippy( $e.get(0), {
							content: h,

							placement: 'top', 

							container: 'body',

//							theme: 'llGrn',

//hideOnClick: false, trigger: 'click', interactive: true,	// <<<<<< FOR DEV ONLY <<<<<<<<<<<<

							onHidden(instance) { instance.destroy(); }
		});
	}
	catch(err)
	{
//console.log('ldStats:  err= ' + err.message);
	}
}
