function pmpIframe( src, o )
{
	if( !o ) { o = {}; }
//console.log('pmpIframe:  starting o= ' + (o ? JSON.stringify(o) : o) );

	if( !o.mainClass ) { o.mainClass = 'my-mfp-zoom-in'; }

	if( !o.shwClsBtn ) { o.shwClsBtn = false; }
	if( !o.clsBgClk  ) { o.clsBgClk  = false; }

	if( !o.onOpnFn ) { o.onOpnFn = ''; }
	if( !o.onClsFn ) { o.onClsFn = ''; }

//console.log('pmpIframe:  ending o= ' + (o ? JSON.stringify(o) : o) );


	setTimeout( function() {

	// HTML markup of popup, `mfp-close` will be replaced by the close button
	var h 	= '<div class="mfp-iframe-scaler"><div class="mfp-close"></div>'
			+ '<iframe src="' + src + '" ' + (o.ifrmID ? 'id="' + o.ifrmID + '"' : "") + ' class="mfp-iframe" frameborder="0"></iframe>'		//  allowfullscreen
			+ '</div>';

	$.magnificPopup.open({
							items: {
								    src: h, 	// can be a HTML string, jQuery object, or CSS selector
								    type: 'inline'
							  	},

							fixedContentPos: false,
							fixedBgPos: true,
							preloader: false,

//							midClick: true,
// default					closeBtnInside: true,
// default					enableEscapeKey: true,
// default					closeOnBgClick: true,
// default					overflowY: 'auto',

							showCloseBtn: 	o.shwClsBtn,
							closeOnBgClick: o.clsBgClk,

							removalDelay: 300,
							mainClass: 	o.mainClass,	// 'ctd-pop'	// 'my-mfp-zoom-in',

							callbacks: {
										open:  function() { return o.onOpnFn; }, 	// this = Popup instance --> this.close()		$(this.contentContainer) --> jQry access to popup content h
										close: function() { return o.onClsFn; }
								}
					});
									}, 400);
}
