function medtOC( evt, tde )
{
//console.log( 'medtOC:  rc= ' + rc );

	if( rc != 2 )	// global rc --> manager RoleCode which should always be 2!!!
		return;

	var $e = $(evt.target);
// ---
	if( $e.find('> i.fa').length > 0 ) { return; }
// ---

	var rd = medt.row( tde ).data(), tmRC = rd.gData.rc;	// TeamMemberRoleCode; not to be confused with global rc --> manager RoleCode which should always be 2!!!
//console.log( 'medtOC:  rd= ' + JSON.stringify(rd) );
//console.log( 'medtOC:  tmRC= ' + tmRC );
//console.log( 'medtOC:  rc= ' + rc + '  gamF= ' + gamF + '  mgrF= ' + mgrF + '  amID= ' + amID + '  rd.gData.ID= ' + rd.gData.ID );

	winWait( 'medtOC' );

	if( gamF || mgrF )	// mgrF	<-- should ALWAYS be a mgr!!!!!	(rc = 2 )
	{
		MgrUsrLogin( rd.gData.ID );
	}
	else
	{
		medt.ajax.url( 'AJAX_MgmtRptg?aID=' + aID + '&uID=' + uID + '&smID=' + rd.gData.ID + '&graF=' + graF + '&affmF=' + affmF + '&affaID=' + affaID + '&affuID=' + affuID + '&dc=1' ).load( medt_CB );
	}
}






function MgrUsrLogin( tmID )	// teamMemberID...		// MgrLogin(as)User...
{
//console.log('MgrUsrLogin: tmID= ' + tmID);
	try
	{
		$.ajax({
				type: "GET",		// type: "POST",	// <-- switch to a "GET" due to chrome FU...

				url: "watoken",

				dataType: "json",

				data: { 'aID':aID, 'uID':tmID, 'mgrID':uID, 'gbcc':'hd' }		// MgrLogin(as)UserFlag		'gbcc':'ed'
			})

			.done( function(jsn, ts, jx) { 
											clearWinWait('MgrUsrLogin');

											if( typeof jsn == 'string' ) { jsn = JSON.parse(jsn); }

											var tkn = jsn.tkn;
//console.log('MgrUsrLogin.watoken: tkn= ' + tkn);
											if( !tkn || tkn.length < 10 )
											{
												oe('MgrUsrLogin.watoken', '!tkn || tkn.length < 10', false);	// silentFlag...
											}
// ---
											var u = GravURL + 'leadsmgr?dF=true&tkn=' + encodeURIComponent(jsn.tkn) + '&eID=' + encodeURIComponent(ceID);
// ---
											var win = window.open(u, '_blank');

												win.focus();
			})	// done

			.fail( function(jx, ts, er) { 
											clearWinWait('MgrUsrLogin');

											oe('MgrUsrLogin.watoken.fail', er, false);	// silentFlag...
			});
	}
	catch(er)
	{
		clearWinWait('MgrUsrLogin');

		oe('MgrUsrLogin.watoken.catch', er, false);	// silentFlag...
//console.log('MgrUsrLogin:  er= ' + er);
	}
}







