	if( $('#meMgr').is(':checked') ) { meMgrCbox= 1; }


//	var d = 'meName=' + meN + '&meEmail=' + meE + $('#meEmailDom').val() + '&meMgr=' + meMgrCbox + '&meuF=true&aID=' + aID + '&uID=' + uID + '&meuID=' + meuID + '&rc=' + rc + '&uN=' + uN + '&ufN=' + ufN + '&uE=' + rA[4] + '&subF=' + subF + '&affmF=' + affmF + '&affaID=' + affaID + '&affuID=' + affuID; 
	var d = 'meName=' + meN + '&meEmail=' + meE + '&meMgr=' + meMgrCbox + '&meuF=true&aID=' + aID + '&uID=' + uID + '&meuID=' + meuID + '&rc=' + rc + '&uN=' + uN + '&ufN=' + ufN + '&uE=' + rA[4] + '&subF=' + subF + '&affmF=' + affmF + '&affaID=' + affaID + '&affuID=' + affuID; 
