function meAddEmContent( $f )
{
	var eSub = $f.find('.meurEISub').val(), EIaTxt = $f.find('.meurEIa').val(), EIbTxt = $f.find('.meurEIb').val(), EIuHtm = $f.find('.merAddLLurl').html(), eSigHtm = $f.find('.eSig').html(), EIaHtm='', EIbHtm='', EIuTxt='';

/* SAVE
		eSub = eSub.replace(/\'/g, "&#39;");
		eSub = eSub.replace(/\"/g, '&#34;');
//		eSub = encodeURIComponent( eSub );

		EIaTxt = EIaTxt.replace(/\'/g, "&#39;");
		EIaTxt = EIaTxt.replace(/\"/g, '&#34;');
//		EIaTxt = encodeURIComponent( EIaTxt );

		EIbTxt = EIbTxt.replace(/\'/g, "&#39;");
		EIbTxt = EIbTxt.replace(/\"/g, '&#34;');
//		EIbTxt = encodeURIComponent( EIbTxt );
*/
		EIuHtm = EIuHtm.replace(/<b>/g, "");
		EIuHtm = EIuHtm.replace(/<\/b>/g, "");

		EIuHtm = EIuHtm.replace(/target="_blank"/g, "");		

//console.log('meAddEmContent:  eSub= ' + eSub);
//console.log('meAddEmContent:  EIaTxt= ' + EIaTxt);
//console.log('meAddEmContent:  EIbTxt= ' + EIbTxt);
//console.log('meAddEmContent:  EIuHtm= ' + EIuHtm);


	var lines = EIaTxt.split(/\r\n|\r|\n/),
		len = lines.length;

		for(let i=0; i<len; i++)
		{
			EIaHtm += lines[i] + '<br>';	// line = lines[i];
		}
//console.log('meAddEmContent:  EIaHtm= ' + EIaHtm);


	lines = EIbTxt.split(/\r\n|\r|\n/); // reset
	len = lines.length;	// reset

		for(let i=0; i<len; i++)
		{
			EIbHtm += lines[i] + '<br>';
		}
//console.log('meAddEmContent:  EIbHtm= ' + EIbHtm);


// ---
	$tDiv.html( EIuHtm );
//console.log('meAddEmContent:  staring $tDiv= ' + $tDiv.html());

// ---
	$tDiv.find('img').remove();
	$tDiv.find('p').each( function(idx, e) { $(this).removeAttr('style'); });
// ---

	var ebTemp = $tDiv.html();
//console.log('meAddEmContent:  starting ebTemp= ' + ebTemp);

		ebTemp = ebTemp.split('<br>').join('\r\n');		// MUST come first!!

		ebTemp = ebTemp.split('<b>').join('');
		ebTemp = ebTemp.split('<u>').join('');
		ebTemp = ebTemp.split('<i>').join('');

		ebTemp = ebTemp.split('</b>').join('');
		ebTemp = ebTemp.split('</u>').join('');
		ebTemp = ebTemp.split('</i>').join('');

		ebTemp = ebTemp.split('</a>').join('');
		ebTemp = ebTemp.split('">').join(' ');	// KEEP space...

		ebTemp = ebTemp.split('<a href="').join('');

		ebTemp = ebTemp.trim();
// ---
		ebTemp = ebTemp.replace(/\"/g, '');		// failsafe removal of any remaining double quotes...
// ---
//console.log('meAddEmContent:  ending ebTemp= ' + ebTemp);

		$tDiv.html('');	// clear...

		$tDiv.html( ebTemp );

		EIuTxt = $tDiv.text();
//console.log('meAddEmContent:  EIuTxt= ' + EIuTxt);
// ---



	eSigProc( 'meAddEmContent', eSigHtm );	// generates/updates global sigObj including eso...


	var emHtm = EIaHtm + EIuHtm + '<br>' + EIbHtm + sigObj.eso.eSigHtm;
//console.log('meAddEmContent: emHtm= ' + emHtm);

	var emTxt = EIaTxt + '\r\n' + EIuTxt + '\r\n' + EIbTxt + '\r\n' + sigObj.eso.eSigTxt;
//console.log('meAddEmContent: emTxt= ' + emTxt);


//	return { eSub:eSub, EIa:encodeURIComponent( EIa ), EIu:encodeURIComponent( EIu ), EIb:encodeURIComponent( EIb ) };
	return { eSub:eSub, emHtm:emHtm, emTxt:emTxt };
}





function meAddUpdateUserProfileCB( j, tde, subF )	// if tde undefined, then adding (not editing) a user...			Subscription(UI)Flag...
{
//console.log('meAddUpdateUserProfileCB:  j.rC= ' + j.rC + '  tde= ' + tde + '  subF= ' + subF);

	if(!subF) { subF = false; }

	var $b = $('#meuModal form').find('#meuSubBtn'), cls='success', txt = 'Updated!';

	if( j.rC != 1 )	// a problem was encountered...
	{
		clearWinWait('meAddUpdateUserProfileCB');

		if(j.dupF || j.rC == -2 || j.rC == -3 || j.rC == -4)
		{
			let $m = $('#gModal1'), w = 'auto', h;

				$m.find('.modal-header').hide(0);

				if(j.rC == -2)
					h = 'Sorry, but a user in a different company already employs the specified email address<p>Please enter a different email address or contact <a href="javascript:gMdlHelp();">LeadLeaper</a> for assistance';
				else if(j.rC == -3)
					h = 'Sorry, but there are no unused user licenses remaining<p>Please contact <a href="javascript:uHelp( \'gModal1\' );">LeadLeaper</a> for assistance';
				else if(j.rC == -4)
					h = 'Sorry, but no existing user with the specified email address exists';
				else
					h = 'Sorry, but the entered email address already exists<p>Please enter a different email address or contact <a href="javascript:gMdlHelp();">LeadLeaper</a> for assistance';

				$m.find('.modal-body').html( '<div style="margin:10px 0; font-size:16px;">' + h + '</div>' );

				$m.find('.modal-footer').show(0).find('button.btn-default').hide(0).end().find('button.btn-confirm').text('OK').show(0);

					$m.modal( { width: w, keyboard: true, backdrop: 'static', show: true } );

				cMdl( $m );
		}
		else
		{
			oe('meAddUpdateUserProfileCB', 'j.rC= ' + j.rC);
		}

		return;
	}


	if( tde )	// if tde undefined, then adding (not editing) a user...
	{
		rd = medt.row( tde ).data();

			rd.fName 		= j.ufN;
			rd.lName 		= j.ulN;

			rd.gData.title 	= j.uTtl;
			rd.gData.email 	= j.uEm;
			rd.gData.phone 	= j.uPh;

			rd.gData.status	= j.uStatus;
//			rd.gData.pafi	= j.pafi;
			rd.gData.rc		= j.uRoleCode;
	
		medt.row( tde ).data( rd ).draw(false);	// do NOT reset pagination!!

		clearWinWait('meAddUpdateUserProfileCB');

		$b.addClass(cls).html(txt).blur();

		setTimeout(function() { $b.removeClass(cls).html('Save <i class="fa fa-arrow-circle-right"></i>'); }, 2000);	// setTimeout(function() { $b.removeClass(cls).html('Update <i class="fa fa-arrow-circle-right"></i>'); }, 2000);
	}
	else
	{
		$('#meuModal').modal('hide');	// close add popup...

		if( subF )		
		{
			clearWinWait('meAddUpdateUserProfileCB');

			$.getJSON( 'AJAX_Subscription', { aID:aID, uID:uID}, function(j) { $('#subscript').find('#eAcctSub').html(j.h); } ).fail(function(jx, ts, er) { oae('meAddUpdateUserProfileCB.AJAX_Subscription', jx, ts, er); });		// subUIcb
		}
		else
		{
			$('#mgmtMT').click();	// added a new team member so refresh table AND ensure displaying top level...

			clearWinWait('meAddUpdateUserProfileCB');			// ensure winWait immediately cleared during table refresh...
		}


		let $m = $('#gModalYN'), w = 'auto', h;

			if( j.dupF )
			{
				if(subF)
				{
					h = 'A user with the specified email address already exists';
				}
				else
				{
					if(j.ieF)
						h = 'Addition complete and user re-notified of their new ' + llName + ' account';
					else
						h = 'Addition of existing user complete';
				}
			}
			else if( j.ieF )
			{
				h = 'Addition complete and user notified of their new ' + llName + ' account';
			}
			else
			{
				h = 'Addition complete';
			}

			h += '<p style="margin-top:20px">Would you like to add another user?</p>';



			$m.find('.modal-header').hide(0);

			$m.find('.modal-body').html( '<div style="margin:10px 0; color:green; font-size:15px;">' + h + '</div>' );

			$m.find('.modal-footer').show(0).find('button').show(0).off('click').on( 'click', function(evt){ meAddUpdateUserProfileCBCB(evt, subF);   } );

			$m.modal( { width: w, keyboard: true, backdrop: 'static', show: true } );	// SAVE!! .on( 'hidden.bs.modal', function() { $('#meuModal').modal('hide'); }); 

			cMdl( $m );

	}	// else
}



