function hsStatusChk( evt )
{
//console.log( 'hsStatusChk:  addHSf= ' + addHSf);

	if( !addHSf || hsStatusChkFlag ) { return; }	// check already underway...

	if( addHSf )
	{
		hsStatusChkFlag = true;	// set...

		addHSf = false;				// reset...

		// get HS integration status...
		$.post(	'HubSpotLdLprProfileData', 

				{ cby:'addHSc', userStatusF:true, uID:uID },

				function( j )
				{
//console.log('hsStatusChk:  j= ' + JSON.stringify(j));
//j.hsAID = 1;
//j.hsUID = 1;
					try
					{
						if( j && j.hsAID && j.hsUID )
						{
							hsAID = j.hsAID;
							hsUID = j.hsUID;

							hsIAF = true;

				hsIF  = true;
				hsASF = true;	// now, if integrated, then auto-sync enabled...
// ---
				$('body').addClass('hsIF');
// ---
							$('#opabhsabt, #opabhsnew, #opabhsillhs').addClass('displayNone');

							$('#opabhsls, #opabhsli').removeClass('displayNone');
// ---
							$('#outDD').trigger('click'); 
						}
					}
					catch( err )
					{
//console.log('addHSc.HubSpotLdLprProfileData.err:  err= ' + err.message);
					}
					finally
					{
						hsStatusChkFlag = false;	// reset...
					}
				}

			).fail(function(jx, ts, er) { hsStatusChkFlag = false;		oae('hsStatusChk.HubSpotLdLprProfileData', jx, ts, er, true); });

	}	// if addHSf...
}



function addHSc( url, o )	// addHSconfirmed...
