function addHS( code )	// AS = AutoSync	LI = ListImport		DS = DossierSync(lead)
{
	if( !code ) { code = ''; }
//console.log( 'addHS:  code= ' + code);

	clearWinWait('addHS');		// KEEP!!!

	$('#opdtActBtn').parent().removeClass('open');	// close drop-down...

// ---
	if ( glc < 2 ) { reqUpGrd( 'addHS' );	return; }		// reqUpGrd calls reqSub if !glc 
// ---


	let asF=false, liF=false, dsF=false, intF=false;

	switch( code )
	{
		case 'AS'	:	asF = true;		break;

		case 'LI'	:	liF = true;		break;

		case 'DS'	:	dsF = true;		break;

		case 'INT'	:	intF = true;	break;

		default		:					break;		// return;
	}
//console.log( 'addHS:  asF= ' + asF + '  liF= ' + liF + '  dsF= ' + dsF + '  intF= ' + intF);


	$.post(	'hs_auth', 

			{ uID: uID }, 

//			function( jsn, s, xhr ) {
			function( jsn ) {
								if( jsn && typeof jsn == 'string' ) { jsn = JSON.parse(jsn); }	
//console.log( 'addHS.hs_auth:  jsn= ' + ( jsn ? JSON.stringify(jsn) : jsn) );		// + '  s= ' + s + '  xhr.status= ' + xhr.status);

								if( !jsn || !jsn.u )
								{
//									$('#hsAuthModal').modal('hide');

									if( !jsn )
										setTimeout(function() { oe('addHS.hs_auth', '!jsn'); }, 400);
									else
										setTimeout(function() { oe('addHS.hs_auth', '!jsn.u for jsn= ' + ( jsn ? JSON.stringify(jsn) : jsn)); }, 400);

									return;
								}

	let h 	= 	'<div>'

			+ 	'<p>Before proceeding<b>,</b> <b>HubSpot</b> requires that you authorize LeadLeaper to integrate with your <b>HubSpot CRM</b> account</p>';
/* SAVE
	if( asF || liF )
	{
		h 	+= 	'<p class="afterAuth">After authorizing<b>,</b> re-select <span class="reSel">' + (asF ? 'Enable Auto Sync' : 'Import Leads' ) + '</span> to continue</p>';
	}
*/
	if( liF )
	{
		h 	+= 	'<p class="afterAuth">After authorizing<b>,</b> re-select <span class="reSel">Import Leads</span> to continue</p>';
	}


	if( !intF )	// NOT
	{
		h 	+= 	'<p class="addHS-lnk"><a href="https://www.hubspot.com/products/crm" target="_blank">About HubSpot FREE CRM</a></p>'

			+ 	'<p class="addHS-lnk"><a href="https://app.hubspot.com/signup-hubspot/crm" target="_blank">Create a HubSpot FREE CRM account</a></p>';	// style="margin-top:10px;"
	}

		h 	+= 	'</div>';


	let $m = $('#hsAuthModal');

		$m.find('.modal-header').show(0).find('.modal-title').text('HubSpot Integration');

		$m.find('.modal-body').html( h );

		$m.find('.modal-footer').show(0).find('button.btn-confirm').off('click').on( 'click', function(evt) { addHSc( jsn.u, { dsF:dsF } ); } );

		$m.modal( { width: 450, keyboard: true, backdrop: 'static', show: true } ).on( 'hidden.bs.modal', function() { $(this).data('bs.modal', null); });

							}	// fn

			).fail(function(jx, ts, er) { if(!jx || !jx.status || jx.status != 200) { $('#hsAuthModal').modal('hide');		oae('addHS.hs_auth', jx, ts, er); } });
}










