function initLLhsAS( loF )	// InitLdLprHubSpotAutoSync...		listOnlyFlag...
{
//console.log( 'initLLhsAS:  loF= ' + loF);

	$('#opdtActBtn').parent().removeClass('open');	// close drop-down...

// ---
	if ( glc < 2 ) { reqUpGrd( 'initLLhsAS' );	return; }		// reqUpGrd calls reqSub if !glc 
// ---

	if( !loF ) { loF = false; }


	winWait( 'initLLhsAS' );

	// 1st, get status...
	$.post(	'HubSpotBatchSync', 

			{ aID:aID, uID:uID, pID:outpID, cntF:true, loF:loF }, 	// loF listOnlyFlag...

			function( jsn, s, xhr ) {

				clearWinWait('initLLhsAS');

				if( jsn && typeof jsn == 'string' ) { jsn = JSON.parse(jsn); }	
	//console.log( 'initLLhsAS:  jsn= ' + ( jsn ? JSON.stringify(jsn) : jsn) + '  s= ' + s + '  xhr.status= ' + xhr.status);
	//console.log( 'initLLhsAS:  xhr.status= ' + xhr.status);
	// ---
				if( xhr.status == 202 )			// NO HS Acct...
				{
					addHS( 'AS' );				// addHS(Integration)...
				}

				else if( xhr.status == 203 )	// Done...
				{
					setTimeout(function() { 
											pmp('LeadLeaper HubSpot Auto Sync Enabled'); 
								}, 400);
				}

				else
				{
					oe('initLLhsAS.HubSpotBatchSync', 'xhr.status= ' + xhr.status);
				}

			}).fail(function(jx, ts, er) { if(!jx || !jx.status || jx.status != 200) { oae('initLLhsAS.HubSpotBatchSync', jx, ts, er); } });
}
