	try { $tipPO.popover('destroy'); } catch(er){}
// ---

	var $e = $(evt.target), n = 0;

	while( $e.get(0).tagName.toLowerCase() != 'li' && n < 5 ) { $e = $e.parent();  n++; }
//console.log( 'dtActBttnAcc:   $e.get(0).tagName= ' +  $e.get(0).tagName + '  for n= ' + n);

	var $u = $e.find('> ul');

