function optSP( $e, btn )
{
//console.log('optSP:  $e= ' + $e + '  btn= ' + btn + '  colleaguesCnt= ' + colleaguesCnt);


	$('.dataTables_filter .actBtn').removeClass('open');



	if( outSelcIDs && outSelcIDs.endsWith(",") ) { outSelcIDs = outSelcIDs.substring(0, outSelcIDs.length-1); }


	let LdsCnt = (outSelcIDs + '').split(',').length;
//console.log( 'dtActBttn.TRANSFER:  LdsCnt= ' + LdsCnt );

// ----
		if( !outSelcIDsNotOwnerA ) { outSelcIDsNotOwnerA = []; }
//console.log( 'optSP:  outSelcIDsNotOwnerA.length= ' + outSelcIDsNotOwnerA.length);

		if( outSelcIDsNotOwnerA.length )
		{
			rpt('optSP.TRANSFER', 'outSelcIDsNotOwnerA.length= ' + outSelcIDsNotOwnerA.length + '  for LdsCnt= ' + LdsCnt + '  and outSelcIDsNotOwnerA= ' + outSelcIDsNotOwnerA);

			setTimeout(function() { pmp('Ownership of duplicate leads cannot be transferred'); }, 500);	// MUST come AFTER oe...

			return;
		}
// ----

	if( !LdsCnt )	// NOT
	{
		oe('optSP', 'LdsCnt= ' + LdsCnt);

		return;
	}



	$.post(	'AJAX_UserTransferLeads', 

			{ aID:aID, uID:uID, glc:glc, cF:true }, 	// colleaguesFlag

			function( j )
			{
//console.log('optSP.AJAX_UserTransferLeads:  j= ' + j);

				if( typeof j == 'string' ) { j = JSON.parse(j); }
//console.log( 'optSP.AJAX_UserTransferLeads:  j= ' + JSON.stringify(j) );

				var colsFlag, oddFlag, colMaxCnt, cntr=0, h='', rh = 26, mt = 0, cls='transLists';	// , TplColFlag;

/* SAVE!!!
				if( j.colleaguesCnt > 3 )
				{
					colsFlag = true;
					if( ( j.colleaguesCnt % 2 ) == 0 )	// even number...
					{
						colMaxCnt = j.colleaguesCnt / 2;
					}
					else
					{
						oddFlag = true;
						colMaxCnt = ( j.colleaguesCnt + 1 ) / 2;
					}
				}
				else
				{
					colMaxCnt = j.colleaguesCnt;
				}
*/

// ----
				if( j.colleaguesCnt > 8 )	// <<<<<<<<<<<<<<<<<<<<<<
				{
					colsFlag   = true;

					if( ( j.colleaguesCnt % 3 ) == 0 )	// even number...
					{
						colMaxCnt = j.colleaguesCnt / 3;
					}
					else
					{
						oddFlag = true;

						colMaxCnt = ( j.colleaguesCnt + 1 ) / 3;
					}
				}
				else if( j.colleaguesCnt > 3 )
				{
					colsFlag = true;

					if( ( j.colleaguesCnt % 2 ) == 0 )	// even number...
					{
						colMaxCnt = j.colleaguesCnt / 2;
					}
					else
					{
						oddFlag = true;

						colMaxCnt = ( j.colleaguesCnt + 1 ) / 2;
					}
				}
				else
				{
					colMaxCnt = j.colleaguesCnt;
				}
// ----


//console.log('optSP:  colsFlag= ' + colsFlag + '  oddFlag= ' + oddFlag + '  colleaguesCnt= ' + j.colleaguesCnt + '  colMaxCnt= ' + colMaxCnt + '  mt= ' + mt + '  cls= ' + cls);

				if( colsFlag ) { h += '<div class="selCamPO selTransTarget">'; }

				h += '<div class="popCpyMvCls popTransCls"><span style="font-size:16px;" title="close" onclick="pmpCls()">X</span></div>';


				h += '<div class="popTransIntro" style="min-width:350px;" >Transfer ownership ' + (LdsCnt > 1 ? ('of the selected ' + LdsCnt + ' leads') : 'of the one selected lead' ) + ' to<b>:</b></div>';


				h += '<ul class="dropdown-menu dropdown_projects-menu ' + cls + '" role="menu"  style="font-size:16px; margin-top:' + mt + 'px;">';


				j.colleaguesArr.forEach(

						function( item, idx )
						{
// NO!!!!						let uFN = item.uFN.replace(/\'/g, "&#39;").replace(/\"/g, '&#34;'),
// NO!!!!							uLN = item.uLN.replace(/\'/g, "&#39;").replace(/\"/g, '&#34;');

							let uFN = item.uFN.replace(/\'/g, "\\'").replace(/\"/g, '\\"'),
								uLN = item.uLN.replace(/\'/g, "\\'").replace(/\"/g, '\\"');
//console.log('optSP:  uLN= ' + uLN + '  for item.uLN= ' + item.uLN);

							if( cntr == colMaxCnt )
							{
								h += '</ul><ul class="dropdown-menu dropdown_projects-menu ' + cls + '" role="menu"  style="margin-top:' + mt + 'px;">'; 

								cntr = 0;	// reset...
							}

							h += '<li  id="opabp' + btn + item.uID + '"  onclick="selTransTarget(\'' + item.uID + '\', \'' + item.email + '\', \'' + uFN + '\', \'' + uLN + '\');"  title=" ' + item.email + ' ">' + item.uLN + '<b>,</b> ' + item.uFN + '</li>';

							cntr++;

						});	// forEach



				if( oddFlag ) { h += '<li class="disabled">&nbsp;</li>'; }

								h += '</ul>';

				if( colsFlag ) { h += '</div>'; }


				pmp( h, { popClass: 'popCpyMv popTrans', hideFttr:true, clsBgClk:true } );

			},	// successFn

			'json'

		).fail(function(jx, ts, er) { oae('optSP.AJAX_UserColleagues', jx, ts, er); });
}



