function exp( id )
{
//console.log('exp:  id= ' + id);

	var $m;		if( !glc ) { $m = $( '#gModalYNwarn' ); } else { $m = $( '#gModalYN' ); }

	var h 	= 	'<div style="width:285px; font-size:16px;">Export leads to a CSV file?';	// Export leads from this list to a CSV file?


	if( !glc )
	{
		h	+= 	'<p id="expSav" style="margin:10px 0 0;">Be sure to save the resulting <b>.</b>csv file<b>.</b></p>'

			+ 	'<p class="expDelCbox" style="margin:10px 0 0;"><label class="chked" for="expDelCbox"><input name="expDelCbox" id="expDelCbox" value="1" type="checkbox"  checked="checked"><span>Remove the exported leads</span></label></p>';
	}
	else
	{
		h	+= 	'<p id="expSav" style="margin:10px 0 0;">Be sure to save the resulting <b>.</b>csv file<b>.</b></p>'

			+ 	'<p class="expDelCbox" style="margin:10px 0 0;"><label for="expDelCbox"><input name="expDelCbox" id="expDelCbox" value="1" type="checkbox"><span>Remove the exported leads</span></label></p>';
	}

		h	+= 	'</div>';

		$m.find('.modal-header').hide(0);

		$m.find('.modal-body').html( h );

		$m.find('.modal-footer').show(0).find('button').show(0).off('click').on( 'click', function(evt){ expC( evt, id ); } );

	$m.find('input#expDelCbox').off('click').on('click', expDelCbox);

	if( glc ) { $m.find('#expSav').hide(); }

		$m.modal( { width: 'auto', keyboard: true, backdrop: 'static', show: true } );

		cMdl( $m );
}



function expDelCbox( evt )
{
//console.log('expDelCbox  evt.target.checked= ' + evt.target.checked);

	var $e = $(evt.target), f = $e.is(':checked');
//console.log("expDelCbox  $e.is(':checked')= " + $e.is(':checked'));

	if( f )
	{
		$('input#expDelCbox').parent().addClass('chked');

		if( glc ) { $('#expSav').show( { duration:400 } ); }
	}
	else
	{
		if( !glc )
		{
			pmp( 'Export without delete requires a subscription upgrade' );

			$('input#expDelCbox')[0].checked = true;
		}
		else
		{
			$('input#expDelCbox').parent().removeClass('chked');

			$('#expSav').hide( { duration:400 } );
		}
	}
}




