function opRp( id, $e, pmF, actF, cnt )	// outProjectRemoveProspects
{
//console.log('opRp:  id= ' + id + '  pmF= ' + pmF + '  actF= ' + actF + '  cnt= ' + cnt);

	if( !cnt ) { return; }

	var h, w = 300, mdlID = '#gModalYNwarn';

	if( actF )
	{
		id = 'actabmREMOVE';

		if( cnt > 1 )
		{
			w = 255;

			h = 'Remove the <b>' + cnt + '</b> selected Leads?';
		}
		else
		{
			w = 210;

			h = 'Remove the selected Lead?';
		}
	}

	else
	{
		if( id == 'opabneREMOVE' )
		{
			if( cnt > 1 )
			{
				w = 460;

				h = 'Remove the <b>' + cnt + '</b> Leads without an email address from this list?';
			}
			else
			{
				w = 440;

				h = 'Remove the one Lead without an email address from this list?';
			}
		}
		else
		{
			if( cnt > 1 )
			{
				w = 340;

				h = 'Remove the <b>' + cnt + '</b> selected Leads from this list?';
			}
			else
				h = 'Remove the selected Lead from this list?';
		}
	}


	$('#outProspects_filter').find('div.actBtn').removeClass('open');


	var $m = $( mdlID );

		$m.find('.modal-header').hide(0);

		$m.find('.modal-body').html( '<div style="width:' + w + 'px; font-size:16px;">' + h + '</div>' );

		$m.find('.modal-footer').show(0).find('button').show(0).off('click').on( 'click', function(evt){ opRpc(evt, pmF, actF); } );

		$m.modal( { width: 'auto', keyboard: true, backdrop: 'static', show: true } );

		cMdl( $m );
}



function opRpc( evt, pmF, actF )
{
//console.log('opRpc:  pmF= ' + pmF + '  actF= ' + actF);

	evt.preventDefault();

	var $b = $(evt.target);

	if( $b.hasClass('btn-confirm') )
	{
		var a, pID=0;
/*
		if( pmF )
		{
			a = pmSelcIDs;
		}
*/
		if( actF )	// else if( actF )
		{
			a = actSelcIDs;
		}

		else
		{
			if( glc ) { pID = outpID; }		// if glc == 0, then remove from all projects since there may be multiple (i.e., we list all leads rather than a single list)...

			a = outSelcIDs;
		}

		$('.dataTables_filter .actBtn').removeClass('open');

//console.log('opRpc:  pID= ' + pID + '  a.length= ' + a.length + '  a= ' + a);
//return;
	
		winWait( 'opRpc' );

		$.post(	'AJAX_CMR', 

				{ aID:aID, uID:uID, glc:glc, from:pID, cIDs:a, ec:'d', pmF:pmF, actF:actF }, 

				function( j ) { cmd_CB(j, true, pmF, actF); },

				'json'

 				).fail(function(jx, ts, er) { if(!jx || !jx.status || jx.status != 200) { oae('opRpc.AJAX_CMR  a= ' + a, jx, ts, er); } });
	}
}




function cmd_CB( j, dF, pmF, actF )
{
//console.log('cmd_CB: j.rC= ' + j.rC + '  dF= ' + dF + '  pmF= ' + pmF + '  actF= ' + actF);

	if( j.rC != 1 )	// a problem was encountered...
	{
		clearWinWait('cmd_CB');

		oe('cmd_CB:', 'j.rC= ' + j.rC);

		return false;
	}


	setTimeout( function() { 
							if( dF )		// also applies to moves...
							{
/*
								if( pmF )
								{ 
									 winWait();  pmdt.ajax.url( 'AJAX_ProspectsMgr?aID=' + aID + '&uID=' + uID + '&glc=' + glc ).load( pm_CB );
								}
*/
								if( actF )	// else if( actF )
								{ 
									 winWait( 'cmd_CB.actF ');  	adt.ajax.url( 'AJAX_Activity?aID=' + aID + '&uID=' + uID + '&glc=' + glc + '&freeOutF=' + freeOutF ).load( act_CB );
								}

								else
								{
//									if( engF )
//										$('#engSB' + outpID).trigger( 'click', { pID:outpID, cmdF:true } );
//									else
										$('#outSB' + outpID).trigger( 'click', { pID:outpID, cmdF:true } );
								}
							}
							else
							{
								if( pmF )
								{
									$('#pmabmNONE').trigger( 'click' );
								}

								else if( actF )
								{
									$('#actabmNONE').trigger( 'click' );
								}

								else
								{
									$('#opabmNONE').trigger( 'click' );
								}

								clearWinWait('cmd_CB');
							}

					}, 500);
}



