function aiAutoSave( cBy, o )	// dataObj		selVer
{
	if( !o ) { o = {}; }
//console.log('aiAutoSave:  o= ' + JSON.stringify(o));

//console.log('aiAutoSave:  cBy= ' + cBy + '  o.tempSavF= ' + o.tempSavF + '  dObj.cID= ' + dObj.cID + '  dObj.aiSessionF= ' + dObj.aiSessionF + '  dObj.aiObj.s3F= ' + (dObj.aiObj ? dObj.aiObj.s3F : dObj.aiObj) + '  dObj.rd.aiS3F= ' + (dObj.rd ? dObj.rd.aiS3F : dObj.rd ));
//console.log('aiAutoSave:  dObj.aiObj.engCon.arr= ' + (dObj.aiObj && dObj.aiObj.engCon ? dObj.aiObj.engCon.arr : 'na'));

		if( !dObj || !dObj.aiObj )
		{
//console.log('aiAutoSave:  ABORT');

			return;
		}


		var aiObj = {};		

		var saveF = true;	// now, always...

		try
		{
			if( !o.tempSavF )	// NOT
			{
				dObj.aiLCDobj = null;	// clear...

				dObj.eCN 	  = null;	// clear...

				aiRemoveClasses( cBy + '.aiAutoSave' );
			}


			if( !dObj.aiObj.editors ) { dObj.aiObj.editors 	= {}; }
			if( !dObj.aiObj.engCon 	) { dObj.aiObj.engCon 	= {}; }

			if( !dObj.aiObj.engCon.emailedA   ) { dObj.aiObj.engCon.emailedA   = []; }
			if( !dObj.aiObj.engCon.emailedObj ) { dObj.aiObj.engCon.emailedObj = {}; }

			if( !dObj.aiObj.engCon.arr    ) { dObj.aiObj.engCon.arr  	= []; }
			if( !dObj.aiObj.engCon.data   ) { dObj.aiObj.engCon.data 	= {}; }
			if( !dObj.aiObj.engCon.snip   ) { dObj.aiObj.engCon.snip 	= {}; }
			if( !dObj.aiObj.engCon.arrStg ) { dObj.aiObj.engCon.arrStg	= ''; }


			aiObj.cID = dObj.cID;

			aiObj.editors 			= dObj.aiObj.editors;
			aiObj.engCon 			= dObj.aiObj.engCon

			aiObj.engCon.emailedA   = dObj.aiObj.engCon.emailedA;
			aiObj.engCon.emailedObj = dObj.aiObj.engCon.emailedObj;

			aiObj.engCon.arr  		= dObj.aiObj.engCon.arr;
			aiObj.engCon.data 		= dObj.aiObj.engCon.data;
			aiObj.engCon.snip 		= dObj.aiObj.engCon.snip;
			aiObj.engCon.arrStg		= dObj.aiObj.engCon.arrStg;


//console.log('aiAutoSave:  starting aiObj.engCon.arr.length= ' + aiObj.engCon.arr.length);

			for(var key in aiObj.editors)		// <<<<<<<<<<<<<<<
			{
				if (Object.prototype.hasOwnProperty.call(aiObj.editors, key)) 
				{
					var id = key.substring(0, key.lastIndexOf('_MCE'));		// AI_226158_1765063848628_1_IEEAR_MCE	-->  AI_226158_1765063848628_1_IEEAR
//console.log('aiAutoSave:  key= ' + key + '  -->  id= ' + id);

					if( !aiObj.engCon.arr.includes( id ) )	// NOT
					{
						aiObj.engCon.arr.push( id )
					}
				}
			}
//console.log('aiAutoSave:  ending aiObj.engCon.arr.length= ' + aiObj.engCon.arr.length);


			if( !aiObj.engCon.arr.length )		// final aiObj= {"cID":223415,"editors":{},"engCon":{"emailedA":[],"emailedObj":{},"arr":[],"data":{},"snip":{},"arrStg":"","selUTC":17}}
			{
//console.log('aiAutoSave:  NOTHING to save --> RETURN');

				return;
			}




			for( const id of aiObj.engCon.arr )		// 	['AI_226111_1765041257456_1_LLP', 'AI_226111_1765041315568_4_IEECR', 'AI_226111_1765041330808_5_IEEPPR']
			{
//console.log('aiAutoSave.for:  id= ' + id);
				try
				{
					if( aiObj.engCon.emailedA.includes( id ) ) { continue; }
// ---
					var code = id.substring(id.lastIndexOf('_') + 1);
// ---
					var sub = $gDOS.find('.aiDOSpop').find('#' + id).find('.aiMCE').find('.eSubject').val().trim();
//console.log('aiAutoSave.for:  id= ' + id + '  -->  code= ' + code + '  and sub= ' + sub);

						if( !aiObj.engCon.data[id] ) { aiObj.engCon.data[id] = {}; }

						aiObj.engCon.data[id].sub = sub;

// -----
					if( code == 'LLP' )
					{
						var comment = $gDOS.find('.aiDOSpop').find('#' + id + '_comment').val().trim();		// AI_221654_1766862520738_13_LLP_comment
//console.log('aiAutoSave.for.LLP:  comment= ' + comment);

						var comCboxF = $gDOS.find('.aiDOSpop').find('#' + id + '_comment_cBox').is(':checked');		// <<<<<<<<<<<<<<<<<<<
//console.log('aiAutoSave.for.LLP:  comCboxF= ' + comCboxF);

						var startingComCboxF = aiObj.engCon.data[id].comCboxF;
//console.log('aiAutoSave.for.LLP:  startingComCboxF= ' + startingComCboxF);


						if( !aiObj.engCon.data[id] ) { aiObj.engCon.data[id] = {}; }

						aiObj.engCon.data[id].comment  = comment;

						aiObj.engCon.data[id].comCboxF = comCboxF;
					}
// -----


					// see if editor "dirty" and if so, capture update before saving...
					var tmce = tinymce.get( id + '_MCE' );		// .getContent().replace(/\n/g, "");	
//console.log('aiAutoSave.for:  id= ' + id + '  -->  code= ' + code + '  -->  tmce.getContent()= ' + tmce.getContent());

					// if( tmce.isDirty() )	<-- DOES NOT WORK - ALWAYS FALSE!!!!!!!!!!!

					if( !tmce || tmce.getContent().replace(/\n/g, "").trim().length < 50 ) { continue; }	// skip...


					$tDiv[0].innerHTML = tmce.getContent().replace(/\n/g, "").trim();	// req'd for syncSal && relativeFontSizes below...

					relativeFontSizes( 'dosCls' );

					var bdy = $tDiv.html();

					if( !aiObj.engCon.data[id] ) { aiObj.engCon.data[id] = {}; }

					aiObj.engCon.data[id].bdy = bdy;


					var eLnks = [];


					$tDiv.find('a').each( function(idx, e) { 

										let href = $(this).attr('href');

										if( href )
										{
											eLnks.push( href );
										}
									});

					aiObj.engCon.data[id].eLnks = eLnks;



//					if( code == 'IEEAR' || code == 'IEECR' || code == 'IEEPPR' )	// || code == 'IEEPPRCR'
					if( code.startsWith( 'IEE' ) )
					{
						var defVerO, selVerCode, edObj = aiObj.editors[ id + '_MCE' ];
//console.log('aiAutoSave:  edObj= ' + edObj);

						try { selVerCode = edObj[ 'selVer' ]; } catch(errr) { selVerCode = null; }
//console.log('aiAutoSave:  starting selVerCode= ' + selVerCode);
// ---
						if( !selVerCode ) { selVerCode = 'DEF'; }	// <<<<<<<<<<<<<<<<<<<<<<<<<<<	dObj
//console.log('aiAutoSave:  ending selVerCode= ' + selVerCode);
// ---
// ---
						aiObj.IEEF = true;
// ---
						if( selVerCode != 'DEF' )
						{
							defVerO = edObj.versionsObj[ 'DEF' ];
						}

						if( !aiObj.engCon.data[id] ) { aiObj.engCon.data[id] = {}; }

						aiObj.engCon.data[id].selVerCode	= (selVerCode ? selVerCode : '');

						aiObj.engCon.data[id].defVerO		= (defVerO  ? defVerO  : '');
					}

					else	// else if( saveF )		// record associated article/post...		id = AI_226111_1765041257456_1_LLP
					{
						var art;	try { art = $gDOS.find('.aiDOSpop').find('#' + id).find('> .con').text().trim(); } catch(errr) { art = null; }
//console.log('aiAutoSave:  id= ' + id + '  -->  art.length= ' + (art ? art.length : art));

						if( art )
						{
							if( !aiObj.engCon.data[id] ) { aiObj.engCon.data[id] = {}; }

							aiObj.engCon.data[id].art	= (art ? art.trim() : '');
						}
					}
// ---
					if( !aiObj.engCon.data[id].del ) { aiObj.engCon.data[id].del = '2 days'; }
// ---
				}
				catch( errrrr )
				{
//console.log('aiAutoSave.for:  errrrr= ' + errrrr.message + '   for id= ' + id);
				}

			}	// for	<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<



			if( !o.tempSavF )
			{
				if( !aiObj.engCon.selUTC )
				{
					var tzOffSetHrs = new Date().getTimezoneOffset()/60;	// --> +8 for GMT-0800 (Pacific Daylight Time) so do NOT invert the sign before applying...
//console.log('aiAutoSave:  starting tzOffSetHrs= ' + tzOffSetHrs);

						tzOffSetHrs = Math.round( tzOffSetHrs );			// ensure an int...
//console.log('aiAutoSave:  final (round) tzOffSetHrs= ' + tzOffSetHrs);

					aiObj.engCon.selUTC = 9 + tzOffSetHrs;				// set to convert to 9 AM local...
				}


//console.log('aiAutoSave:  final aiObj= ' + JSON.stringify(aiObj));		// final aiObj= {"cID":223415,"editors":{},"engCon":{"emailedA":[],"emailedObj":{},"arr":[],"data":{},"snip":{},"arrStg":"","selUTC":17}}


				try
				{
					$.post(	'AJAX_DossierOC', 

						{ aID:aID, uID:uID, cID:dObj.rd.gData.cID,   oe:dObj.rd.email,  autoSaveF:true, aiLiveF:false, aiSaveF:true, aiEngConF:true, aiObj:JSON.stringify(aiObj) },

						function( jsn ) 
						{
//console.log('aiAutoSave.AJAX_DossierOC:  jsn= ' + (jsn ? JSON.stringify(jsn) : jsn));
							if( !jsn || !jsn.sF )
							{
								oe('aiAutoSave.AJAX_DossierOC', '!jsn || !jsn.sF  for jsn= ' + (jsn ? JSON.stringify(jsn) : jsn), true, true );		// silent...
							}

//								try { dObj.aiObj.tpyArr = tpyArr; } catch(errrr){}	// reset...
						}, 

						'json' )

						.fail(function(jx, ts, er) { oae('aiAutoSave.AJAX_DossierOC', er, true, true);  });
				}
				catch(errr)
				{
//console.log('aiAutoSave.AJAX_DossierOC:  errr= ' + errr.message);

					oe('aiAutoSave.AJAX_DossierOC', errr.message, true);
				}

			}	// if NOT o.tempSavF...



			if( !o.tempSavF )	// NOT
			{
				dObj.rd.aiS3F = true;	// <<<<<<<<<<<<<<<<<<<<<<<<<<<<

				opdt.row( dObj.tde ).data( dObj.rd ).draw(false);	// <<<<<<<<<<<<<<<<<<<<<<<<<<<<


				$gDOS.find('.dosAI-dd').find('> .aiEmpRsrch').removeClass('hl');
//console.log("aiAutoSave:  $('#aiDOSpop').find('> .content').find('> .body').find('> .block').length= " + $('#aiDOSpop').find('> .content').find('> .body').find('> .block').length);

//				$gDOS.find('.aiDOSpop').find('> .content').find('> .body').find('> div').remove(); 		// <<<<<<<<<<<<<<<<<<<<<
				$gDOS.find('.aiDOSpop').find('> .content').find('> .body').find('> .block').find('> .bdy').find('> div').remove();  	// <<<<<<<<<<<<<<<<<<<<<	
			}

		}
		catch(errr)
		{
//console.log('aiAutoSave.aiF:  errr= ' + errr.message);
		}
}






function dosCls( )
{
//console.log('dosCls:  aiF= ' + aiF + '  dObj.aiObj= ' + dObj.aiObj);
//console.log('dosCls:  dREMcIDo.dREMcIDa= ' + dREMcIDo.dREMcIDa);
//console.log('dosCls:  dREMcIDo.dREMcIDa.length= ' + dREMcIDo.dREMcIDa.length);
//console.log('dosCls:  dREMcIDo.opF= ' + dREMcIDo.opF + '  dREMcIDo.aF= ' + dREMcIDo.aF + '  dREMcIDo.dREMcIDa= ' + dREMcIDo.dREMcIDa);

// ---
	if( aiF )
	{
// ---
		$('#dosNext').trigger('mouseout');	// <<<<<<<<<<<<<<<<<<<<
// ---

		if( !aiSessionObj ) // NOT
		{
			aiSessionObj = { aiINmodeF:false, aiNoINmodeF:false };
		}
		else
		{
			aiSessionObj.aiINmodeF 	 = false;	// reset...

			aiSessionObj.aiNoINmodeF = false;	// reset...
		}


		if( dObj.aiObj )
		{
			aiAutoSave( 'dosCls' );		// includes aiRemoveClasses
		}
		else
		{
			aiRemoveClasses( 'dosCls' );
		}
// ---
		$gDOS.find('.std-form, .aiDOSpop').hide(0);	
// ---
	}
// ---


// console.log('dosCls:  AAA');


	if( listLoadingFlag )
	{
		winWait( 'dosCls.listLoadingFlag' );

		setTimeout( function() { if( !listLoadingFlag ) { clearWinWait('dosCls'); } }, 2000);
	}
// ---



	if( dObj.cnF && dObj.tde && !hsLoginF && !hsIF )	// <<<<<<<<<<<<<<<<<<<<<<<<
	{
		winWait( 'dosCls.listLoadingFlag.cnF' );

		let v = $('#dNotes').val();

		$.getJSON( 'AJAX_DossierOC', 

					{ aID:aID, uID:uID, cID:dObj.cID, name:'dNotes', value:v, hsLoginF:hsLoginF, hsASF:hsASF, hsUID:hsUID }, 

					function( j ) { gDOSocCB( JSON.stringify(j), v, dObj.tde, { dclsF:true } ); } )

				.fail(function(jx, ts, er) { if(!jx || !jx.status || jx.status != 200) { oae('dosCls.AJAX_DossierOC', jx, ts, er); } });
	}


	if( dREMcIDo.dREMcIDa.length )
	{
		let a = '';		$.each( dREMcIDo.dREMcIDa, function(i,v) { a += v + ','; } );
//console.log('dosCls:  a= ' + a);

		if( dREMcIDo.opF )
		{
			opdt.rows('.dosREM').remove().draw(false);

			$.getJSON( 'AJAX_CMR', { aID:aID, uID:uID, from:outpID, cIDs:a, ec:'d', pmF:false } ).fail(function(jx, ts, er) { if(!jx || !jx.status || jx.status != 200) { oae('dosCls.AJAX_CMR', jx, ts, er); } });
		}

		else if( dREMcIDo.aF )
		{
			$.getJSON( 'AJAX_DeleteActivity', 

						{ aID:aID, uID:uID, cID:a, dosF:true }, 

 						function( j ) {	
										adt.ajax.url( 'AJAX_Activity?aID=' + aID + '&uID=' + uID + '&glc=' + glc + '&freeOutF=' + freeOutF + '&pID=' + actpID ).load( act_CB );
									} 

 				).fail(function(jx, ts, er) { if(!jx || !jx.status || jx.status != 200) { oae('dosCls.AJAX_DeleteActivity', jx, ts, er); }	 });
		}
	}



	if( !dObj.cnF )	// NOT
	{
		$gDOS.modal('hide');
// ---
		$gDOS.find('.gDosBlkContent').hide();

		$gDOS.find('.dNotesHS').html('<div class="noNotes">No notes</div>');	// <-- Notes only!!!

		$gDOS.find('.gDosBlk').find('.gDosHdr').find('.itemCnt').text( 0 ).end().find('i.fas').removeClass('rotate');
	}

// ---
	tinymce.remove();	// --> removes ALL editors...		tinymce.remove( 'temMCE' );
// ---
}





