function dosAcb( evt, opF, aF, $r, rd, tde )	// outreachProjectsFlag, ActivityMonitorFlag...
{
	var id = evt.target.id, f = evt.target.checked, cID, pID, udtF=true;	// updateDataTableFlag...
//console.log('dosAcb:  id= ' + id + '  f= ' + f);	// + '  cID= ' + rd.gData.cID);

	if( opF ) { cID = rd.gData.cID;  	pID = outpID; } else { cID = rd.gData.cID;	 	pID = rd.projectID; }
//console.log('dosAcb:  id= ' + id + '  f= ' + f + '  cID= ' + cID + '  pID= ' + pID);


	switch( id )
	{
// ---
		case	'dosLEAD'	:	if( f ) { rd.status = 2; } else { rd.status = 1; }

								$gDOS.find('.modal-header').find('.hdr-cntrls > .callBtns .grp-dosA > ul > li > input#dosOPP')[0].checked  = false;

								$.getJSON( 	'AJAX_DossierOC', 

											{ aID:aID, uID:uID, cID:cID, name:'status', value:rd.status, hsASF:hsASF, hsUID:hsUID }

										).fail(function(jx, ts, er) { if(!jx || !jx.status || jx.status != 200) { oae('dosAcb.AJAX_DossierOC', jx, ts, er); } });

								break;
// ---
		case	'dosOPP'	:	if( f ) { rd.status = 3; } else { rd.status = 1; }

								$gDOS.find('.modal-header').find('.hdr-cntrls > .callBtns .grp-dosA > ul > li > input#dosLEAD')[0].checked = false;

								$.getJSON( 	'AJAX_DossierOC', 

											{ aID:aID, uID:uID, cID:cID, name:'status', value:rd.status, hsASF:hsASF, hsUID:hsUID } 

										).fail(function(jx, ts, er) { if(!jx || !jx.status || jx.status != 200) { oae('dosAcb.AJAX_DossierOC', jx, ts, er); } });

								break;


		case	'dosDNC'	:	if( f )
								{
									rd.gData.dncF = true;

									$gDOS.find('.modal-header').find('h4.modal-title').addClass('dncTtl');

									$gDOS.find('.modal-header').find('.callBtns').addClass('dnc');
								}
								else
								{
									rd.gData.dncF = false;

									$gDOS.find('.modal-header').find('h4.modal-title').removeClass('dncTtl');

									$gDOS.find('.modal-header').find('.callBtns').removeClass('dnc');
								}

								$.getJSON( 'AJAX_DNC', { aID:aID, uID:uID, cID:cID, dncF:f } ).fail(function(jx, ts, er) { if(!jx || !jx.status || jx.status != 200) { oae('dosAcb.AJAX_DNC', jx, ts, er); } });

								if( aF ) { adt.rows().every( function ( idx, tableLoop, rowLoop ) { var d = this.data();	if( d && d.gData && d.gData.cID == cID ) { 	d.gData.dncF = f; }	 } ); }

								break;


// --------
		case	'dosHSsync'	:	udtF = false;	hsSyncLead( cID, $r, rd, tde, true, opF, aF );		break;
// --------



		case	'dosDNE'	:	if( f ) { rd.gData.dneF = true; } else { rd.gData.dneF = false; }

								$.getJSON( 'AJAX_DNE', { aID:aID, uID:uID, cID:cID, pID:pID, dneF:f } ).fail(function(jx, ts, er) { if(!jx || !jx.status || jx.status != 200) { oae('dosAcb.AJAX_DNE', jx, ts, er); } });

								if( aF ) { adt.rows().every( function ( idx, tableLoop, rowLoop ) { var d = this.data();	if( d && d.gData && d.gData.cID == cID ) { 	d.gData.dneF = f; }	 } ); }

								break;


		case	'dosREM'	:	// console.log('dosAcb:  starting dREMcIDo.dREMcIDa= ' + dREMcIDo.dREMcIDa );		

								if( f )
								{
									$r.addClass('dosREM');	

									dREMcIDo.dREMcIDa.push( cID );
//console.log('dosAcb:  ending dREMcIDo.dREMcIDa= ' + dREMcIDo.dREMcIDa );  
								}
								else
								{
									$r.removeClass('dosREM');
//console.log('dosAcb:  starting dREMcIDo.dREMcIDa= ' + dREMcIDo.dREMcIDa );	

									var idx = dREMcIDo.dREMcIDa.indexOf( cID );
//console.log('dosAcb:  idx= ' + idx );
									if( idx > -1 )
									{
										dREMcIDo.dREMcIDa.splice(idx, 1);
									}
//console.log('dosAcb:  ending dREMcIDo.dREMcIDa= ' + dREMcIDo.dREMcIDa );	
								}	// else
	}	// switch



	if( udtF && tde && rd )
	{
		if( opF )
		{
			opdt.row( tde ).data( rd ).draw(false);		// do NOT reset pagination!!
		}
/* ONLY applies to opF   See dosCls for aF processing...
		else if( aF )
		{
			adt.row( tde ).data( rd ).draw(false);		// do NOT reset pagination!!
		}
*/
	}
}	// dosAcb





function hsSyncLead( cID, $r, rd, tde, dosF, opF, aF )
{
//console.log('hsSyncLead:  cID= ' + cID + '  dosF= ' + dosF + '  opF= ' + opF + '  aF= ' + aF );

	winWait( 'hsSyncLead' );

	$.getJSON( 'HubSpotSyncLead', { aID:aID, uID:uID, cID:cID, syncF:true }, 

					function(jsn) { 
// console.log('hsSyncLead:  HubSpotSyncLead.jsn= ' + JSON.stringify(jsn));

									if( jsn && jsn.sF && jsn.hsID )
									{
										clearWinWait('hsSyncLead');

										rd.gData.hsAID 	= jsn.hsAID;
										rd.gData.hsID 	= jsn.hsID;

// --- Refresh Dossier...
										if( $gDOS.find('.dNotesBlk').find('i.fas').hasClass('rotate')	) 	// contents visible
										{
											$gDOS.find('.dNotesBlk').find('i.fas').trigger('click');		// hide contents...
										}

										$.getJSON( 'AJAX_Dossier', { aiF:aiF, glc:glc, aID:aID, uID:uID, hsUID:hsUID, cID:cID, noF:rd.gData.noF, incID:rd.gData.incID, hspsrF:true }, function(j) { j.esID = rd.gData.esID;		dosCB('hsSyncLead', j, cID, tde, rd); }).fail(function(jx, ts, er) { oae('hsSyncLead.AJAX_Dossier', jx, ts, er); });
// ---

										setTimeout(function() { pmp('Synchronized', { clsTO:2000 }); }, 400);

// ---
	if( tde && rd )
	{
		if( opF )
		{
			opdt.row( tde ).data( rd ).draw(false);		// do NOT reset pagination!!
		}
/* ONLY applies to opF   See dosCls for aF processing...
		else if( aF )
		{
			adt.row( tde ).data( rd ).draw(false);	// do NOT reset pagination!!
		}
*/
	}
// ---
									}

									else if( jsn && jsn.msg )
									{
										clearWinWait('hsSyncLead');

										setTimeout(function() { pmp( jsn.msg ); }, 400);
									}

									else
									{
										oe('hsSyncLead.HubSpotSyncLead', '!jsn || !jsn.sF || !jsn.hsID');
									} 
				})

		.fail(function(jx, ts, er) { if(!jx || !jx.status || jx.status != 200) { oae('hsSyncLead.HubSpotSyncLead', jx, ts, er); } });
}





