//console.log('dcBtnOCs:  rd= ' + JSON.stringify(rd) );

	var pID=0, pTtl='', apF=false, dt = Date.now() + tzOsMS;

	if( rd.gData.pID ) { pID = rd.gData.pID;  pTtl = $('#outSB' + pID).text(); } else if( rd.projectID ) { pID = rd.projectID;  pTtl = rd.project;  apF=true; }

