function opdtOC( evt, tde, npf )		// nextPrevFlag, next(page)Flag		npf
{
	if( !npf ) { npf = false; }
//	if( !nextPageF ) { nextPageF = false; }

//console.log( 'opdtOC:  npf= ' + npf );		// + '  nextPageF= ' + nextPageF);

//console.log( 'opdtOC;  $(evt.target).get(0).tagName= ' + $(evt.target).get(0).tagName );
//console.log( 'opdtOC:  evt.target.id= ' + evt.target.id );
//console.log( 'opdtOC:  cIDflag= ' + cIDflag );

	var rd = opdt.row( tde ).data(), cID = rd.cID, pID = rd.gData.pID, $e = $(evt.target), neF;
//console.log( 'opdtOC:  rd= ' + JSON.stringify(rd) );
//console.log( 'opdtOC:  cID= ' + cID + '  pID= ' + pID);

	switch( $e.get(0).tagName.toUpperCase() )
	{
		case 'INPUT'	:	var id = evt.target.id;

								if( id == 'samc' )
								{
									if( $e.is(':checked') )
									{
										rd.gData.selF = 1;

										outSelcIDs  = '';	// reset...

										outSelcIDsA = [];	// reset...

										outSelcIDsNotOwnerA = [];	// reset...
									}
									else
									{
										rd.gData.selF = 0; 
									}
								}

								else if( id == 'sadnc' ) { neF = true;		let dncF = false, em = rd.email;	 if( $e.is(':checked') ) { dncF = true; }  rd.gData.dncF = dncF;  	if( dncF ) { $e.parent().parent().find('td span.ce').addClass('dnc').text('Do not contact'); } else { if( !em.length ) { em = '&nbsp;'; }  		if( rd.gData.esID == -2 ) { em = '<span class="fa fa-circle emUV">&nbsp;</span>' + em; } else { em = '<span class="fa fa-circle emV">&nbsp;</span>' + em; }			$e.parent().parent().find('td span.ce').removeClass('dnc').html( em ); }		$.getJSON( 'AJAX_DNC', { aID:aID, uID:uID, cID:cID, dncF:dncF } ).fail(function(jx, ts, er) { if(!jx || !jx.status || jx.status != 200) { oae('opdtOC.AJAX_DNC', jx, ts, er); } }); 	}

							 	else if( id == 'sadne' ) { neF = true;		let dneF = false, em = rd.email;	 if( $e.is(':checked') ) { dneF = true; }  rd.gData.dneF = dneF;	$.getJSON( 'AJAX_DNE', { aID:aID, uID:uID, cID:cID, pID:pID, dneF:dneF } ).fail(function(jx, ts, er) { if(!jx || !jx.status || jx.status != 200) { oae('opdtOC.AJAX_DNE', jx, ts, er); } });  }

							break;

		default			:	
// ---
							if( glc )
							{
								while( $e.get(0).tagName.toUpperCase() != 'TD' ) { if( $e.hasClass('cBox') ) { return; }	$e = $e.parent(); }

								if( $e.hasClass('ldsScore') )
								{
									if( $e.find('span.noData').hasClass('upgrd') )		// else if( $e.find('span.noData').hasClass('upgrd') )
									{
										reqUpGrd( 'opdtOC' );

										return;
									}
								}
							}
// ---

							while( $e.get(0).tagName.toUpperCase() != 'TR' ) { if( $e.hasClass('cBox') ) { return; }	$e = $e.parent(); }	 	

							dos( $e, rd, cID, tde, false, npf );

							$e.parent().find('tr.dosSel').removeClass('dosSel');	$e.addClass('dosSel');		
	}

// ---
	if( neF )
	{
		emDDcntrs( null, true );	// cntrsOnlyFlag...
	}
// ---
}






