function TglDosHdr( evt )
{
//console.log('TglDosHdr:  ');

	let $e = $(evt.target), cntr = 0, notesF;

	while( !$e.hasClass('gDosBlk') && cntr < 4 )
	{
		$e = $e.parent();
	}
//console.log('TglDosHdr:  cntr= ' + cntr + '  $e.length= ' + $e.length);


	if( $e.length == 1 && $e.hasClass('gDosBlk') )
	{
		$i = $e.find('.gDosHdr').find('> i.fas');
//console.log('TglDosHdr:  $i.length= ' + $i.length);

		if( $i && $i.length == 1 )
		{
// ---
	if( $e.hasClass('dNotesBlk') ) { notesF = true; }
//console.log('TglDosHdr:  notesF= ' + notesF);
// ---
//console.log('TglDosHdr:  $i.hasClass("rotate")= ' + $i.hasClass("rotate"));

			if( $i.hasClass('rotate') )	// switching from content visible to content hidden so switch to angle down...
			{
/*
				if( notesF )
					$e.find('.gDosBlkContent').slideUp(400);	//.hide();	// .slideUp(400);	// .hide(400);
				else
					$e.find('.gDosBlkContent').hide();			//.hide();	// .slideUp(400);	// .hide(400);
*/
				$e.find('.gDosBlkContent').slideUp();			//.hide();	// .slideUp(400);	// .hide(400);

				$i.removeClass('rotate');
			}
			else
			{
/*
				if( notesF )
					$e.find('.gDosBlkContent').slideDown(400);	//.show();	// .slideDown(400);	// .show(400);
				else
					$e.find('.gDosBlkContent').show();			//.show();	// .slideDown(400);	// .show(400);
*/
				$e.find('.gDosBlkContent').slideDown();		//.show();	// .slideDown(400);	// .show(400);

				$i.addClass('rotate');	// switching from content hidden to content visible so switch to angle up...
			}
		}
	}
}




