function aiPingUCD( cBy, o )
{
	try
	{
		if( !o ) { o = {}; }

		if( !aiF ) { clearWinWait('aiPingUCD');		return; }
	}
	catch(er)
	{
		oe( 'aiPingUCD.catch', er.message);
	}
}








function aiPingLCD( cBy, o )	// o.statusF
{
	try
	{
		if( !o ) { o = {}; }

		if( $gDOS ) { $gDOS.find('.dosAI-dd').find('> .aiEmpRsrch').removeClass('hl'); }

// ---
		if( !aiF ) { clearWinWait('aiPingLCD');		return; }
// ---



// ========================
		if( aiF && !o.statusF )
		{
			aiSessionNextDos( 'aiPingLCD' );
		}
// ========================





// ---
//		if( !dObj.IncID || !dObj.aiLCDobj || !dObj.aiLCDobj.IncID || dObj.IncID != dObj.aiLCDobj.IncID || !dObj.cID || !dObj.aiLCDobj.cID  || dObj.cID != dObj.aiLCDobj.cID )
		if( !dObj.aiLCDobj || !dObj.cID || !dObj.aiLCDobj.cID  || dObj.cID != dObj.aiLCDobj.cID )
		{
//console.log('aiPingLCD:  CLEAR  for dObj.IncID' + dObj.IncID + '  and dObj.aiLCDobj= ' + dObj.aiLCDobj + '  and dObj.aiLCDobj.IncID= ' + (dObj.aiLCDobj ? dObj.aiLCDobj.IncID : dObj.aiLCDobj) + '  and dObj.cID= ' + dObj.cID + '  and dObj.aiLCDobj.cID= ' + (dObj.aiLCDobj ? dObj.aiLCDobj.cID : dObj.aiLCDobj));

			dObj.aiLCDobj 	= null;		// clear <<<<<<<<<<<<<<<<<<<
			dObj.eCN 		= null;		// clear
		}
// ---


		var IncID = (dObj.IncID ? dObj.IncID : (dObj.rd && dObj.rd.gData && dObj.rd.gData.incID ? dObj.rd.gData.incID : 0));
//console.log('aiPingLCD:  cBy= ' + cBy + '  IncID= ' + IncID + '  dObj.IncID= ' + dObj.IncID + '  dObj.email= ' + dObj.email);

		if( dObj.aiLCDobj && dObj.aiLCDobj.cID != dObj.cID ) { dObj.aiLCDobj = null; }

		if( ( dObj.aiLCDobj && dObj.aiLCDobj.status == 1 && dObj.aiLCDobj.RCAdoneF ) || !dObj.email || dObj.email.indexOf('@') == -1 )		//  || !IncID )	// <-- see below...
		{
			if( dObj.aiLCDobj && dObj.aiLCDobj.status == 1 && dObj.aiLCDobj.RCAdoneF )
			{
				$gDOS.find('.callBtns').addClass( 'lcdF' );

				if( dObj.aiLCDobj.NoRCAF ) { $gDOS.find('.callBtns').addClass( 'NoRCAF' ); } else { $gDOS.find('.callBtns').removeClass( 'NoRCAF' ); }
			}
//console.log('aiPingLCD:  (dObj.aiLCDobj.status == 1 && dObj.aiLCDobj.RCAdoneF) || !dObj.email  -->  DONE RETURN');	// <<<<<<<<<<<<<<<<<<

			return;
		}


		if( !dObj.aiLCDobj ) { dObj.aiLCDobj = { status:0, retryCntr:0, statusCntr:0, statusRetryCntr:0, cID:dObj.cID, IncID:IncID, webDomID:0, webDom:'', eCN:'', ts:Date.now() }; }	// <<<<<<<<<<<<<<<<


		$.post( 'aiPing', { lcdF:true, statusF:(o.statusF ? true : false), aID:aID, uID:uID, cID:dObj.cID, IncID:IncID, retryCntr:dObj.aiLCDobj.retryCntr },	// <<<<<<<<<<<<<<<<<<<<<<<<<<<

					function( jsn ) 
					{ 
//console.log('aiPingLCD.aiPing:  jsn= ' + (jsn ? JSON.stringify(jsn) : jsn));

						if( !jsn || !jsn.sF ) 
						{
							dObj.aiLCDobj.status = 9; 

							dObj.aiLCDobj.err = '!jsn || !jsn.sF';

							clearWinWait('aiPingLCD: !jsn || !jsn.sF');		// <<<<<<<<<<<<<<<<<

							return;
						}

// ---
				if( !jsn.cID || !dObj || !dObj.cID || jsn.cID != dObj.cID )
				{
//console.log('aiPingLCD:  !jsn.cID || !dObj || !dObj.cID || jsn.cID != dObj.cID  -->  RETURN  for jsn.cID= ' + jsn.cID + '  and dObj.cID= ' + (dObj ? dObj.cID : dObj));

					clearWinWait('aiPingLCD: jsn.cID != dObj.cID');		// <<<<<<<<<<<<<<<<<

					return;
				}
// ---


// ---
				if( !IncID )
				{
					if( jsn.IncID )
					{
						dObj.aiLCDobj.IncID = jsn.IncID;

						dObj.IncID = jsn.IncID;
					}
				}
// ---


						dObj.aiLCDobj.status 	= ( jsn.status && jsn.status > 0 ? jsn.status : 0 );		// <<<<<<<<<<<<<<<<

				dObj.aiLCDobj.NoRCAF 	= ( dObj.aiLCDobj.status == 1 && jsn.RCAdoneF && jsn.NoRCAF ? true : false );	// NO Recent Company Announcement

				dObj.aiLCDobj.RCAdoneF 	= ( dObj.aiLCDobj.status == 1 && jsn.RCAdoneF ? true : false );


						dObj.aiLCDobj.webDomID 	= ( jsn.webDomID && jsn.webDomID > 0 ? jsn.webDomID : 0 );	// <<<<<<<<<<<<<<<<

						dObj.aiLCDobj.webDom 	= ( jsn.webDom ? jsn.webDom   : '' );		// <<<<<<<<<<<<<<<<

						dObj.aiLCDobj.eCN 		= ( jsn.ECN    ? jsn.ECN      : '' );		// <<<<<<<<<<<<<<<<
// ---
						if( dObj.aiLCDobj.eCN ) { dObj.eCN = dObj.aiLCDobj.eCN; } 			// <<<<<<<<<<<<<<<<
// ---

						if( dObj.aiLCDobj.status == 1 && dObj.aiLCDobj.RCAdoneF )			// <<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<
						{
							$gDOS.find('.callBtns').addClass( 'lcdF' );

							if( dObj.aiLCDobj.NoRCAF ) { $gDOS.find('.callBtns').addClass( 'NoRCAF' ); } else { $gDOS.find('.callBtns').removeClass( 'NoRCAF' ); }
						}

						else
						{
							if( dObj.aiLCDobj.status < 1 || !dObj.aiLCDobj.RCAdoneF )	// 0 or -1 		<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<
							{
								if( !dObj.aiLCDobj.statusCntr ) { dObj.aiLCDobj.statusCntr = 0; }

								dObj.aiLCDobj.statusCntr++;

								if( dObj.aiLCDobj.statusCntr < 30 )		// 20
								{
									setTimeout(function(){ aiPingLCD( 'aiPingLCD', { statusF:true } ); }, 5000);
								}
								else
								{
									oe('aiPingLCD', 'statusCntr= ' + dObj.aiLCDobj.statusCntr + '  for IncID= ' + IncID + '  and  dObj.cID= ' + dObj.cID, true, true);		// silentFlag, sendGregEmailFlag
								}
							}

						}	// else...

					},	// fn...

					'json'

				).fail(function(jx, ts, er) { 
												dObj.aiLCDobj.status = 9;	// <<<<<<<<<<<<<<<<

												dObj.aiLCDobj.err = er.message;

												oae('aiPingLCD.aiPing', jx, ts, er, false, true); 	// oae(fn, jx, ts, er, sf, sgef)
			});
	}
	catch(er)
	{
		if( dObj && dObj.aiObj ) { dObj.aiObj.tpyArr = []; }	// circular BS!!!!!!!!!!!!!!!!!!!!!!!			statusF

		if( dObj && dObj.aiLCDobj )
		{
			dObj.aiLCDobj.status = 9;

			dObj.aiLCDobj.err = er.message;
		}

		oe( 'aiPingLCD.catch', er.message + '  for dObj= '  + (dObj ? JSON.stringify(dObj) : dObj), false, true); 	// oae(fn, jx, ts, er, sf, sgef));
	}
}




