function aiPingLCDpp( cBy, o, dataObj )	// { cID:cID, IncID:IncID }, nextRowData		called by aiPingLCD...
{
	var errMsg;
	try
	{
		if( !o ) { o = {}; }
//console.log('aiPingLCDpp:  cBy= ' + cBy + '  o.cID= ' + o.cID + '  o.IncID= ' + o.IncID + '  o.statusF= ' + o.statusF + '  dObj.aiPingLCD2F= ' + dObj.aiPingLCD2F);
//console.log('aiPingLCDpp:  o.nrd= ' + (o.nrd ? JSON.stringify(o.nrd) : o.nrd));	// should match dataObj below...
//console.log('aiPingLCDpp:  o= ' + JSON.stringify(o));

// --
		if( dObj.aiPingLCD2F && !o.statusF ) { return; }	// KEEP as dObj!!!!

		dObj.aiPingLCD2F = true;	// prevent repeats...	KEEP as dObj!!!!
// --

		if( !dataObj && o.nrd && !o.statusF )
		{
			dataObj = o.nrd;		// NO!!!	aiSessionObj.dataMap.get( 'cID'+ o.cID );		// should match o.nrd above... 	<<<<<<<<<<<<<<<
		}

		if( !dataObj ) { dataObj = { cID:o.cID, IncID:(o.IncID ? o.IncID : 0) }; }
//console.log('aiPingLCDpp:  starting dataObj= ' + (dataObj ? JSON.stringify(dataObj) : dataObj));


		if( dataObj.aiLCDobj && dataObj.aiLCDobj.status == 1 && dataObj.aiLCDobj.RCAdoneF )
		{
//console.log('aiPingLCDpp:  AAA  status == 1 && RCAdoneF  -->  aiPingLCDppFinal  RETURN');

			aiPingLCDppFinal( errMsg, o, dataObj );

			return;
		}


		if( !dataObj.aiLCDobj ) { dataObj.aiLCDobj = { status:0, retryCntr:0, statusCntr:0, statusRetryCntr:0, cID:dataObj.cID, IncID:dataObj.IncID, webDomID:0, webDom:'', eCN:'', ts:Date.now() }; }		// <<<<<<<<<<<<<<<<

		aiSessionObj.dataMap.set( 'cID'+ o.cID, dataObj );	
//console.log('aiPingLCDpp: dataObj.aiLCDobj.retryCntr= ' + dataObj.aiLCDobj.retryCntr);


//console.log('aiPingLCDpp:  starting dataObj= '  + (dataObj ? JSON.stringify(dataObj) : dataObj));

		$.post( 'aiPing', { lcdF:true, aiNextF:true, statusF:(o.statusF ? true : false), aID:aID, uID:uID, cID:dataObj.cID, IncID:dataObj.IncID, retryCntr:dataObj.aiLCDobj.retryCntr },	// <<<<<<<<<<<<<<<<<<<<<<<<<<<

					function( jsn ) 
					{
//console.log('aiPingLCDpp.aiPing:  jsn= ' + (jsn ? JSON.stringify(jsn) : jsn));

						if( !jsn || !jsn.sF ) 
						{
//console.log('aiPingLCDpp.aiPing:  !jsn || !jsn.sF  -->  RETURN');

							errMsg = '!jsn || !jsn.sF';

							aiPingLCDppFinal( errMsg, o, dataObj );

							return;
						}

// ---
						if( !jsn.cID || !dataObj || !dataObj.cID || jsn.cID != dataObj.cID )
						{
//console.log('aiPingLCDpp:  !jsn.cID || !dataObj || !dataObj.cID || jsn.cID != dataObj.cID  -->  RETURN  for jsn.cID= ' + jsn.cID + '  and dataObj.cID= ' + (dataObj ? dataObj.cID : dataObj));

							errMsg = '!jsn.cID || !dataObj || !dataObj.cID || jsn.cID != dataObj.cID  -->  for jsn.cID= ' + jsn.cID + '  and dataObj.cID= ' + (dataObj ? dataObj.cID : dataObj);

							aiPingLCDppFinal( errMsg, o, dataObj );

							return;
						}
// ---


// ---
						if( !dataObj.IncID && jsn.IncID )
						{
							dataObj.aiLCDobj.IncID = jsn.IncID;

							dataObj.IncID = jsn.IncID;
						}



						dataObj.aiLCDobj.status 	= ( jsn.status && jsn.status > 0 ? jsn.status : 0 );		// <<<<<<<<<<<<<<<<

						dataObj.aiLCDobj.NoRCAF 	= ( dataObj.aiLCDobj.status == 1 && jsn.RCAdoneF && jsn.NoRCAF ? true : false );	// NO Recent Company Announcement

						dataObj.aiLCDobj.RCAdoneF 	= ( dataObj.aiLCDobj.status == 1 && jsn.RCAdoneF ? true : false );

						dataObj.aiLCDobj.webDomID 	= ( jsn.webDomID && jsn.webDomID > 0 ? jsn.webDomID : 0 );	// <<<<<<<<<<<<<<<<

						dataObj.aiLCDobj.webDom 	= ( jsn.webDom ? jsn.webDom   : '' );		// <<<<<<<<<<<<<<<<

						dataObj.aiLCDobj.eCN 		= ( jsn.ECN    ? jsn.ECN      : '' );		// <<<<<<<<<<<<<<<<
// ---
						if( dataObj.aiLCDobj.eCN ) { dataObj.eCN = dataObj.aiLCDobj.eCN; } 		// <<<<<<<<<<<<<<<<
// ---
//console.log('aiPingLCDpp:  ending dataObj= '  + (dataObj ? JSON.stringify(dataObj) : dataObj));


						if( dataObj.aiLCDobj.status == 1 && dataObj.aiLCDobj.RCAdoneF )			// <<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<
						{
//console.log('aiPingLCDpp.aiPing:  BBB  status == 1 && RCAdoneF  -->  aiPingLCDppFinal()  RETURN');

							aiPingLCDppFinal( errMsg, o, dataObj );

							return;
						}

						else
						{
							if( dataObj.aiLCDobj.status < 1 || !dataObj.aiLCDobj.RCAdoneF )	// 0 or -1 		<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<
							{
								if( !dataObj.aiLCDobj.statusCntr ) { dataObj.aiLCDobj.statusCntr = 0; }

								dataObj.aiLCDobj.statusCntr++;

								if( dataObj.aiLCDobj.statusCntr < 30 )		// 20
								{
									setTimeout(function(){ aiPingLCDpp( 'aiPingLCDpp', { cID:o.cID, IncID:o.IncID, statusF:true }, dataObj ); }, 5000);
								}
								else
								{
									errMsg = 'statusCntr= ' + dataObj.aiLCDobj.statusCntr + '  for jsn.IncID= ' + jsn.IncID + '  and  o.cID= ' + o.cID;
	
									aiPingLCDppFinal( errMsg, o, dataObj );

									return;
								}
							}

						}	// else...

					},	// fn...

					'json'

				).fail(function(jx, ts, er) { 
												dataObj.aiLCDobj.status = 9;	// <<<<<<<<<<<<<<<<

												dataObj.aiLCDobj.err = er.message;

												oae('aiPingLCDpp.aiPing', jx, ts, er, true, true); 	// oae(fn, jx, ts, er, sf, sgef)

												aiPingLCDppFinal( errMsg, o, dataObj );		// 
			});
	}
	catch(er)
	{
//console.log('aiPingLCDpp.catch:  er= ' + er.message + '  for dataObj= '  + (dataObj ? JSON.stringify(dataObj) : dataObj));

		oe( 'aiPingLCDpp.catch', errMsg + '  for dataObj= ' + (dataObj ? JSON.stringify(dataObj) : dataObj), true, true);	// silentFlag, sendGregEmailFlag

		errMsg = (errMsg ? errMsg + '  |  ' : '') + er.message;

		if( dataObj && dataObj.aiLCDobj )
		{
			dataObj.aiLCDobj.status = 9;

			dataObj.aiLCDobj.err = errMsg;
		}

		aiPingLCDppFinal( errMsg, o, dataObj );
	}
}



function aiPingLCDppFinal( errMsg, o, dataObj )
{
	try
	{
		if( dataObj && o.cID )
		{
			var ExitF;		if( !dataObj.gData || dataObj.aiS3F || dataObj.liveStatus ) { ExitF = true; }
//console.log('aiPingLCDppFinal:  dataObj.gData= ' + dataObj.gData + '  dataObj.aiS3F= ' + dataObj.aiS3F + '  dataObj.liveStatus= ' + dataObj.liveStatus + '  --> ExitF= ' + ExitF);
//console.log('aiPingLCDppFinal:  ExitF= ' + ExitF);

			if( ExitF )
			{
				aiSessionObj.dataMap.delete( 'cID'+ o.cID );
			}

			else	//if( !ExitF )	// NOT
			{
				aiSessionObj.dataMap.set( 'cID'+ o.cID, dataObj );	// <<<<<<<<<<<<<<<<<		//	aiSessionObj.dataMap.delete( 'cID'+ o.cID )

				if( !errMsg && dataObj.aiLCDobj && dataObj.aiLCDobj.status == 1 && dataObj.aiLCDobj.RCAdoneF )
				{
//console.log('aiPingLCDppFinal:  starting aiSessionObj.aiNoINmodeF= ' + aiSessionObj.aiNoINmodeF + '  and dObj.aiObj.IEEF= ' + (dObj.aiObj ? dObj.aiObj.IEEF : dObj.aiObj));
					if( !aiSessionObj.aiNoINmodeF && dObj.aiObj && dObj.aiObj.IEEF ) { aiSessionObj.aiNoINmodeF = true; }
//console.log('aiPingLCDppFinal:  ending aiSessionObj.aiNoINmodeF= ' + aiSessionObj.aiNoINmodeF + '  for dObj.aiObj.IEEF= ' + (dObj.aiObj ? dObj.aiObj.IEEF : dObj.aiObj));
//console.log('aiPingLCDppFinal:  dataObj.aiObj.aiNoINmodeDoneF= ' + (dataObj.aiObj ? dataObj.aiObj.aiNoINmodeDoneF : dataObj.aiObj));

					if( aiSessionObj.aiNoINmodeF && ( !dataObj.aiObj || !dataObj.aiObj.aiNoINmodeDoneF ) )	// ONLY gen emails if aiSessionObj.aiNoINmodeF; otherwise, stop after generating next LCD...
					{
						aiPostPingLCDpp( 'aiPingLCDppFinal', o, dataObj );	// <<<<<<<<<<<<<<<<<<<<
					}
				}
			}
		}
	}
	catch(er)
	{
		oe( 'aiPingLCDppFinal.catch', er.message + '  for dataObj= ' + (dataObj ? JSON.stringify(dataObj) : dataObj), true, true);	// silentFlag, sendGregEmailFlag

		errMsg = (errMsg ? errMsg + '  |  ' : '') + er.message;
	}
	finally
	{
		if( errMsg )
		{
			oe( 'aiPingLCDppFinal.finally', errMsg + '  for dataObj= ' + (dataObj ? JSON.stringify(dataObj) : dataObj), true, true);		// silentFlag, sendGregEmailFlag
		}
	}
}




