function aiStatus( cBy )
{
//console.log('aiStatus:  cBy= ' + cBy + '  aiStatusCntr= ' + aiStatusCntr + '  dObj.aiINmodeF= ' + dObj.aiINmodeF + '  dObj.aiNoINmodeF= ' + dObj.aiNoINmodeF + '  dObj.aiObj.doneF= ' + (dObj.aiObj ? dObj.aiObj.doneF : dObj.aiObj) );
// ---
	if( aiStatusKillF  ) { clearWinWait('aiStatus.aiStatusKillF');	return; }	// <<<<<<<<<<< KEEP as manual failsafe!!!
// ---

	try
	{
		if( aiStatusTO ) { try { window.clearTimeout( aiStatusTO );		aiStatusTO = null; } catch(er){ aiStatusTO = null; } }


		chrome.runtime.sendMessage( ceID, { aiStatus:true, cID:dObj.cID },  // <<<<<<<<<<<<<<<<<<<<<

			function( rsp )
			{
//console.log('aiStatus:  rsp= ' + (rsp ? JSON.stringify(rsp) : rsp));

				if( chrome.runtime.lastError ) 
				{
					if( dObj && dObj.aiObj ) { dObj.aiObj.tpyArr = []; }	// circular BS!!!!!!!!!!!!!!!!!!!!!!!

					oe( 'aiStatus', 'chrome.runtime.lastError= ' + chrome.runtime.lastError.message + '  for dObj= '  + (dObj ? JSON.stringify(dObj) : dObj));

					return;
				}

				if( !rsp || !rsp.sF )
				{
					if( dObj && dObj.aiObj ) { dObj.aiObj.tpyArr = []; }	// circular BS!!!!!!!!!!!!!!!!!!!!!!!

					oe( 'aiStatus', '!rsp || !rsp.sF  for rsp= ' + (rsp ? JSON.stringify(rsp) : rsp) + '  and dObj= '  + (dObj ? JSON.stringify(dObj) : dObj));

					return;
				}


				if( !rsp.aiObj )
				{
					if( dObj && dObj.aiObj ) { dObj.aiObj.tpyArr = []; }	// circular BS!!!!!!!!!!!!!!!!!!!!!!!

					oe( 'aiStatus', '!aiObj  for rsp= ' + (rsp ? JSON.stringify(rsp) : rsp) + '  and dObj= '  + (dObj ? JSON.stringify(dObj) : dObj));

					return;
				}

// ---
//console.log('aiStatus:  rsp.aiObj= ' + rsp.aiObj);
//console.log('aiStatus:  rsp.aiObj= ' + (rsp.aiObj ? JSON.stringify(rsp.aiObj) : rsp.aiObj));

				if( dObj.aiObj )
				{
					dObj.aiObj = { ...dObj.aiObj, ...rsp.aiObj };	// shallow merge...
				}
				else
				{
					dObj.aiObj = rsp.aiObj;		// <<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<
				}
// ---
//console.log('aiStatus:  dObj.aiObj.doneF= ' + dObj.aiObj.doneF);
//console.log('aiStatus:  dObj.aiObj.err= '   + dObj.aiObj.err);


				if( dObj.aiObj.doneF )
				{
					if( dObj.aiINmodeF )
					{
						dObj.aiINmodeDoneF = true;
					}

					else if( dObj.aiNoINmodeF )
					{
						dObj.aiNoINmodeDoneF = true;
					}

					aiDOSpop2( 'aiStatus.doneF', null, { INrespF:true } );		// aiDOSpop( 'aiStatus.doneF', null, { INrespF:true } );	//	<<<<<<<<<<<<<<<<<<<<<<<<<<<<<
				}

				else if( dObj.aiObj.err )
				{
					aiStatusPunt( 'aiStatus: dObj.aiObj.err', { errF:true, err:dObj.aiObj.err } );

					clearWinWait('aiStatus.err');	// <<<<<<<<<<< KEEP!!!
				}

				else if( aiStatusCntr < 20 )	// 15  25
				{
					aiStatusCntr++;

					// ping ext for status & results...
					aiStatusTO = setTimeout(aiStatus, 3000);	// 5000	<<<<<<<<<<<<<<<<<<<
				}

				else
				{
					aiStatusPunt( 'aiStatus: aiStatusCntr', { } );

					clearWinWait('aiStatus.aiStatusCntr');		// <<<<<<<<<<< KEEP!!!
				}

			});
	}
	catch(er)
	{
		if( dObj && dObj.aiObj ) { dObj.aiObj.tpyArr = []; }	// circular BS!!!!!!!!!!!!!!!!!!!!!!!

		oe( 'aiStatus.catch', er.message + '  for dObj= '  + (dObj ? JSON.stringify(dObj) : dObj));
	}
}
