function aiEngageUpDwnOC( evt )
{
	var $e = $(evt.target);
//console.log('aiEngageUpDwnOC:  starting class= ' + $e.attr('class'));

	while( $e.hasClass('caret') ) { $e = $e.parent(); }
//console.log('aiEngageUpDwnOC:  ending class= ' + $e.attr('class'));


	var $blk = $e.parent();		while( $blk.get(0).tagName.toUpperCase() != 'LI' ) { $blk = $blk.parent(); }

	if( $e.hasClass('moveUp') )
	{
		var $p = $blk.prev(), $pp = $p.prev();
//console.log('aiEngageUpDwnOC:  $p.length= ' + $p.length + '$pp.length= ' + $pp.length  );

		if( $p.length )
		{
			$blk.fadeOut(function() { 

/* SAVE!!!
				if( !$pp.length ) { $blk.find('.aiPauseBG').addClass('hide');		$blk.find('.comment').addClass('hide'); }

				$p.find('.aiPauseBG').removeClass('hide');
// ---
		$p.find('.comment').removeClass('hide');
// ---
*/
				$blk.insertBefore( $p );   

				$blk.fadeIn(); 
			});
		}
	}

	else if( $e.hasClass('moveDwn') )
	{
		var $n = $blk.next(), $p = $blk.prev();

		if( $n.length )
		{
			$blk.fadeOut( function() { 

				$blk.insertAfter( $n );   

				$blk.fadeIn(); 
			});
		}
	}
}




