// SAVE!!!!!!!!!!!!
function aiPopSelPost( evt, o )
{
	if( !o ) { o = {}; }
//console.log('aiPopSelPost:  o= ' + JSON.stringify(o));
//console.log('aiPopSelPost:  o.IERF= ' + o.IERF);

// ---------
	if( o.IERF )
	{
//console.log('aiPopSelPost.IERF:  --> aiPopSelPostOC  RETURN');

		aiPopSelPostOC( 'aiPopSelPost.IERF', evt, o );

		return;
	}
// ---------

	var $posts;		// list of posts...

	if( o.ldPostF || o.npF || o.nrF ) 	// LeadPosts...
	{
		$posts = $('#aiDOSpop').find('.aiPopLdAct').find('.post');
	}
	else	// CompanyPosts...
	{
		$posts = $('#aiDOSpop').find('.aiPopEmpAct').find('.post');
	}

//console.log('aiPopSelPost:  $posts.length= ' + $posts.length);





	var h 	= '<div id="aiPopSelPost" class="mpop, aiPopSelPost">'	// <<<<<<<<<<<<<<<<<<<<<<<<<<

			+	'<div class="mpopTxt">'

			+		'<div class="popHdr"><span class="title">Select Post</span><button type="button" class="close"title="close">X</button></div>'	// <<<<<<<<<<<<<

			+ 		'<div class="block aiPopPosts">';


			if( $posts )
			{
				$posts.each( function(idx, elem) { 
													if( o.npF )
													{
														if( $(this).hasClass('npF') )
														{
															h += '<div class="post npF" title="select post">' + $(this).html() + '</div>';

															return false;	// exit...
														}
													}


													else if( o.cpnpF )
													{
														if( $(this).hasClass('cpnpF') )
														{
															h += '<div class="post cpnpF" title="select post">' + $(this).html() + '</div>';

															return false;	// exit...
														}
													}


													else if( o.cpnsF )
													{
														if( $(this).hasClass('cpnsF') )
														{
															h += '<div class="post cpnsF" title="select post">' + $(this).html() + '</div>';

															return false;	// exit...
														}
													}


													else
													{
														if( idx )
														{
															h += '<div class="divdr disabled"><span class="divider disabled"></span></div>';
														}

														h += '<div class="post" title="select post">' + $(this).html() + '</div>';
													}
						});	// .each

			}	// if $posts


			h +=	'</div>'

			+	'</div>';


			$.magnificPopup.open({
									items: {
											src: h, 	// can be a HTML string, jQuery object, or CSS selector
											type: 'inline'
										},

									fixedContentPos: false,
									fixedBgPos: true,
									preloader: false,

		//							midClick: true,
		// default					closeBtnInside: true,
		// default					closeOnBgClick: true,
		// default					overflowY: 'auto',

									enableEscapeKey: true,	// ( o.mdlFlag ? false : true),	// <<<<<<<<<<<<<<<<<<<<

									showCloseBtn:   false,	// o.shwClsBtn,
									closeOnBgClick: false,	// o.clsBgClk,

									removalDelay: 300,
									mainClass: 'my-mfp-zoom-in',	// 'my-mfp-zoom-in',	mainClass

									callbacks: {
												open: function() {  // this = Popup instance --> this.close()		$(this.contentContainer) --> jQry access to popup content h

														var $t = $(this.contentContainer);
//console.log('aiPopSelPostl.open:  $t.length= ' + $t.length);

//console.log('aiPopSelPostl.open:  $t.find(.aiPopPosts).find(.post).length= ' + $t.find('.aiPopPosts').find('.post').length);

//console.log('aiPopSelPostl.open:  $t.find(.hdr).find(.close).length= ' + $t.find('.hdr').find('.close').length);		

//console.log('aiPopSelPostl.open:  $t.html()= ' + $t.html());

														$t.find('.aiPopPosts').find('.post').off('click').on('click', function(evt) { aiPopSelPostOC( 'aiPopSelPostl.open', evt, o ); });	// <<<<<<<<<<<<<<<

														$t.find('.popHdr').find('.close').off('click').on('click', pmpCls);

													}	// open fn...

											// close: function() { return o.onClsFn; }		// pmpCls()
										}
							});
}	// aiPopSelPost






