function getAIoptionText( verCode )
{
// var optionsArr = ['DEF-SV', 'DEF-LV', 'DEF-LF', 'DEF-MF', 'DEF-SV-LF', 'DEF-SV-MF', 'DEF-LV-LF', 'DEF-LV-MF' ]

	var txt;		// Generate a more formal version

	switch( verCode )
	{
		case	'DEF-SV'	:	txt = 'Generate a shorter version';						break;
		case	'DEF-LV'	:	txt = 'Generate a longer version';						break;

		case	'DEF-LF'	:	txt = 'Generate a less formal version';					break;
		case	'DEF-MF'	:	txt = 'Generate a more formal version';					break;

		case	'DEF-SV-LF'	:	txt = 'Generate a shorter and less formal version';		break;
		case	'DEF-SV-MF'	:	txt = 'Generate a shorter and more formal version';		break;

		case	'DEF-LV-LF'	:	txt = 'Generate a longer and less formal version';		break;
		case	'DEF-LV-MF'	:	txt = 'Generate a longer and more formal version';		break;
	}
//console.log('getAIoptionText:  verCode= '   + verCode + '  -->  txt= ' + txt);

	return txt;
}





function getAIverText( verCode )
{
// var optionsArr = ['DEF-SV', 'DEF-LV', 'DEF-LF', 'DEF-MF', 'DEF-SV-LF', 'DEF-SV-MF', 'DEF-LV-LF', 'DEF-LV-MF' ]

	var txt;

	switch( verCode )
	{
		case	'DEF'		:	txt = 'Original email';							break;

		case	'DEF-SV'	:	txt = 'Original > shorter';						break;
		case	'DEF-LV'	:	txt = 'Original > longer';						break;

		case	'DEF-LF'	:	txt = 'Original > less formal';					break;
		case	'DEF-MF'	:	txt = 'Original > more formal';					break;

		case	'DEF-SV-LF'	:	txt = 'Original > shorter > less formal';		break;
		case	'DEF-SV-MF'	:	txt = 'Original > shorter > more formal';		break;

		case	'DEF-LV-LF'	:	txt = 'Original > longer > less formal';		break;
		case	'DEF-LV-MF'	:	txt = 'Original > longer > more formal';		break;
	}

//console.log('getAIverText:  verCode= '   + verCode + '  -->  txt= ' + txt);

	return txt;
}




function getAIoptions( mceCls, cntrlTxt, api )		// AI_226138_1764089458579_3_IEEPPR_MCE			// cntrlTxt --> 'Gen-AI Options'
{
//console.log('getAIoptions:  mceCls= '   + mceCls + '  cntrlTxt= ' + cntrlTxt + '  api= ' + api + '  dObj.aiObj.s3F= ' + dObj.aiObj.s3F);

	try { clearTimeout( aiOptBtnTO );	aiOptBtnTO = null; } catch(er) { }		// <<<<<<<<<<<<< clear any pending TO...

/*
DEFAULT							2 para with up to 3 sentences each
DEFAULT-SV (SHORTER VERSION)	1 para with up to 3 sentences each
DEFAULT-LV (LONGER VERSION)		2 para with up to 4 sentences each

DEFAULT							Employ a friendly and informal, but professional, tone.
DEFAULT-MF (MORE FORMAL)		Employ a professional tone.
DEFAULT-LF (LESS FORMAL)		Employ a friendly and informal tone.


DEFAULT-SV-MF
DEFAULT-SV-LF

DEFAULT-LV-MF
DEFAULT-LV=LF
*/

	var optionsArr = ['DEF-SV', 'DEF-LV', 'DEF-LF', 'DEF-MF', 'DEF-SV-LF', 'DEF-SV-MF', 'DEF-LV-LF', 'DEF-LV-MF' ];

// ----------------
	if( !dObj.aiObj.editors ) { dObj.aiObj.editors = {}; }	// init if not already exists...

	var editorObj = dObj.aiObj.editors[ mceCls ];	// editorObj= {"verArr":["DEF"],"versionsObj":{"DEF":{"ver":"DEF","verTxt":"Original email","sub":"I like your post on Physical AI and collaborative intelligence","bdy":"<p>Greg,</p>\n<p>Great post on Physical AI and the shift towards collaborative intelligence. Your insights from years with NVIDIA and work alongside cutting-edge minds highlight the real progress happening in AI perception, reasoning, and interaction. It is exciting to see how these advances will redefine human and AI teamwork in powerful new ways.</p>"}}}
//console.log('getAIversions:  editorObj= ' + (editorObj ? JSON.stringify(editorObj) : editorObj));

	var verArr = [];	if( editorObj ) { verArr = editorObj.verArr; }		// , versionsObj = editorObj.versionsObj;
//console.log('getAIoptions:  verArr.length= ' + verArr.length);
//console.log('getAIoptions:  verArr= ' + verArr);



	var items = [];

	for(var i = 0; i < optionsArr.length; i++)
	{
		const verCode = optionsArr[i];		// KEEP as a const !!!!!!
//console.log('getAIoptions:  i= ' + i + ' --> verCode= ' + verCode);

		if( verArr.includes( verCode ) ) { continue; }	// <<<<<<<<<<<<<<<<<<<<<<

		const optionText = getAIoptionText( verCode );	// KEEP as a const !!!!!!
//console.log('getAIoptions:  i= ' + i + ' --> verCode= ' + verCode + '  --> optionText= ' + optionText);


		var item = {
					type: 'menuitem',

					text: ('' + optionText),	// 'Generate a more formal version',

					onAction: (api) => {		// executed each time a user selects option from button's drop-down list...

						onSelAIoption( ('' + mceCls), ('' + cntrlTxt), ('' + verCode) );
					},

					onSetup: (api) => {			// setup for drop-down list option...

							return () => {};	// REQUIRED!!!   cleanup function run upon teardown...
					}
			};

			items.push( item );		// <<<<<<<<<<<<<<<<<<<

	}	// for...
//console.log('getAIoptions:  post-for --> items= ' + (items ? JSON.stringify(items) : items));


	if( !items.length )
	{
		var item = {
					type: 'menuitem',

					text: ('All email versions have been generated'),

					onAction: (api) => {		// executed each time a user selects option from button's drop-down list...

						// onSelAIoption( ('' + mceCls), ('' + cntrlTxt), ('' + verCode) );
					},

					onSetup: (api) => {			// setup for drop-down list option...

							return () => {};	// REQUIRED!!!   cleanup function run upon teardown...
					}
			};

		items.push( item );		// <<<<<<<<<<<<<<<<<<<
	}

	return items;	// <<<<<<<<<<<<<<<<<<<

}	// getAIoptions...








