function onSelAIoption( mceCls, cntrlTxt, selVer )		// mceCls = AI_221568_1761930363531_3_IEECR_MCE  	selVer = DEF-LF
{
//console.log('onSelAIoption:  mceCls= '   + mceCls + '  cntrlTxt= ' + cntrlTxt + '  selVer= '   + selVer);

	// 1st, record current editor content...
	onSelAIsave( 'onSelAIoption', mceCls, cntrlTxt );	// <<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<

	// Now, generate selected aiOption
//console.log('onSelAIoption:  Now, generate selected aiOption');

	var editorObj = dObj.aiObj.editors[ mceCls ];

		if( editorObj )
		{
			editorObj.selVer = selVer;	// <<<<<<<<<<<<<<<<<<<<<<<<<
		}

	var id  =  mceCls.replace( '_MCE', '' );		// AI_221568_1761930363531_3_IEECR_MCE  -->  AI_221568_1761930363531_3_IEECR

	var n   = id.lastIndexOf( '_' );

	var etc = id.substring( n+1 );					// AI_221568_1761930363531_3_IEECR  -->  IEECR

	var etcVer = selVer.replace( 'DEF-', '' );		// selVer = DEF-LF	--> 'LF' (less formal)

//console.log('onSelAIoption:  id= '   + id + '  etc= ' + etc + '  etcVer= '   + etcVer);

// NO!!!!	etc = etc + selVer.replace( 'DEF', '' );	// selVer = DEF-LF	--> 'IEECR-LF' (less formal)

	aiPopSelPostOC( 'onSelAIoption.' + selVer, null, { selVerF:true, id:id, etc:etc, etcVer:etcVer } );	// ( cBy, evt, o )		// o= { id:"IEEALL", IERF:true, etc:"IEEAR" }	

}	// onSelAIoption







