//console.log('onSelAIversion:  sub= '    + sub);
//console.log('onSelAIversion:  bdy= '    + bdy);

// ---
		var id =  mceCls.replace( '_MCE', '' );

		$gDOS.find('.aiDOSpop').find('.' + id).find('.aiSub').find('.aiSubject').val( sub );

		tinymce.get( mceCls ).setContent( bdy );
// ---

// ----------
		var etc = id.substring( id.lastIndexOf( '_' ) + 1 );					// AI_221568_1761930363531_3_IEECR  -->  IEECR
