function aiSubmitStatus( cBy, TrxID, o )
{
//console.log('aiSubmitStatus:  cBy= ' + cBy + '  -->  TrxID= ' + TrxID);			// <<<<<<<<<<<<<<<<<<

	if( !o ) { o = {}; }
//console.log('aiSubmitStatus:  o= ' + JSON.stringify(o));	// <<<<<<<<<<<<<<<<<<

// ---
	if( aiStatusKillF ) { clearWinWait( 'aiSubmitStatus' );		return; }	// <<<<<<<<<<<<<<<<<<
// ---

   	$.post( 'aiSubmitStatus', { uID:uID, cID:dObj.cID, TrxID:TrxID },

			function( jsn ) { 
//console.log('aiSubmitStatus:  jsn= ' + (jsn ? JSON.stringify(jsn) : jsn));

				if( !jsn || !jsn.sF )
				{
					oe('aiSubmitStatus', 'jsn= ' + (jsn ? JSON.stringify(jsn) : jsn) + '  for o= ' + JSON.stringify(o) + '  and uID= ' + uID + '  and cID= ' + dObj.cID + '  and TrxID= ' + TrxID + '  and cBy= ' + cBy);

					return;
				}


				if( !jsn.cID || !dObj || !dObj.cID || jsn.cID != dObj.cID )
				{
//console.log('aiSubmitStatus:  !jsn.cID || !dObj || !dObj.cID || jsn.cID != dObj.cID  -->  RETURN  for jsn.cID= ' + jsn.cID + '  and dObj.cID= ' + (dObj ? dObj.cID : dObj));

					return;
				}


				if( jsn.doneF )	
				{
// ---
//console.log('aiSubmitStatus.doneF:  o.etcVer= ' + o.etcVer);
					if( o.etcVer )
					{
						AIsubmitNewVerCB( 'aiSubmitStatus.doneF', jsn, o )
					}
					else
					{
						AIsubmitCBdone( 'aiSubmitStatus.doneF', jsn, o );	// <<<<<<<<<<<<<<<<<<<<<<<
					}
// ---
				}
				else
				{
					setTimeout(function() { aiSubmitStatus( 'aiSubmitStatus', TrxID, o ); }, 5000);		// <<<<<<<<<<<<
				}
			},

			'json'

		).fail(function(jx, ts, er) { oae('aiSubmitStatus', jx, ts, er); });
}






