	if( !statusChkF ) { statusChkF = false; }

	if( !statusCntr ) { statusCntr = 0; }

//console.log('aiPopUserComDesc:  olF= ' + olF + '  statusChkF= ' + statusChkF + '  statusCntr= ' + statusCntr + '  mgrF= ' + mgrF + '  apaF= ' + apaF + '  amID= ' + amID + '  userValDefJsn.UCNE= ' + (userValDefJsn ? userValDefJsn.UCNE : userValDefJsn));

//-----------
