// -----
	if( !userValDefJsn || !userValDefJsn.UCNE )		// NOT 
	{
		if( userDefUWF )
		{
			statusCntr++;

			if( statusCntr > 10 )
			{
				userDefUWF = false;		// reset...

				clearWinWait('aiPopUserComDesc.aiComDefHtm:  statusCntr > 10');

//console.log('aiPopUserComDesc:  statusCntr > 10  -->  RETURN');

				oe('aiPopUserComDesc.aiComDefHtm', 'statusCntr > 10');
			}
			else
			{
// NO!!!		winWait( 'aiPopUserComDesc.userDefUWF' );

				setTimeout(function() { aiPopUserComDesc( null, false, true, statusCntr ) }, 5000);		// evt, olF, statusChkF
			}

			return;
		}


		if( mgrF || apaF || amID )
		{
			aiGenComDef( 'aiPopUserComDesc', true );	// aiBtnF
		}
		else
		{
			pmm('Before proceeding, a company description is required<p>Contact your administrator or LeadLeaper for assistance</p>');		// <<<<<<<<<<<<<<<<<<<<
		}

		return;
	}
// -----

/*
				if( !jsn.htm )		// still generating research...
				{
//console.log('aiPopUserComDesc:  !jsn.htm  -->  RETURN');
					pmm('Generating company research ... please wait');
					return;
				}
*/



				if( !apaF && rc != 2 )
				{
					var h = '<div id="aiPopUserDesc" class="aiPopUserDesc"><div class="htm">' + (jsn.htm ? jsn.htm : '') + '</div></div>';		// <<<<<<<<<<<<<<<<<<<

					pmp( h, { popClass:'aiPopCusVS' } );	// <<<<<<<<<<<<<<<<<<<<<<<<<<<

					return;		// <<<<<<<<<<<<<<<<<<<<<<<<<<<
				}



// =============================================
				var h 	= '<div id="aiPopUserDesc" class="aiPopUserDesc">'

						+	'<div class="htm">' + (jsn.htm ? jsn.htm : '') + '</div>'	// <<<<<<<<<<<<<<<<<<<

					 	+ 	'<div class="modal-footer">'
						+ 		'<div class="modal-footer-cntrls">'
						+			'<button class="btn btn-info      btn-close"   style="width:64px;" >Close</button>'
						+			'<button class="btn btn-primary   btn-edit"    style="width:64px;" >Edit</button>'
						+ 			'<button class="btn btn-success   btn-save"    style="width:64px;" >Save</button>'
						+		'</div>'
						+	'</div>'

						+ '</div>'	// aiPopUserDesc


				pmp( h, { hideFttr:true, mdlFlag:true, popClass:'aiPopCusVS aiPopUserDesc' } );


				setTimeout(function() {

					var $m = $('#aiPopUserDesc');	// <<<<<<<<<<<<

						$m.find('.htm').find('.editable').off('click').on('click', aiEditPopUserDescOC);

						$m.find('.modal-footer').find('.modal-footer-cntrls').find('> button').off('click').on('click', aiPopUserDescFtrOC);	// aiConfigFtrOC

					}, 400);
