function roFoptem( row )
{
//console.log('roFoptem:  row= ' + JSON.stringify(row));

	var emF=true, em = row.email;

	if( row.gData.dncF )
	{
		em = '<span class="ce"><span class="dnc">Do not contact</span></span>';
	}
	else if( row.gData.noF && !row.gData.noeF )	// notOwnerFlag && NOT notOwnerEmailFlag...
	{
		em = '<span class="ce"><span class="dnc">Duplicate capture <span class="noDet">(view profile for details)</span></span>';
	}
	else
	{
		if( row.gData.esID == -1 && !em.length )	
		{
			em = '<span class="ce"><span class="edu"><span class=\"srchgW\"></span>Searching internet  <b>. . .</b></span></span>';
		}
		else if( em.length )
		{
// ---
			if( row.gData.rvF )	// reverifyFlag...
			{
				em = '<span class="ce"><span class="fa fa-circle emRV">&nbsp;</span>' + em + '</span>';
			}
// ---
// ---
			else if( lloutF && (row.gData.esID == 1 || row.gData.GESC > 0) )	//  outrearch validated  OR  MV/EC verified...
			{
				em = '<span class="ce"><span class="fa fa-circle emV emVG">&nbsp;</span>' + em + '</span>';
			}
// ---

			else if( row.gData.esID == -2 )
			{
				em = '<span class="ce"><span class="fa fa-circle emUV">&nbsp;</span>' + em + '</span>';
			}
			else
			{
				em = '<span class="ce"><span class="fa fa-circle emV">&nbsp;</span>' + em + '</span>';
			}
		}
		else
		{
			em = '<span class="ce">&nbsp</span>';
		}
	}
//console.log('roFoptem:  em= ' + em);

	return em;
}







