	try
	{
		let $e = $(evt.target);
		if( $e.get(0).tagName.toUpperCase() == 'I' ) 
		{
			$e = $e.parent();
			if( $e.hasClass('trtg') )
			{
				evtStop(evt); 
				tStats( $e, tde );   
				return; 
			}
		}
		else if( $e.find('span.trtg').length > 0 )
		{
			evtStop(evt);   
			$e = $e.find('span.trtg');  
			tStats( $e, tde );   
			return;
		}
	}
	catch(err)
	{
console.log('temOC:  err= ' + err.message);
	}
