function aiTemptCboxOC( evt, editor )
{
	var $m = $('#tModal');

	if( $m.find('#aiTmpltCbox').is(':checked') )
	{
//console.log('aiTemptCboxOC:  checked');

		var sub  = $m.find('#eSubject').val().trim(),
			desc = $m.find('#aiTmpltDesc').val().trim();
////console.log('aiTemptCboxOC:  sub= ' + sub + '  desc= ' + desc);

			if( sub.indexOf(  '{AI_Generated_Subject}' ) != -1 ) { sub  = ''; }
			if( desc.indexOf( '{AI_Generated_Subject}' ) != -1 ) { desc = ''; }

//???	$m.find('#aiTmpltCbox').addClass('vis');

		$m.find('#aiTmpltDesc').val( (desc ? desc : sub) );

		$m.find('#eSubject').val( '{AI_Generated_Subject}' );


		if( editor.getContent().indexOf( '{AI_Generated_Content}' ) == -1 )
		{
//console.log('aiTemptCboxOC:  editor.getContent().indexOf  == -1');
//console.log('aiTemptCboxOC:  editor.getContent()= ' + editor.getContent());

//			editor.setContent( editor.getContent() + '<p>{AI_Generated_Content}</p>' );
			editor.insertContent( '<p>{AI_Generated_Content}</p>' );
		}
	}
	else
	{
//console.log('aiTemptCboxOC:  NOT checked');

//???	$m.find('#aiTmpltCbox').removeClass('vis');

		$m.find('#aiTmpltDefCbox').prop('checked', false);	// <<<<<<<<<<<<<<<<<<<<<<

		var sub = $m.find('#eSubject').val().trim();
//console.log('aiTemptCboxOC:  sub= ' + sub);

			if( sub.indexOf( '{AI_Generated_Subject}' ) != -1 )
			{
//console.log('aiTemptCboxOC:  sub.indexOf( ... ) != -1');

				$m.find('#eSubject').val( '' );
			}


		if( editor.getContent().indexOf( '{AI_Generated_Content}' ) != -1 )
		{
//console.log('aiTemptCboxOC:  editor.getContent().indexOf  != -1');
//console.log('aiTemptCboxOC:  editor.getContent()= ' + editor.getContent());

			editor.setContent( editor.getContent().replace( '{AI_Generated_Content}', '' ) );
		}
	}
}






