function ncei( nID, ttl, o )	// newCampaignEmailInstance...
{
	var $tc, $ta, hrf, ctID, ctObj, eObj, pID, cID, piID, ciID, camSavF;

	if( o )
	{
//console.log('ncei:  o= ' + JSON.stringify( o ) );

		camSavF = o.camSavF;

		ctObj = o.ctObj;	// may be undefined...
	}
//console.log('ncei:  camSavF= ' + camSavF);


	if( ctObj ) // if( camSavF )
	{
		//ctObj = o.ctObj;

		ciID = ctObj.id;

		ctID = 'ct' + ciID;

		hrf = '#ct' + ciID;		// ctID = '#ct' + ciID;

		eObj = ctObj.eObj;		// eObj = ctObj.eObj;

		$tc = $('#camModal .modal-body > .tabbable > .tab-content').find( hrf );	// ctID
//console.log('ncei:  $tc.length= ' + $tc.length);

		$ta = $('#camModal .modal-body > .tabbable > ul.nav-tabs > li').find('a[href="' + hrf + '"]');
//console.log('ncei:  $ta.length= ' + $ta.length);
	}
	else
	{
		$ta = $('#camModal .modal-body > .tabbable > ul.nav-tabs > li.active a');

		$tc = $('#camModal .modal-body > .tabbable > .tab-content > div.active');

		ctID = $tc.attr('id');

		ctObj = camObj[ ctID ];

		eObj = ctObj.eObj;		// eObj = ctObj.eObj;
	}
//console.log('ncei:  starting ctID= ' + ctID);


		if( camObj.pID )	// an outreach(project) Campaign...
		{
			piID = nID;
		}
		else	// a library campaign...
		{
			ciID = nID;
		}
//console.log('ncei:  ciID= ' + ciID + '  piID= ' + piID + '  nID= ' + nID + '  ttl= ' + ttl + '  ctObj= ' + ctObj);


//	var $tc = $('#camModal .modal-body > .tabbable > .tab-content > div.active'), ctID = $tc.attr('id'), ctObj = camObj[ctID], eObj = ctObj.eObj;

		ctObj.id = nID;

		if( ciID ) { eObj.ciID = ciID; }

		if( piID ) { eObj.piID = piID; }


		if( ttl && ttl.trim().length > 0 ) { $ta.find('> span').text( ttl ); }		// $('#camModal .modal-body').find('ul#cam-tabs-list > li.active > a > span').text( eS )

		$ta.attr('href', '#ct' + nID);

		$tc.attr('id', 'ct' + nID);

		camObj['ct' + nID] = ctObj;

		camObj[ctID] = null;

		ctID = 'ct' + nID;
//console.log('ncei:  ending ctID= ' + ctID);

//console.log('ncei:  camSavF  eSendC');
		if( camSavF ) { o.ctObj = ctObj;	eSendCHB( 'ncei', null, o ); }
}






