function camUIbOpn( j, o )
{
	if( !o ) { o = {}; }
//console.log('camUIbOpn:  camObj.nf= ' + camObj.nf + '  camObj.savF= ' + camObj.savF + '  camObj.pID= ' + camObj.pID  + '  camObj.CADF= ' + camObj.CADF + '  camObj.actF= ' + camObj.actF);
//console.log('camUIbOpn:  o.empF= ' + o.empF + '  o.pID= ' + o.pID + '  camObj.cID= ' + camObj.cID + '  camObj.pID= ' + camObj.pID);
//console.log('camUIbOpn:  o= ' + JSON.stringify(o) );
//console.log('camUIbOpn:  j= ' + JSON.stringify(j) );


	if( j.rC != 1 )
	{
		oe('camUIbOpn', 'j.rC= ' + j.rC);

		return;
	}


// ----
//console.log('camUIbOpn:  j.rndRbnF= ' + j.rndRbnF + '  j.senderAcct= ' + j.senderAcct + '  j.xweF= ' + j.xweF + '  j.opnFUpID= ' + j.opnFUpID + '  j.lnkFUpID= ' + j.lnkFUpID  + '  j.repFUpID= ' + j.repFUpID );

	camObj.xweF 	= ( j.xweF ? j.xweF : false );

	camObj.opnFUpID = ( j.opnFUpID ? j.opnFUpID : 0 );

	camObj.lnkFUpID = ( j.lnkFUpID ? j.lnkFUpID : 0 );

	camObj.repFUpID = ( j.repFUpID ? j.repFUpID : 0 );

// ---
	camObj.rndRbnF 	= ( j.rndRbnF ? j.rndRbnF : false );

	camObj.senderAcct = ( j.senderAcct ? j.senderAcct : null );
// ---

//console.log('camUIbOpn:  camObj.rndRbnF= ' + camObj.rndRbnF + '  camObj.senderAcct= ' + camObj.senderAcct + '  camObj.xweF= ' + camObj.xweF + '  camObj.opnFUpID= ' + camObj.opnFUpID + '  camObj.lnkFUpID= ' + camObj.lnkFUpID  + '  camObj.repFUpID= ' + camObj.repFUpID );
// ----



	var data = j.data, iLs = j.iLs, id;
//console.log('camUIbOpn:  data= ' + data + '  iLs= ' + iLs);

		if( iLs && iLs.trim().length > 0 )
		{
			var iLa = iLs.split('|'), len = iLa.length;
//console.log('camUIbOpn:  iLa= ' + iLa + '  len= ' + len);

			if( camLibPrevObj && !j.empF )
			{
				camLibPrevObj.snA = iLa;	// sequenceNumberArray...
			}
			else
			{
				camObj.snA = iLa;	// sequenceNumberArray...
			}

			for(var i=0; i<len; i++)
			{
				id = iLa[i];

				if( camLibPrevObj && !j.empF )
				{
					camLibPrevObj['ct' + id] = { id:id, eObj:data[id] };
				}
				else
				{
					camObj['ct' + id] = { id:id, eObj:data[id] };
				}
			}

			id = iLa[0];	// get the first email...
//console.log('camUIbOpn:  id= ' + id);

			var emURL;

			if( camLibPrevObj && !j.empF )
			{
				emURL = awsEU + 'E' + camLibPrevObj.rd.gData.authID + '.' + id + '.txt';
			}
			else if( camObj.pID )	// an outCam...
			{
				emURL = awsEU + 'E' + uID + '.' + id + '.txt';
			}
			else
			{
				emURL = awsEU + 'E' + camObj.rd.gData.authID + '.' + id + '.txt';
			}

//console.log('camUIbOpn:  j.empF= ' + j.empF + '  emURL= ' + emURL);

// ---
			comDNC( 'camUIbOpn', sigObj.SigHtml );
// ---

			$.getJSON( emURL + '?n=' + Date.now(), function( jsn ) {  if( j.empF ) { jsn.empF=true; }	camOpnSM( id,  jsn, o );  }).fail(function(jx, ts, er) { camOpnSM( id, null, o ); });

		}	// if iLS

		else
		{
//console.log('camUIbOpn:  else');

			camUIc( j, o );		// <<<<<<<<<<<<<<<<<<<<<<<<
		}

}	// camUIbOpn




function camOpnSM( id, j, o )
{
//console.log('camOpnSM:  id= ' + id);

	if( !o ) { o = {}; }
//console.log('camOpnSM:  o= '  + JSON.stringify(o) );	//console.log('camOpnSM:  o.empF= ' + o.empF);
//console.log('camOpnSM:  j= '  + (j ? JSON.stringify(j) : j) );
//console.log('camOpnSM:  camObj.nf= ' + camObj.nf + '  camObj.savF= ' + camObj.savF + '  camObj.cID= ' + camObj.cID + '  camObj.pID= ' + camObj.pID );
//console.log('camOpnSM:  camObj= ' + camObj + '  camLibPrevObj= ' + camLibPrevObj);


	var ctObj, eObj, df=true, empF;

	if( (j && j.empF) || o.empF ) { empF = true; }		// if( j && j.empF ) { empF = true; }
//console.log('camOpnSM:  AAA empF= ' + empF);

// ---
	if( camLibPrevObj && o.empF ) { empF = true; }
// ---
//console.log('camOpnSM:  BBB empF= ' + empF);



	if( j )
	{
		if( camLibPrevObj && !empF )
		{
			ctObj = camLibPrevObj['ct' + id];
		}
		else
		{
			ctObj = camObj['ct' + id];
		}
//console.log('camOpnSM:  ctObj= ' + (ctObj ? JSON.stringify(ctObj) : ctObj) );

		eObj = ctObj.eObj;

		eObj.edo = j;	// emailDataObj
	}
	else
	{
		if( camLibPrevObj )
		{
			camLibPrevObj['ct' + id] = null;
		}
		else
		{
			camObj['ct' + id] = null;
		}
	}


	var snA;

	if( camLibPrevObj && !empF )
	{
		snA = camLibPrevObj.snA;
	}
	else
	{
		snA = camObj.snA;
	}

	var len = snA.length, theID, emURL, f;
//console.log('camOpnSM:  snA= ' + snA + '  len= ' + len );

	for( var i=0; i<len; i++ )
	{
		theID = snA[i];

		if( camLibPrevObj && !empF )
		{
			ctObj = camLibPrevObj['ct' + theID];
		}
		else
		{
			ctObj = camObj['ct' + theID];
		}
//console.log('camOpnSM:  i= ' + i + '  -->  ctObj= ' + ctObj );


		if( ctObj )
		{
			eObj = ctObj.eObj;
//console.log('camOpnSM:  ctObj.eObj= ' + (ctObj.eObj ? JSON.stringify(ctObj.eObj) : ctObj.eObj) );

			if( !eObj.edo )		// NOT
			{
				df = false;

				eObj.edo = {};	// placeholder...

				if( camLibPrevObj && !empF)
				{
					emURL = awsEU + 'E' + camLibPrevObj.rd.gData.authID + '.' + theID + '.txt';
				}

				else if( camObj.pID  && !empF )		// an outCam...		<<<<<<<<<<<<<<<<<<<<<
				{
					emURL = awsEU + 'E' + uID + '.' + theID + '.txt';
				}

				else
				{
					emURL = awsEU + 'E' + camObj.rd.gData.authID + '.' + theID + '.txt';

//console.log('camOpnSM:  else  empF= ' + empF + ' -->  emURL= ' + emURL);
				}

				f = true;

				break;	// exit loop...
			}
		}
	}	// for


// ---
//console.log('camOpnSM:  f= ' + f + '  df= ' + df + '  o.empF= ' + o.empF + '  empF= ' + empF + '   emURL= ' + emURL);

	if( f )
	{
		$.getJSON( emURL + '?n=' + Date.now(), function( jsn ) { if( empF ) { jsn.empF=true; }	 camOpnSM( theID, jsn, o );  }).fail(function(jx, ts, er) { oae('camOpnSM.emURL', jx, ts, er);	camOpnSM( theID, null, o );  });
	}
// ---

	if( df )
	{
		camUIc( j, o );
	}
}







