function emUIfocus( evt, o, tID )
{
//console.log('emUIfocus:  emUIo= ' + emUIo + '  o= ' + o + '  tID= ' + tID);
//if( o ) { console.log('emUIfocus:  o= ' + JSON.stringify(o)); }

	try
	{
		try { if( o ) { if( ( o.rd && o.rd.gData.uID == uID ) || o.cID ) { o.savF = true; } }  } catch(er) { console.log('emUIfocus:  o.er= ' + er); }

		if( !emUIo || !emUIo.id ) { return; }

//console.log('emUIfocus:  emUIo.id= ' + emUIo.id);

		var toInsert;

		switch( emUIo.id )
		{
			case 'note-gpnBtn' :	toInsert = '[Lead_First_Name] ';		break;

			case 'note-gcnBtn' :	toInsert = '[Lead_Company_Name] ';		break;
		}
//console.log('emUIfocus:  toInsert= ' + toInsert);	
	
		if( toInsert )
		{
			var $e = $(evt.target);
	
			if( $e.hasClass('eSubject') )
			{
				if('selectionStart' in evt.target)
				{
					let cursorPos = evt.target.selectionStart, oldContent = $e.val();	//, newContent = oldContent.substring(0,cursorPos) + toInsert + oldContent.substring(cursorPos);
//console.log('emUIfocus:  cursorPos= ' + cursorPos);
//console.log('emUIfocus:  oldContent= ' + oldContent);
//console.log('emUIfocus:  newContent= ' + newContent);

					$e.val( oldContent.substring(0,cursorPos) + toInsert + oldContent.substring(cursorPos) );	// newContent

					$e.blur();
				}
			}
			else
			{
				let sel = document.getSelection(), cursorPos = sel.anchorOffset, oldContent = sel.anchorNode.nodeValue;	//, newContent = oldContent.substring(0, cursorPos) + toInsert + oldContent.substring(cursorPos);

				try
				{
					sel.anchorNode.nodeValue = oldContent.substring(0, cursorPos) + toInsert + oldContent.substring(cursorPos);	// newContent;
				}
				catch(er)
				{
					sel.anchorNode.innerText = toInsert;	//console.log('emUIfocus:  er= ' + er);
				}
// ---
				let $sn;
				if( tID )
				{
					$sn = $('#camModal').find(tID).find('.note-editable'); 
				}
				else if( o )	// MUST be an email template...
				{
					$sn = $('#tModal').find('.note-editable'); 
				}

				if( $sn && $sn.length == 1 )
				{
					$sn.blur();

					var $lnk = $sn.find('a#gravWP'), lnkTxt = $lnk.text(), f;
//console.log('emUIfocus:  $sn.length= ' + $sn.length + '  $lnk.length= ' + $lnk.length);
//console.log('emUIfocus:  starting lnkTxt= ' + lnkTxt);

					if( lnkTxt.indexOf('[Lead_First_Name] ') != -1 )
					{
						f = true;

						lnkTxt = lnkTxt.replace('[Lead_First_Name] ', '');
					}
					else if( lnkTxt.indexOf('[Lead_Company_Name] ') != -1 )
					{
						f = true;

						lnkTxt = lnkTxt.replace('[Lead_Company_Name] ', '');
					}

					else if( lnkTxt.indexOf('[Lead_First_Name]') != -1 )
					{
						f = true;

						lnkTxt = lnkTxt.replace('[Lead_First_Name]', '');
					}
					else if( lnkTxt.indexOf('[Lead_Company_Name]') != -1 )
					{
						f = true;

						lnkTxt = lnkTxt.replace('[Lead_Company_Name]', '');
					}
//console.log('emUIfocus:  f= ' + f + '  ending lnkTxt= ' + lnkTxt);
			
					if( f )
					{
						$sn.find('a#gravWP').text(lnkTxt);
					}
				}	// if $sn
// ---
			}	// else

//			$(emUIo.evt.target).removeClass('active');	// target: i.fas.fa-user.fa-fw
			$(emUIo.evt.target).removeClass('active').parent().removeClass('active');

			emUIo = null;
		}
	}
	catch(er)
	{
//console.log('emUIfocus:  er= ' + er);

		rpt('emUIfocus:', er.message);
	}
}








