function sizeCamTabs( o )
{
//console.log('sizeCamTabs:  o= ' + JSON.stringify(o) );
//console.log('sizeCamTabs:  o.mID= ' + o.mID + '  o.empF= ' + o.empF + '  o.authF= ' + o.authF + '  camLibPrevObj= ' + camLibPrevObj);

	var $tul = $('#' + o.mID).find('.modal-body > .tabbable').find('#cam-tabs-list'), w = $tul.width(),  $liA = $tul.find('> li'), cnt = $liA.length, $s, sw, f;
//console.log('sizeCamTabs:  w= ' + w + '  starting cnt= ' + cnt);

// w = w - 100;
	if( cnt < 5 ) { cnt++; } else { f = true; }


	if( o.arcf || !o.authF || ( camLibPrevObj && !o.empF ) )	// if( !o.authF || ( camLibPrevObj && !o.empF ) )
	{
		sw =( w - ( cnt * 44 ) ) / cnt;
	}
	else
	{
		cnt = cnt - 1;

		sw = ( w - 44 - ( cnt * 44 ) ) / cnt;
	}
//console.log('sizeCamTabs:  w= ' + w + '  ending cnt= ' + cnt + '  sw= ' + sw + '  f= ' + f);

	$liA.each( function(i, o) { var $a = $(this).find('a'), n = sw;  if( $a.hasClass('addTab') ) { } else {  if( i == (cnt-1) ) { if( cnt > 5 ) { n=n+1; } else { n=n+2; } }	$a.find('> span').css('width', n + 'px'); }  });	// each
//console.log('sizeCamTabs:  $tul.height()= ' + $tul.height());

	if( f )
	{
		$tul.find('li.addTab').addClass('addTabRt');
	}
	else
	{
		$tul.find('li.addTab').removeClass('addTabRt');
	}



/* SAVE
	if( f )
	{
		var cntr = 0;
		while( $tul.height() > 40 && cntr < 5 )
		{
			cntr++;
			$s = $tul.find('> li.camTab:last > a > span');
	//console.log('sizeCamTabs:  cntr= ' + cntr + '  $s.width()= ' + $s.width());
			$s.css('width', ( $s.width() - 1 ) + 'px');
		}
	}
*/
}





