function camTabClk( evt, o )	// { savF:false, camSavF:camSavF, actSendF:actSendF, tmceInitF:tmceInitF }
{
	if( !o ) { o = {}; }
//console.log('camTabClk:   evt= ' + evt +  '  o.empF= ' + o.empF + '   camLibPrevObj= ' + camLibPrevObj + '  camObj= ' + camObj + '  o= ' + (o ? JSON.stringify(o) : o));

	winWait( 'camTabClk' );

	eSubOnBlurCurPos = null;	// may be 0 so ONLY cleared if set to null !!!!!		// eSubOnClickF = false;	// clear...

	eSubPlcHldrProcF = false;

	emUIo = null;	


	var $m;

	if( camLibPrevObj )
	{
		$m = $('#camLibPrevModal');
	}
	else
	{
		$m = $('#camModal');

		$m.find('.ttip').tooltip('hide');
	
		if( camObj.TDpoF ) { try { camObj.TDpoF = false;  		try { $tipPO.popover('destroy'); } catch(er){} } catch(er){} }
	
		if( camObj.sendF ) { try { camObj.sendF = false;		$m.find('#eSendBttn').popover('hide'); } catch(er){} }			// KEEP!!!
	
		if( camObj.delF )  { try { camObj.delF  = false;		$m.find('#camDel').popover('hide');	} catch(er){} 	 }			// KEEP!!!
	}


	$m.find('.modal-header').find('button').tooltip('hide');


	var hrf, tabID, camSavF, actSendF;

	if( o )
	{
//console.log('camTabClk:   o= ' + JSON.stringify(o));
		if( evt && o.actSendF ) { actSendF = o.actSendF; }

		if( !actSendF )	// NOT		if actSendF && o.camSavF, then save executed within eSend processing...
		{
			if( o.camSavF ) { camSavF = o.camSavF; }
		}
//console.log('camTabClk:   camSavF= ' + camSavF + '  actSendF= ' + actSendF);
	}


	if( camSavF || o.tmceInitF )	// <<<<<<<<<<<<<<<<<<
	{
		hrf   = o.hrf;

		tabID = hrf.substring(1);
//console.log('camTabClk:  hrf= ' + hrf + '  tabID= ' + tabID);
	}

	else	// else if( evt )
	{
// ---
		$m.css('position', 'fixed');
// ---

		var $e = $(evt.target), $li = $e.parents('li');

		$m.find('.modal-body').find('.tab-content > .active').find("input.HL").removeClass('HL').popover('hide');


		if( evt.target.tagName.toLowerCase() == 'i' )
		{
			if( !$li.hasClass('active') )	// NOT
			{
				if( evt.target.tagName.toLowerCase() == 'i' )
				{
					$e.parent().parent().click();
				}

				return;
			}
	
			remCamTab( evt );

			return;
		}


		if( evt.target.tagName.toLowerCase() != 'a' )
		{
			$e = $e.parent();
		}
	
	
		if( $e.hasClass('addTab') )
		{
			$e.blur();
	
			addCamTab( 'addTab', evt );
	
			return;
		}


		hrf   = $e.attr('href');

		tabID = hrf.substring(1);
//console.log('camTabClk:  hrf= ' + hrf + '  tabID= ' + tabID);

		$m.find('ul#cam-tabs-list > li').removeClass('active').end().find('.tab-content > div.tab-pane').removeClass('active');

		$li.addClass('active');

	} // else NOT camSavF && NOT o.tmceInitF



//console.log('camTabClk:  camSavF= ' + camSavF + '  hrf= ' + hrf + '  tabID= ' + tabID + '  o.tmceInitF= ' + o.tmceInitF +  '  o.empF= ' + o.empF);

	var ctObj;

	if( camLibPrevObj )
	{
		ctObj = camLibPrevObj[tabID];
	}
	else
	{
		ctObj = camObj[tabID];
	}
//console.log('camTabClk:  ctObj= ' + (ctObj ? JSON.stringify(ctObj) : ctObj));


	var eObj = ctObj.eObj, 
		edo  = eObj.edo;
//console.log('camTabClk:  eObj= ' + (eObj ? JSON.stringify(eObj) : eObj));
//console.log('camTabClk:  edo= '  + (edo  ? JSON.stringify(edo)  : edo));	

		if( tmceF )
		{
			let $tc = $m.find('.tab-content').find( hrf );
//console.log('camTabClk:  hrf= ' + hrf + '  -->  $tc.attr(id)= ' + $tc.attr('id'));

			camTabMCE( 'camTabClk' + (o.tmceInitF ? '.tmceInitF' : ''), $tc );		// <<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<
//console.log('camTabClk:  o.tmceInitF= ' + o.tmceInitF + '  edo= '  + edo);

// ---
//console.log('camTabClk:  ctObj.id= ' + ctObj.id + '  --> o.empF= '  + o.empF);
	if( o.empF )
	{
		try { tinymce.get( 'camMCEct' + ctObj.id ).setDirty( true ); } catch(errr) { console.log('camTabClk.setDirty:  ctObj.id= ' + ctObj.id + '  --> errr= ' + errr.message); }	// MUST EXCLUDE #		// camMCEct0, camMCEct1, ...

		camObj.savF = true;	// <<<<<<<<<<<<<<<< 
	}
// ---

			if( edo )
			{
// ---
				emProc( null, { cf:'camTabClk', $m:$m, camF:true, camSavF:camSavF, camOpnID:tabID, $tc:$tc, eObj:eObj, lc:eObj.lc } );
// ---
// SAVE!!!		eObj.edo = null;	// clear...		<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<

				if( !camSavF && !o.tmceInitF )	// NOT
				{
					$tc.addClass('active');

					setTimeout( function() { 
											$m.css('position', 'absolute');
				
											clearWinWait('camTabClk');  
				
											if( !camSavF && !camLibPrevObj ) { camTabToDD( $tc ); }
								}, 500);
				}


				if( actSendF && !o.tmceInitF )
				{
//console.log('camTabClk:   if edo  if actSendF  -->  eSendB');
					eSendB( null, o );
				}

				return;			// <<<<<<<<<<<<<<<<<<<<<<<<<<<<<<

			}	// if( edo )	// <<<<<<<<<<<<<<<<<<<<<<<<<<<<<<
// ---
			if( o.tmceInitF ) { return; }	// <<<<<<<<<<<<<<<<<<<<<<<<<<<<<<
// ---
		}	// if tmceF...		// <<<<<<<<<<<<<<<<<<<<<<<<<<<<<<


	let $tc = $m.find('.tab-content').find( hrf );

	$tc.addClass('active');

	setTimeout( function() { $m.css('position', 'absolute');		clearWinWait('camTabClk');  }, 500);


//console.log('camTabClk:  camSavF= ' + camSavF + '  camLibPrevObj= ' + camLibPrevObj + '  camObj.pID= ' + camObj.pID);

	if( !camSavF )
	{
		camTabToDD( $tc );

		camPopTabDragMsg();
	}


// ---
	if( actSendF )
	{
//console.log('camTabClk:  eSendB');
		eSendB( null, o );
	}
// ---

}	// camTabClk






