function engAct_CB( d, o )
{
	if( !o ) { o = {}; }
//console.log('engAct_CB:  o= ' + JSON.stringify(o));
//console.log('engAct_CB:  d= ' + JSON.stringify(d));		// d.misc = {"lstOpnTS":1704186850000,"lstRplyTS":1704191799000,"lstEmTS":1718399127000,"lstLnkTS":1716750894000}

	var hmDashF = $('body').hasClass('hmDash');
//console.log('engAct_CB:  hmDashF= ' + hmDashF);


// ------
	if ( !glc && !hmDashF && !freeOutF )	// NOT
	{
		clearWinWait('engAct_CB');
// ---
		setTimeout(function() { $('body').css('overflow-y', 'auto'); }, 1000);	// <<<<<<<<
// ---
		reqSub( 'engAct_CB' );

		return;
	}
// ------



	if( hmDashF )	// hmDashLastOpened		// d.misc = { "emUWf":false, "lstOpnTS":1704186850000, "lstRplyTS":1704191799000, "lstEmTS":1718399127000, "lstLnkTS":1716750894000 }
	{
		var dt, fdt;

		if( d && d.misc && d.misc.lstEmTS )
		{
			dt = new Date( d.misc.lstEmTS - zero );

			fdt = Intl.DateTimeFormat( 'en-US', { weekday: 'short', month: 'short', day: 'numeric' } ).format( dt ) + '<span class="actAtBR"></span>' + Intl.DateTimeFormat( 'en-US', { hour: 'numeric', minute: 'numeric', second: 'numeric' } ).format( dt );
		}


		if( d && d.misc && d.misc.emUWf )	// emailUnderwayFlag... 	<span class="gears"></span>
		{
			$('#hmDashLastDelivered').addClass('gears').html( '<span class="gears"></span><span class="lbl">emailing<span class="actAtBR"></span>underway</span>' );
		}
		else
		{
			$('#hmDashLastDelivered').removeClass('gears').html( (fdt ? '<span class="lbl">' + fdt + '</span>' : '') );	// <label>last: </label>
		}


		hmLoadCntr++;
//console.log('engAct_CB:  hmDashF  hmLoadCntr= ' + hmLoadCntr);

		hmEngAdt.order( [ 1, 'asc' ] ).draw();		// 1 --> sequence / list title...	<<<<<<<<<<<<<<<<<<<<<<<<<<<

		$hmEngAdt.show();

	$hmEngAct.fadeIn();


		if( hmLoadCntr > 3 )
		{
			clearWinWait('engAct_CB');
// ---
	$('#HomeDash').find('.gravPanel').show().end().show();			

//	$('#HomeDash').fadeIn();

	setTimeout(function() { $('body').css('overflow-y', 'auto'); }, 1000);		// <<<<<<<<	
// ---
			try{ window.clearTimeout( hmLoadTOid );		hmLoadTOid = null; }catch(er){ hmLoadTOid = null; } }	// <<<<<<<<<<<<<<<<<<<<<<<<<<

	}	// if hmDashF...

	else
	{
		engAdt.order( [ 3, 'asc' ] ).draw();	// 3 --> sequence / list title...
// ---
		$('.gravPanel').hide();
// ---
		$engAct.show();

		clearWinWait('engAct_CB');
// ---
	setTimeout(function() { $('body').css('overflow-y', 'auto'); }, 1000);		// <<<<<<<<
// ---
		$engAdt.find('tbody>tr>td').find('.ttip').tooltip( { container: 'body', placement:'top', html:true } );		// top

	}	// else NOT hmDashF...
}



function emailStatusRefHmDash( doneF )	// called every 5min (prod) / 30sec during an emailing...
{
	if( !doneF ) { doneF = false; }
//console.log("emailStatusRefHmDash:  doneF= " + doneF + "  $('#HomeDash').is(':visible')= " + $('#HomeDash').is(':visible'));

	if( $('#HomeDash').is(':visible') )
	{
		if( doneF )
			hmEngAdt.ajax.url( 'AJAX_Activity?aID=' + aID + '&uID=' + uID + '&glc=' + glc + '&freeOutF=' + freeOutF + '&engF=true&pID=0&hmDashF=true' ).load( function( d ) { engAct_CB( d ); } );

		hmLinksAdt.ajax.url( 'AJAX_Activity?aID=' + aID + '&uID=' + uID + '&glc=' + glc + '&freeOutF=' + freeOutF + '&lnkF=true&pID=0&hmDashF=true' ).load( function( d ) { act_CB( d, { lnkF:true,  hmDashF:true } ); } );

		hmReplyAdt.ajax.url( 'AJAX_Activity?aID=' + aID + '&uID=' + uID + '&glc=' + glc + '&freeOutF=' + freeOutF + '&rplyF=true&pID=0&hmDashF=true').load( function( d ) { act_CB( d, { rplyF:true, hmDashF:true } ); } );

//$('#hmDashChart').css('opacity','0');

		$.getJSON( 'AJAX_Dash', { aID:aID, uID:uID, glc:glc, freeOutF:freeOutF, tzOs:tzOs, hmDashF:true, hmDashOnlyF:!doneF }, hmGrphCB ).fail(function(jx, ts, er) { oae('homeDash.AJAX_Dash', jx, ts, er); });
	}
}



