function engDashRowSelOC( evt, rde )
{
	evtStop(evt);

	var $e = $(evt.target), id = $e.find('option:selected').attr('id'), row = engAdt.row( rde ).data(), cnt = 0, pID, iID;
//console.log('engDashRowSelOC: $e.get(0).tagName= ' + $e.get(0).tagName + '  --> id= ' + id)
//console.log('engDashRowSelOC: row= ' + JSON.stringify(row));

	if( id )	// id= p3441_4006
	{
		var sA = id.split('_');
//console.log('engDashRowSelOC:  sA= ' + sA);

		pID = sA[0].substring(1);	// stip leading 'p'
		iID = 'inst' + sA[1];
//console.log('engDashRowSelOC:  pID= ' + pID + '  iID= ' + iID);
	}


	while( cnt < 6 && $e.get(0).tagName.toLowerCase() != 'tr' ) { cnt++;   $e = $e.parent(); }
//console.log('engDashRowSelOC:  cnt= ' + cnt);
	if( cnt < 6  )
	{
		winWait( 'engDashRowSelOC' );	// <<<<<<<<<<

		$e.find('> td.seqLdsNEcnt').html( '<span class="centCnt40">' + ( row.iData && row.iData[iID] && row.iData[iID].ldsNEcnt ? numberWithCommas(row.iData[iID].ldsNEcnt) : 0 ) + '</span>' );


		if( row.aData && row.aData[iID] && row.aData[iID].sent && row.aData[iID].leDt ) 
		{
			var dt = new Date ( row.aData[iID].leDt - zero );

			var dtStr = '<span class="leDt">' + Intl.DateTimeFormat( 'en-US', { month: 'short', day: 'numeric', year: 'numeric' } ).format( dt ) + '<br><span class="actAt">@</span> ' + Intl.DateTimeFormat( 'en-US', { hour: 'numeric', minute: 'numeric', second: 'numeric' } ).format( dt ) + '</span>'; 

			$e.find('> td.seqLeDt').html( dtStr );
		}
		else
		{
//			$e.find('> td'.find('> span.leDt').parent().html( '' );
			$e.find('> td.seqLeDt').html( '<span class="leDt"></span>' );
		}


		if( row.aData && row.aData[iID] && row.aData[iID].delivered && row.aData[iID].openRate  ) { $e.find('> td.seqOpenRate' ).html( '<span class="centRate">' + row.aData[iID].openRate + '</span>' ); } else { $e.find('> td.seqOpenRate'  ).html( '<span class="engAct noData">no data</span>' ); }

		if( row.aData && row.aData[iID] && row.aData[iID].delivered && row.aData[iID].clickRate ) { $e.find('> td.seqClickRate').html( '<span class="centRate">' + row.aData[iID].clickRate + '</span>' ); } else { $e.find('> td.seqClickRate').html( '<span class="engAct noData">no data</span>' ); }

		if( row.aData && row.aData[iID] && row.aData[iID].delivered && row.aData[iID].repyRate  ) { $e.find('> td.seqRepyRate' ).text( '<span class="centRate">' + row.aData[iID].repyRate + '</span>' ); } else { $e.find('> td.seqRepyRate'  ).html( '<span class="engAct noData">no data</span>' ); }


		setTimeout(function() { clearWinWait('engDashRowSelOC'); }, 300);	// <<<<<<<<<<

	} // if cnt < 6

}	// engDashRowSelOC





function engDashRowOC( evt, rde )
{
	evtStop(evt);

	var $e = $(evt.target), cnt = 0;		// SAVE!!!!  rd = engAdt.row( rde ).data(), 
//console.log('engDashRowOC: $e.get(0).tagName= ' + $e.get(0).tagName)
//console.log('engDashRowOC: rd= ' + JSON.stringify(rd));

// ---
	if( $e.get(0).tagName.toUpperCase() == 'SELECT' )	// || $e.get(0).tagName.toUpperCase() == 'OPTION' || ( $e.get(0).tagName.toUpperCase() == 'TD' && $e.find('select').length == 1 ) )
	{
//console.log('engDashRowOC:  SELECT RETURN');

		$('#engActTbl').find('tbody > tr').removeClass('sel');

		rde.addClass('sel');

		return;
	}
// ---


	while( cnt < 6 && $e.get(0).tagName.toLowerCase() != 'td' ) { cnt++;   $e = $e.parent(); }
//console.log('engDashRowOC:  cnt= ' + cnt);

	if( cnt < 6  )
	{
		if( $e.hasClass('seqSet') )
		{
//console.log('engDashRowOC.seqSet:  ');

			if( $e.find('> span.seqSet').hasClass('disabled') ) { return; }

			engTst( evt, rde, { engSetF:true } );	// ALWAYS call engTst!!!
		}
		else
		{
//console.log('engDashRowOC.td:  ');

			engTst( evt, rde, null );	// ALWAYS call engTst!!!
		}
// ---
		$('#engActTbl').find('tbody > tr').removeClass('sel');

		rde.addClass('sel');
// ---
	}
}



function seqTglOC( evt, rde )
{
//console.log('seqTglOC:  evt.target.id= ' + evt.target.id + '  rde= ' + rde);

	var $e = $(evt.target), engTglOn = $e.is(':checked'), rd = engAdt.row( rde ).data(), cnt = 0;
//console.log('seqTglOC:  rd= ' + JSON.stringify(rd));
//console.log('seqTglOC:  rd.pID= ' + rd.pID + '  --> engTglOn= ' + engTglOn );

	engTst( evt, rde, { tglF:true, engTglOn:engTglOn } );	// ALWAYS call engTst!!!

// ---
	$('#engActTbl').find('tbody > tr').removeClass('sel');

	rde.addClass('sel');
// ---
}














