function liET( v )
{
	var n = v.indexOf('@'), n2; 

		v = v.substring(n+1).toLowerCase();		// strip leading @

		n2 = v.lastIndexOf('.');	// KEEP since we changed v!!!

	var ed = v.substring(0, n2);
//console.log('liET:  v= ' + v + '  ed= ' + ed);

//		if( $.inArray(v, fe) == -1 && $.inArray(ed, bl) == -1 )
		if( ( pF && aID == 1380 ) || ( devF && aID == 11418 ) || ( $.inArray(v, fe) == -1 && $.inArray(ed, bl) == -1 ) )	// 1380 --> leadleaper.net		11418 --> cal.berkeley.edu
		{
			return 1;
		}
		else
		{
			return 2;
		}
}



