function liVerCI_CB( j, lID, pID, capCntr, tiF )
{
//console.log('liVerCI_CB:  j.rC= ' + j.rC + '  lID= ' + lID + '  pID= ' + pID);

	clearWinWait('liVerCI_CB');

	if( j.rC != 1 )
	{
		if( j.rC == 2 )	// an import is already underway...
			pmp('Please first allow the existing import to complete');
		else
			oe('liVerCI_CB', 'j.rC= ' + j.rC + '  for lID= ' + lID);

		return false;
	}


	$('#liDTverModal').modal('hide');

// ---
	ListImportID = lID;

//	ListImportSize 	= j.ListSize;

//	setTimeout(function() { pmp('<div id="emStatus"  class="email-status email-statusPB import-statusPB"><span class="gears"></span><div class="progress"><div id="importStatusProgBar" class="progress-bar progress-bar-success active" role="progressbar" aria-valuenow="0" aria-valuemin="0" aria-valuemax="' + j.ListSize + '" style="width: 0%;"></div></div>', { mdlFlag:true } ); }, 400);	// progress-bar-striped 

	setTimeout(function() { pmp('<div id="emStatus"  class="email-status email-statusPB import-statusPB"><div class="intro" style="font-size:14px; margin:-7px 0 5px 44px;">Importing Leads' + (tiF ? '' : ' and Verifying Emails') + '<b>...</b></div><span class="gears" style="margin:-23px 8px 0 -8px; width:44px; height:44px;"></span><div class="progress" style="width:380px;"><div id="importStatusProgBar" class="progress-bar progress-bar-success active" role="progressbar" aria-valuenow="0" aria-valuemin="0" aria-valuemax="' + j.ListSize + '" style="width: 0%;"></div></div>', { mdlFlag:true } ); }, 400);	// progress-bar-striped


	ListImportStatusFailedCntr = 0;		// ensure reset...

	ListImportStatusProgBar();

	ListImportStatusIntervalID = setInterval(ListImportStatusProgBar, 1500);
// ---
}




function ListImportStatusProgBar()
{
	$.ajax({
			url: "AJAX_CsvImportStatus",

			data: { uID:uID, lID:ListImportID },

			timeout: 0,

			type: "GET",	// type: "POST",	// <-- switch to a "GET" due to chrome FU...

			dataType: "json"
	})

	.done( function(jsn, ts, jx) { 
									if( !jsn ) { return false; }

									if( jsn && typeof jsn == 'string' ) { jsn = JSON.parse(jsn); }	

//console.log('ListImportStatusProgBar.AJAX_CsvImportStatus  jsn= ' + JSON.stringify(jsn));

									if( jsn.rC != 1 )
									{
										ListImportStatusFailedCntr++;

										if( ListImportStatusFailedCntr > 10 )
										{
											oe('ListImportStatusProgBar.AJAX_CsvImportStatus', 'jsn.rC= ' + jsn.rC + '  for jsn.lID= ' + jsn.lID);

											try { if( ListImportStatusIntervalID ) { clearInterval(ListImportStatusIntervalID);  ListImportStatusIntervalID = null; } } catch(er) { ListImportStatusIntervalID = null; }
										}

										return false;
									}


									if( jsn.ipcFi )
									{
										if( jsn.ipcFi == 2 )	// a problem was encountered...
										{
											oe('ListImportStatusProgBar.AJAX_CsvImportStatus', 'jsn.ipcFi= ' + jsn.ipcFi + '  for jsn.lID= ' + jsn.lID);
										}
										else
										{
											ListImportStatusFailedCntr = 0;		// reset...

											pmpCls();

											setTimeout(function() { pmp('List import complete'); }, 400);
											
//											$('#importStatusProgBar').attr('aria-valuenow', jsn.iCnt).css('width', '100%');

											try { if( ListImportStatusIntervalID ) { clearInterval(ListImportStatusIntervalID);  ListImportStatusIntervalID = null; } } catch(er) { ListImportStatusIntervalID = null; }

											$('#outDD').trigger('click');
										}
									}
									else
									{
										ListImportStatusFailedCntr = 0;		// reset...

										var w = Math.round( ( (jsn.pCnt)/jsn.iCnt )*100 ) + '%';	

										$('#importStatusProgBar').attr('aria-valuenow', jsn.pCnt).css('width', w);
									}
	})

	.fail(function(jx, ts, er) { if( er ) { oae('ListImportStatusProgBar.AJAX_CsvImportStatus', jx, ts, er); }	try { if( ListImportStatusIntervalID ) { clearInterval(ListImportStatusIntervalID);  ListImportStatusIntervalID = null; } } catch(er) { ListImportStatusIntervalID = null; } });
}








