function EmployLandPageCB( j )
{
//console.log('EmployLandPageCB:  j= ' + JSON.stringify(j));

	if(j.rC != 1)
	{
		oe('EmployLandPageCB', 'rC= ' + j.rC + ' and j.tF= ' + j.tF + ' and j.cF= ' + j.cF);

		return;
	}


	if( j.dF )	// dossier...
	{
		dObj.lpsF = true;	// landPageSavFlag...

		dObj.lc = 1;
		dObj.lpUrl = j.u;
		dObj.lpOFN = j.fn;

		dObj.lprN = j.rN;
		dObj.lpfs = j.fs;
	}

	else if( j.tF )
	{
		if( j.ntF )
		{
//			temObj.nf	 	= true;
// NO!!		temObj.authID   = uID;

			temObj.tID   = 0;		// KEEP!!!
			temObj.nID   = j.nID;

			temObj.lprN  = j.rN;
			temObj.lpfs  = j.fs;
		}

		temObj.lc = 1;
		temObj.lpOFN = j.fn;
		temObj.lpUrl = j.u;

		temObj.savF = true;
	}

	else
	{
		var $tc = $('#camModal .modal-body > .tabbable > .tab-content > div.active'), ctID = $tc.attr('id'), ctObj = camObj[ctID], eObj = ctObj.eObj;

		if( j.nlcF )	// newLibraryCampaignFlag...  so capture newly-generated campaignID...
		{
			camObj.cID = j.cID;		// do NOT reset nF...
		}

		if( j.nceiF )	// NewCampEmailInstanceFlag			
		{
			ncei( j.nID );
		}

		eObj.lc = 1;
		eObj.lpUrl = j.u;
		eObj.lpOFN = j.fn;

		eObj.lprN = j.rN;
		eObj.lpfs = j.fs;

		if( !devF ) { camObj.savF = true; }
	}


	$('#eLinkModal input#lpOFN').val( j.fn );


	setTimeout(function() {
							$aeLandMdl.modal('hide');

							$eLdgsMdl.modal('hide');

							clearWinWait('EmployLandPageCB');

						}, 1000);
}


