function updateCC( evt )
{
//console.log('updateCC:   glc= ' + glc + '  apaF= ' + apaF);

	if( !apaF )		// acctPurchaseAuthorityFlag...
	{
		rpt('updateCC', 'updateCC encountered for apaF= ' + apaF);

		return;
	}

	if( !glc )		// free so canNOT be a CC update...
	{
		rpt('updateCC', 'updateCC encountered for glc= ' + glc);

		return;
	}

// ---
	UpdateCreditCard();

	return;
// ---

}





