function popHS( evt, id, $r, rd, tde, dosF )
{
//console.log('popHS:  rd= ' + JSON.stringify(rd) );

	if( !dosF ) { dosF = false; }

	if( dosF ) { evtStop(evt); }	// prevent toggle of display...

//console.log('popHS:  id= ' + id + '  dosF= ' + dosF + '  hsIAF= ' + hsIAF + '  hsUID= ' + hsUID + '  rd.gData.cID= ' + rd.gData.cID + '  rd.gData.hsID= ' + rd.gData.hsID + '  rd.gData.hsAID= ' + rd.gData.hsAID + '  hsAID= ' + hsAID);

	if( !hsIAF || !hsUID )	// NOT
	{
		if( !hsIAF && ( !glc || glc < 2 ) )
		{
			reqSub( 'popHS' );
		}

		else if( !hsIAF )
		{
			pmm( 'Requires HubSpot CRM Integration' );
		}
		else
		{
			addHS( ( dosF ? 'DS' : '') );
		}

		return;
	}



	if( !rd.gData.hsID || !rd.gData.hsAID || rd.gData.hsAID != hsAID )	// NOT
	{
//console.log('popHS:  if:   rd.gData.hsID= ' + rd.gData.hsID + '  rd.gData.hsAID= ' + rd.gData.hsAID + '  hsAID= ' + hsAID);
		LeadNotHSsync( rd, tde, $r, true, true, false );

		return;
	}


	let src = 'https://app.hubspot.com/contacts/' + hsAID + '/contact/' + rd.gData.hsID + '/';		// 'https://app.hubspot.com/contacts/21170832/contact/151/';
//console.log('popHS:  src= ' + src );

	let win = window.open(src, '_blank');  	win.focus();
}





