function MCEintro( id )
{
//console.log('MCEintro:  id= ' + id + '  amID= ' + amID + '  uID= ' + uID + '  utips.MCEintro= ' + utips.MCEintro);

	if( amID || !tmceF || !id || !utips || utips.MCEintro ) { return; }		// <<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<

	setTimeout(function() {

// --------------
		if( id == '#tModal' || id == '#emailSig' || id == '#gDOS' )
		{
			$( id ).find('.tox-editor-container').find('.tox-toolbar').find('.tox-toolbar__group:eq(2)').find('> button.tox-tbtn').trigger('click');	// display "Quick Tips" button drop-down list...
		}
		else	// MUST be a seq or seq tmplt...
		{
			$( id ).find('.tox-editor-container').find('.tox-toolbar').find('.tox-toolbar__group:eq(3)').find('> button.tox-tbtn').trigger('click');	// display "Quick Tips" button drop-down list...
		}

		// Allow time for drop-down list to display...
		setTimeout(function() {

				$('body').find('> .tox-tinymce-aux').find('.tox-tiered-menu').find('> .tox-selected-menu').find('> .tox-collection__group').find('> .tox-collection__item').removeClass('tox-collection__item--active').eq(2).addClass('tox-collection__item--active tox-collection__item--hl');

			}, 300);

/* See llhelp bttn onSetup & onAction...
// $('body').find('> .tox-tinymce-aux').find('.tox-tiered-menu').find('> .tox-selected-menu').find('> .tox-collection__group').find('> .tox-collection__item').removeClass('tox-collection__item--active');
// $('body').find('> .tox-tinymce-aux').find('.tox-tiered-menu').find('> .tox-selected-menu').find('> .tox-collection__group').find('> .tox-collection__item').removeClass('tox-collection__item--active').eq(1).addClass('tox-collection__item--active');
*/
// --------------
// ---
								$( id + ' .tox-tinymce .tox-editor-container .tox-toolbar .tox-toolbar__group:eq(0)' ).addClass( 'llprev' );	// <<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<
// ---
								var tid = id + ' .tox-tinymce .tox-editor-container .tox-toolbar .llprev';
//console.log('MCEintro:  tid= ' + tid + '  --> $(tid).length= ' + $(tid).length);

								tippyTMCE = tippy( tid, {

//									content: 'NEW editor including "Email Preview"',	// <<<<<<<<<<<<<<<<<<

//									content: 'New editor with new features including recipient <b>Email Preview</b>',	// <<<<<<<<<<<<<<<<<<

									content: 'New editor with new functionality including <b>Email Preview</b>',		// <<<<<<<<<<<<<<<<<<

									placement: 'top-start',		// <<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<

									offset: [0, 15],			// [0, 10],

 									hideOnClick: true,			// default...

									allowHTML: true,			// default...

//									trigger: 'manual',			// KEEP!!!!!

									onShown( instance ) {
//console.log('MCEintro.tippy.onShown:');
											ctip( 'MCEintro', '1' );     // ALWAYS, even if amID...

											setTimeout(function() { try { if( tippyTMCE ) { tippyTMCE.hide(); } } catch(err) {} }, 10000);	// <<<<<<<<<<<<<<<<<<
										},

									onHidden( instance ) {
//console.log('MCEintro.tippy.onHidden');
											instance.destroy();

											tippyTMCE = null;
// ---
											if( eTmpCnt && utips && !utips.MCEeTempIntro ) { MCEeTempIntro( id ); }
// ---
										}
								})[0];

//console.log('MCEintro:  tippyTMCE= ' + tippyTMCE);

								try { if( tippyTMCE ) { tippyTMCE.show(); } } catch(err) {}     // <<<<<<<<<<<<<<<<<<
			}, 2000);
}





function MCEeTempIntro( id )
{
//console.log('MCEeTempIntro:  id= ' + id + '  amID= ' + amID + '  eTmpCnt= ' + eTmpCnt + '  utips.MCEeTempIntro= ' + utips.MCEeTempIntro);

	if( amID || !tmceF || !eTmpCnt || !id || id == '#tModal' || id == '#emailSig' || !utips || utips.MCEeTempIntro ) { return; }	// <<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<


	setTimeout(function() {
							$( id + ' .tox-tinymce .tox-editor-container .tox-toolbar .tox-toolbar__group:eq(1)' ).addClass( 'lletmp' );	// <<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<

							var tid = id + ' .tox-tinymce .tox-editor-container .tox-toolbar .lletmp';
//console.log('MCEeTempIntro:  tid= ' + tid + '  --> $(tid).length= ' + $(tid).length);

							tippyTMCEeTemp = tippy( tid, {

								content: 'Email Templates',	// <<<<<<<<<<<<<<<<<<

								placement: 'top',			// <<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<

								offset: [0, 10],			// [0, 10],

								hideOnClick: true,			// default...

//								allowHTML: true,			// default...

//								trigger: 'manual',			// KEEP!!!!!

								onShown( instance ) {
//console.log('MCEeTempIntro.tippy.onShown:');
										ctip( 'MCEeTempIntro', '1' );     // ALWAYS, even if amID...

//										setTimeout(function() { try { if( tippyTMCEeTemp ) { tippyTMCEeTemp.hide(); } } catch(err) {} }, 10000);	// <<<<<<<<<<<<<<<<<<
									},

								onHidden( instance ) {
//console.log('MCEeTempIntro.tippy.onHidden');
										instance.destroy();

										tippyTMCEeTemp = null;
									}
							})[0];

//console.log('MCEeTempIntro:  tippyTMCEeTemp= ' + tippyTMCEeTemp);

							try { if( tippyTMCEeTemp ) { tippyTMCEeTemp.show(); } } catch(err) {}     // <<<<<<<<<<<<<<<<<<
			}, 2000);
}
